func writeDaemonBotletsRegistry(t *testing.T, botletsHome string, bots []map[string]any) {
	t.Helper()
	normalized := make([]map[string]any, 0, len(bots))
	for _, bot := range bots {
		next := make(map[string]any, len(bot))
		for key, value := range bot {
			next[key] = value
		}
		if managed, ok := next["managed_session"].(map[string]any); ok {
			nextManaged := make(map[string]any, len(managed)+1)
			for key, value := range managed {
				nextManaged[key] = value
			}
			if enabled, _ := nextManaged["enabled"].(bool); enabled {
				if _, ok := nextManaged["host"]; !ok {
					nextManaged["host"] = SessionHostTmux
				}
			}
			next["managed_session"] = nextManaged
		}
		normalized = append(normalized, next)
	}
	writeBotletsRegistry(t, botletsHome, normalized)
}

func TestDaemonHealthAndOwnerAuth(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()

	health := requestDaemon(t, paths, map[string]any{"id": "req_health", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health failed: %+v", health.Error)
	}
	result := health.Result.(map[string]any)
	if result["version"] != "test" || result["profiles_loaded"].(float64) != 0 {
		t.Fatalf("unexpected health result: %#v", result)
	}
	features := result["features"].(map[string]any)
	if features[FeatureBotletsSetupOrientation] != FeatureBotletsSetupOrientationVersion {
		t.Fatalf("health features = %#v", features)
	}

	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_reload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	if encoded := mustJSON(t, reload); containsSecretValue(encoded) {
		t.Fatalf("daemon response leaked secret-shaped value: %s", encoded)
	}
}

func TestDaemonRejectsMalformedOwnerCapabilityFile(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()

	malformedCapability := "not-a-capability-token-with-length"
	if err := os.WriteFile(paths.OwnerCapability, []byte(malformedCapability+"\n"), 0o600); err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_badcap",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": malformedCapability,
		},
		"params": map[string]any{},
	})
	if reload.OK || reload.Error == nil || reload.Error.Code != "FORBIDDEN" {
		t.Fatalf("expected malformed owner capability rejection, got %+v", reload)
	}
}

func TestDaemonReloadProfilesLoadsAgentRegistry(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	profilePath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_agent_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": profilePath,
		"managed_session": map[string]any{
			"enabled": true,
			"runtime": "claude",
		},
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadprofiles",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	result := reload.Result.(map[string]any)
	if result["profiles_loaded"].(float64) != 1 || result["bots_loaded"].(float64) != 1 {
		t.Fatalf("reload result = %#v", result)
	}
	if added := result["added"].([]any); len(added) != 1 || added[0] != "max.reviewer" {
		t.Fatalf("added = %#v", added)
	}
	if errorsOut := result["errors"].([]any); len(errorsOut) != 0 {
		t.Fatalf("errors = %#v", errorsOut)
	}
	if encoded := mustJSON(t, reload); containsSecretValue(encoded) {
		t.Fatalf("daemon reload response leaked secret-shaped value: %s", encoded)
	}

	health := requestDaemon(t, paths, map[string]any{"id": "req_profilehealth", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health failed: %+v", health.Error)
	}
	healthResult := health.Result.(map[string]any)
	if healthResult["profiles_loaded"].(float64) != 1 || healthResult["bots_loaded"].(float64) != 1 || healthResult["profile_errors"].(float64) != 0 {
		t.Fatalf("health result = %#v", healthResult)
	}
	config, ok, err := ReadBusConfig(paths)
	if err != nil || !ok || config.BotletsHome != botletsHome {
		t.Fatalf("persisted bus config = %+v ok=%v err=%v", config, ok, err)
	}
	if err := daemon.Close(); err != nil {
		t.Fatal(err)
	}
	restarted, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:   paths,
		Version: "test",
		Tmux:    newTestTmuxController(),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer restarted.Close()
	restartHealth := requestDaemon(t, paths, map[string]any{"id": "req_profilerestarthealth", "op": "health", "params": map[string]any{}})
	if !restartHealth.OK {
		t.Fatalf("restart health failed: %+v", restartHealth.Error)
	}
	restartHealthResult := restartHealth.Result.(map[string]any)
	if restartHealthResult["profiles_loaded"].(float64) != 1 || restartHealthResult["bots_loaded"].(float64) != 1 {
		t.Fatalf("restart health result = %#v", restartHealthResult)
	}
}

