func TestDaemonManagedSessionModelChangeStalesLiveSession(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_modelstale-start1",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("first start failed: %+v", start.Error)
	}
	firstSession := start.Result.(map[string]any)["session"].(map[string]any)
	firstSessionID := firstSession["session_id"].(string)

	daemon.profileMu.Lock()
	bot := daemon.profileState.BotRegistry["reviewer"]
	bot.ManagedSession.Model = "opus"
	daemon.profileState.BotRegistry["reviewer"] = bot
	daemon.profileMu.Unlock()

	second := requestDaemon(t, paths, map[string]any{
		"id": "req_modelstale-start2",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !second.OK {
		t.Fatalf("second start failed: %+v", second.Error)
	}
	secondSession := second.Result.(map[string]any)["session"].(map[string]any)
	secondSessionID := secondSession["session_id"].(string)
	if secondSessionID == firstSessionID {
		t.Fatalf("model change reused stale session %s", firstSessionID)
	}

	oldRecord, err := ReadSessionRecord(paths, firstSessionID)
	if err != nil {
		t.Fatal(err)
	}
	if oldRecord.State != "stale" {
		t.Fatalf("old model session state = %+v", oldRecord)
	}
	newRecord, err := ReadSessionRecord(paths, secondSessionID)
	if err != nil {
		t.Fatal(err)
	}
	if newRecord.State != "alive" || newRecord.Model != "opus" {
		t.Fatalf("new model session record = %+v", newRecord)
	}
	wantCommand := []string{"claude", "--model", "opus", "--dangerously-skip-permissions"}
	if strings.Join(newRecord.RuntimeCommand, "\x00") != strings.Join(wantCommand, "\x00") {
		t.Fatalf("new model runtime command = %#v, want %#v", newRecord.RuntimeCommand, wantCommand)
	}
}

func TestDaemonManagedSessionRequestedModelOverridesRegistry(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	daemon.profileMu.Lock()
	bot := daemon.profileState.BotRegistry["reviewer"]
	bot.ManagedSession.Model = "stale-local-registry"
	daemon.profileState.BotRegistry["reviewer"] = bot
	daemon.profileMu.Unlock()

	clear := requestDaemon(t, paths, map[string]any{
		"id": "req_modeloverride-clear",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "requested_model": "", "requested_model_set": true},
	})
	if !clear.OK {
		t.Fatalf("clear model start failed: %+v", clear.Error)
	}
	clearSession := clear.Result.(map[string]any)["session"].(map[string]any)
	clearSessionID := clearSession["session_id"].(string)
	clearRecord, err := ReadSessionRecord(paths, clearSessionID)
	if err != nil {
		t.Fatal(err)
	}
	if clearRecord.Model != "" {
		t.Fatalf("cleared requested model session record = %+v, want empty model", clearRecord)
	}
	wantClearCommand := []string{"claude", "--dangerously-skip-permissions"}
	if strings.Join(clearRecord.RuntimeCommand, "\x00") != strings.Join(wantClearCommand, "\x00") {
		t.Fatalf("cleared model runtime command = %#v, want %#v", clearRecord.RuntimeCommand, wantClearCommand)
	}

	set := requestDaemon(t, paths, map[string]any{
		"id": "req_modeloverride-set",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "requested_model": "opus", "requested_model_set": true},
	})
	if !set.OK {
		t.Fatalf("set model start failed: %+v", set.Error)
	}
	setSession := set.Result.(map[string]any)["session"].(map[string]any)
	setSessionID := setSession["session_id"].(string)
	if setSessionID == clearSessionID {
		t.Fatalf("requested model change reused stale session %s", clearSessionID)
	}
	oldRecord, err := ReadSessionRecord(paths, clearSessionID)
	if err != nil {
		t.Fatal(err)
	}
	if oldRecord.State != "stale" {
		t.Fatalf("cleared model session state = %+v, want stale", oldRecord)
	}
	setRecord, err := ReadSessionRecord(paths, setSessionID)
	if err != nil {
		t.Fatal(err)
	}
	if setRecord.Model != "opus" {
		t.Fatalf("requested model session record = %+v, want opus", setRecord)
	}
	wantSetCommand := []string{"claude", "--model", "opus", "--dangerously-skip-permissions"}
	if strings.Join(setRecord.RuntimeCommand, "\x00") != strings.Join(wantSetCommand, "\x00") {
		t.Fatalf("requested model runtime command = %#v, want %#v", setRecord.RuntimeCommand, wantSetCommand)
	}
}

func TestDaemonReloadProfilesPreservesPreviousStateOnErrors(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	profilePath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_agent_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": profilePath,
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	first := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadfirst",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !first.OK {
		t.Fatalf("first reload failed: %+v", first.Error)
	}

	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "writer",
		"handle":             "max.writer",
		"credential_profile": profilePath,
	}})
	second := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadsecond",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !second.OK {
		t.Fatalf("second reload failed: %+v", second.Error)
	}
	result := second.Result.(map[string]any)
	if result["profiles_loaded"].(float64) != 1 || result["bots_loaded"].(float64) != 1 {
		t.Fatalf("reload with errors did not preserve state: %#v", result)
	}
	errorsOut := result["errors"].([]any)
	if len(errorsOut) != 1 || errorsOut[0].(map[string]any)["code"] != "HANDLE_MISMATCH" {
		t.Fatalf("errors = %#v", errorsOut)
	}
	if encoded := mustJSON(t, second); containsSecretValue(encoded) {
		t.Fatalf("daemon error response leaked secret-shaped value: %s", encoded)
	}

	health := requestDaemon(t, paths, map[string]any{"id": "req_healthaftererror", "op": "health", "params": map[string]any{}})
	healthResult := health.Result.(map[string]any)
	if healthResult["profiles_loaded"].(float64) != 1 || healthResult["bots_loaded"].(float64) != 1 || healthResult["profile_errors"].(float64) != 1 {
		t.Fatalf("health after failed reload = %#v", healthResult)
	}

	writeJSONFile(t, filepath.Join(botletsHome, "registry.json"), map[string]any{})
	malformed := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadmalformed",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !malformed.OK {
		t.Fatalf("malformed registry reload failed: %+v", malformed.Error)
	}
	malformedResult := malformed.Result.(map[string]any)
	if malformedResult["profiles_loaded"].(float64) != 1 || malformedResult["bots_loaded"].(float64) != 1 {
		t.Fatalf("malformed registry reload did not preserve state: %#v", malformedResult)
	}
	malformedErrors := malformedResult["errors"].([]any)
	if len(malformedErrors) != 1 || malformedErrors[0].(map[string]any)["code"] != "INVALID_BOTLETS_REGISTRY" {
		t.Fatalf("malformed registry errors = %#v", malformedErrors)
	}

	if err := os.Remove(profilePath); err != nil {
		t.Fatal(err)
	}
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{})
	removed := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadremoved",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !removed.OK {
		t.Fatalf("removed reload failed: %+v", removed.Error)
	}
	removedResult := removed.Result.(map[string]any)
	if removedResult["profiles_loaded"].(float64) != 0 || removedResult["bots_loaded"].(float64) != 0 {
		t.Fatalf("removed reload did not clear state: %#v", removedResult)
	}
	removedHandles := removedResult["removed"].([]any)
	if len(removedHandles) != 1 || removedHandles[0] != "max.reviewer" {
		t.Fatalf("removed handles = %#v", removedHandles)
	}
	if errorsOut := removedResult["errors"].([]any); len(errorsOut) != 0 {
		t.Fatalf("removed reload errors = %#v", errorsOut)
	}
}

func TestDaemonReloadProfilesLoadsValidProfilesAlongsideBadOne(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()

	// One valid profile (correct private permissions via the test helper).
	writeAgentProfile(t, paths, "max.staging-test", map[string]any{
		"agent_secret": "as_agent_profile_secret",
	})
	// One stale profile with world-readable permissions — exactly the shape
	// that breaks the daemon when migrating from the legacy 0.1.0 CLI.
	stalePath := writeAgentProfile(t, paths, "max.personal", map[string]any{
		"agent_secret": "as_other_agent_secret",
	})
	if err := os.Chmod(stalePath, 0o644); err != nil {
		t.Fatal(err)
	}

	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	resp := requestDaemon(t, paths, map[string]any{
		"id": "req_reloadpartial",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{},
	})
	if !resp.OK {
		t.Fatalf("reload-profiles failed: %+v", resp.Error)
	}
	result := resp.Result.(map[string]any)
	if result["profiles_loaded"].(float64) != 1 {
		t.Fatalf("expected 1 profile loaded despite stale sibling, got %#v", result)
	}
	added := result["added"].([]any)
	if len(added) != 1 || added[0] != "max.staging-test" {
		t.Fatalf("expected max.staging-test in added, got %#v", added)
	}
	errs := result["errors"].([]any)
	if len(errs) != 1 {
		t.Fatalf("expected 1 reported error for stale profile, got %#v", errs)
	}
	first := errs[0].(map[string]any)
	if first["code"] != "INVALID_AGENT_PROFILE" || first["profile"] != "max.personal" {
		t.Fatalf("unexpected error shape: %#v", first)
	}
}

func TestDaemonReloadProfilesSerializesConcurrentReloads(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	profilePath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_agent_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": profilePath,
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	var wg sync.WaitGroup
	for i := 0; i < 20; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			params := map[string]any{}
			if i%2 == 0 {
				params["botlets_home"] = botletsHome
			}
			response := requestDaemon(t, paths, map[string]any{
				"id": "req_reloadrace" + string(rune('a'+i)),
				"op": "reload-profiles",
				"auth": map[string]any{
					"mode":       "owner",
					"capability": capability,
				},
				"params": params,
			})
			if !response.OK {
				t.Errorf("reload %d failed: %+v", i, response.Error)
			}
		}(i)
	}
	wg.Wait()

	health := requestDaemon(t, paths, map[string]any{"id": "req_healthrace", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health failed: %+v", health.Error)
	}
	healthResult := health.Result.(map[string]any)
	if healthResult["profiles_loaded"].(float64) != 1 || healthResult["bots_loaded"].(float64) != 1 || healthResult["profile_errors"].(float64) != 0 {
		t.Fatalf("health after concurrent reload = %#v", healthResult)
	}
}

func TestDaemonManagedSessionReportsMissingBmux(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	prependFakeRuntime(t, "claude")
	profilePath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_agent_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": profilePath,
		"managed_session": map[string]any{
			"enabled": true,
			"runtime": "claude",
			// Explicit bmux opt-in: tmux is the default host, so we must pin
			// host=bmux to exercise the bmux-missing launch path.
			"host": "bmux",
		},
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_managedmissingbmuxreload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}

	// Managed-session launch hits the same NewSession path; a missing bmux must
	// surface the dedicated code + install guidance, not a generic launch error.
	daemon.tmux.(*testTmuxController).failStartErrAll = ErrBmuxNotInstalled
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_managedmissingbmuxstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if start.OK || start.Error == nil {
		t.Fatalf("expected sessions.start to fail when bmux is missing: %+v", start)
	}
	if start.Error.Code != SocketErrorCodeBmuxNotInstalled {
		t.Fatalf("sessions.start error code = %q; want %q", start.Error.Code, SocketErrorCodeBmuxNotInstalled)
	}
	if !strings.Contains(start.Error.Message, "bmux is required") {
		t.Fatalf("error message should explain bmux is required + how to install: %q", start.Error.Message)
	}
}

