func TestDaemonSessionStartStopAndNudgeState(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstartreviewer",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	generation := session["generation"].(string)
	sessionName := session["session_name"].(string)
	if session["profile"] != "max.reviewer" || session["bot_name"] != "reviewer" || session["scope_type"] != "profile" || session["scope_id"] != "max.reviewer" || session["state"] != "alive" {
		t.Fatalf("started session = %#v", session)
	}
	if session["pane_target"] == "" || session["session_name"] == "" {
		t.Fatalf("managed start should record tmux target: %#v", session)
	}
	startedRecord, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	// New managed sessions launch in "shell" mode: the runtime name is resolved
	// through the user's login shell at exec time, so no trusted binary path is
	// pinned in the record.
	if startedRecord.RuntimeCommand[0] != "claude" || startedRecord.RuntimeLaunchMode != RuntimeLaunchModeShell || startedRecord.RuntimePath != "" || startedRecord.RuntimeCommandPath != "" {
		t.Fatalf("managed start should produce a shell-mode record with no pinned paths: mode=%q path=%q command_path=%q command=%+v", startedRecord.RuntimeLaunchMode, startedRecord.RuntimePath, startedRecord.RuntimeCommandPath, startedRecord.RuntimeCommand)
	}
	sessionCapability, err := ReadCapability(session["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}
	startAgain := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstartagain",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !startAgain.OK {
		t.Fatalf("second session start failed: %+v", startAgain.Error)
	}
	startAgainSession := startAgain.Result.(map[string]any)["session"].(map[string]any)
	if startAgainSession["session_id"] != sessionID || startAgainSession["generation"] != generation {
		t.Fatalf("second start minted another live session: first=%#v second=%#v", session, startAgainSession)
	}

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgesend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "wake reviewer"},
		},
	})
	if !send.OK {
		t.Fatalf("send for nudge failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	nudge := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgeowner",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "message_id": messageID},
	})
	if !nudge.OK {
		t.Fatalf("owner nudge failed: %+v", nudge.Error)
	}
	nudgeWithoutSelector := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgenoselector",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if nudgeWithoutSelector.OK || nudgeWithoutSelector.Error == nil || nudgeWithoutSelector.Error.Code != "VALIDATION_ERROR" {
		t.Fatalf("nudge without selector response = %+v", nudgeWithoutSelector)
	}
	nudgeBySessionID := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgebysession",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID, "message_id": messageID},
	})
	if !nudgeBySessionID.OK || nudgeBySessionID.Result.(map[string]any)["session_id"] != sessionID {
		t.Fatalf("nudge by session_id response = %+v", nudgeBySessionID)
	}
	scopedOwnerWrongProfile := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgescopedwrongprofile",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.sender",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "message_id": messageID},
	})
	if scopedOwnerWrongProfile.OK || scopedOwnerWrongProfile.Error == nil || scopedOwnerWrongProfile.Error.Code != "FORBIDDEN" {
		t.Fatalf("scoped owner wrong profile response = %+v", scopedOwnerWrongProfile)
	}
	nudgeResult := nudge.Result.(map[string]any)
	if nudgeResult["session_id"] != sessionID || nudgeResult["message_id"] != messageID || nudgeResult["attempted_at"] == nil {
		t.Fatalf("nudge result = %#v", nudgeResult)
	}
	if _, ok := nudgeResult["succeeded_at"]; !ok {
		t.Fatalf("tmux nudge should report success: %#v", nudgeResult)
	}
	status := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgestatus",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID},
	})
	if !status.OK {
		t.Fatalf("status after nudge failed: %+v", status.Error)
	}
	statusSession := status.Result.(map[string]any)["sessions"].([]any)[0].(map[string]any)
	lastNudge := statusSession["last_nudge"].(map[string]any)
	if lastNudge["message_id"] != messageID || lastNudge["attempted_at"] == nil || lastNudge["succeeded_at"] == nil {
		t.Fatalf("last nudge = %#v", lastNudge)
	}

	sessionNudge := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgesession",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !sessionNudge.OK {
		t.Fatalf("session nudge failed: %+v", sessionNudge.Error)
	}
	sessionReceive := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionreceivestopclaim",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !sessionReceive.OK {
		t.Fatalf("session receive before stop failed: %+v", sessionReceive.Error)
	}
	stopWithoutSelector := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopnoselector",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"reason": "test"},
	})
	if stopWithoutSelector.OK || stopWithoutSelector.Error == nil || stopWithoutSelector.Error.Code != "VALIDATION_ERROR" {
		t.Fatalf("stop without selector response = %+v", stopWithoutSelector)
	}
	scopedOwnerWrongProfileStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopscopedwrongprofile",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.sender",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID, "reason": "wrong profile"},
	})
	if scopedOwnerWrongProfileStop.OK || scopedOwnerWrongProfileStop.Error == nil || scopedOwnerWrongProfileStop.Error.Code != "FORBIDDEN" {
		t.Fatalf("scoped owner wrong profile stop response = %+v", scopedOwnerWrongProfileStop)
	}
	tmux.mu.Lock()
	tmux.failKill[sessionName] = true
	tmux.mu.Unlock()
	failedStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopkillfailure",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID, "reason": "tmux failed"},
	})
	if failedStop.OK || failedStop.Error == nil || failedStop.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("tmux kill failure stop response = %+v", failedStop)
	}
	tmux.mu.Lock()
	tmux.failKill[sessionName] = false
	tmux.mu.Unlock()
	statusAfterFailedStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstatusafterfailedstop",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID},
	})
	if !statusAfterFailedStop.OK {
		t.Fatalf("status after failed stop failed: %+v", statusAfterFailedStop.Error)
	}
	failedStopSession := statusAfterFailedStop.Result.(map[string]any)["sessions"].([]any)[0].(map[string]any)
	if failedStopSession["state"] != "alive" {
		t.Fatalf("failed stop should leave session alive: %#v", failedStopSession)
	}
	listAfterFailedStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionlistafterfailedstop",
		"op": "messages.list",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{},
	})
	if !listAfterFailedStop.OK {
		t.Fatalf("session list after failed stop failed: %+v", listAfterFailedStop.Error)
	}
	if listed := listAfterFailedStop.Result.(map[string]any)["messages"].([]any); len(listed) != 1 || listed[0].(map[string]any)["id"] != messageID {
		t.Fatalf("failed stop should not release session claim: %#v", listed)
	}
	daemon.writeSessionRecord = func(paths Paths, record SessionRecord) error {
		if record.SessionID == sessionID && record.State == "dead" {
			return errors.New("injected stop write failure")
		}
		return WriteSessionRecord(paths, record)
	}
	writeFailedStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopwritefailure",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID, "reason": "write failed"},
	})
	if writeFailedStop.OK || writeFailedStop.Error == nil || writeFailedStop.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("session stop write failure response = %+v", writeFailedStop)
	}
	daemon.writeSessionRecord = nil
	recordAfterWriteFailure, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	if recordAfterWriteFailure.State != "alive" {
		t.Fatalf("write-failed stop should leave session record alive: %+v", recordAfterWriteFailure)
	}
	tmux.mu.Lock()
	_, tmuxLiveAfterWriteFailure := tmux.sessions[sessionName]
	tmux.mu.Unlock()
	if !tmuxLiveAfterWriteFailure {
		t.Fatal("write-failed stop killed tmux before dead state was durable")
	}
	daemon.busMu.Lock()
	messageAfterWriteFailure, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if messageAfterWriteFailure.Delivery.State != "claimed" {
		t.Fatalf("write-failed stop released claim: %+v", messageAfterWriteFailure.Delivery)
	}
	tmux.mu.Lock()
	tmux.missingOnKill[sessionName] = true
	tmux.mu.Unlock()
	stop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopowner",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID, "reason": "done"},
	})
	if !stop.OK || stop.Result.(map[string]any)["state"] != "dead" {
		t.Fatalf("owner stop response = %+v", stop)
	}
	if released := stop.Result.(map[string]any)["released_messages"].([]any); len(released) != 1 || released[0] != messageID {
		t.Fatalf("stop released messages = %#v", released)
	}
	if redactedJSON := latestMessageEventJSON(t, daemon, messageID, "message.released"); !strings.Contains(redactedJSON, `"reason":"done"`) {
		t.Fatalf("stop release event reason = %s", redactedJSON)
	}
	sessionStatusAfterStop := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstatusafterstop",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{},
	})
	if sessionStatusAfterStop.OK || sessionStatusAfterStop.Error == nil || sessionStatusAfterStop.Error.Code != "FORBIDDEN" {
		t.Fatalf("stopped session auth response = %+v", sessionStatusAfterStop)
	}
	nudgeDead := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgedead",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "message_id": messageID},
	})
	if nudgeDead.OK || nudgeDead.Error == nil || nudgeDead.Error.Code != "CONFLICT" {
		t.Fatalf("dead nudge response = %+v", nudgeDead)
	}
	restartReviewer := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionrestartreviewer",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !restartReviewer.OK {
		t.Fatalf("reviewer restart failed: %+v", restartReviewer.Error)
	}
	restartedSession := restartReviewer.Result.(map[string]any)["session"].(map[string]any)
	restartedSessionID := restartedSession["session_id"].(string)
	restartedGeneration := restartedSession["generation"].(string)
	restartedCapability, err := ReadCapability(restartedSession["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}
	nudgeRestarted := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgerestarted",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "message_id": messageID},
	})
	if !nudgeRestarted.OK || nudgeRestarted.Result.(map[string]any)["session_id"] != restartedSessionID {
		t.Fatalf("restarted nudge response = %+v", nudgeRestarted)
	}
	restartedWait := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionwaitafterrestart",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         restartedSessionID,
			"session_generation": restartedGeneration,
			"capability":         restartedCapability,
		},
		"params": map[string]any{"timeout_ms": 0},
	})
	if !restartedWait.OK || restartedWait.Result.(map[string]any)["message_id"] != messageID {
		t.Fatalf("restarted session wait response = %+v", restartedWait)
	}

	startSender := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstartsender",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "sender"},
	})
	if !startSender.OK {
		t.Fatalf("sender start failed: %+v", startSender.Error)
	}
	senderSession := startSender.Result.(map[string]any)["session"].(map[string]any)
	senderSessionID := senderSession["session_id"].(string)
	senderGeneration := senderSession["generation"].(string)
	senderCapability, err := ReadCapability(senderSession["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}
	wrongProfileNudge := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionnudgewrongprofile",
		"op": "sessions.nudge",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.sender",
			"session_id":         senderSessionID,
			"session_generation": senderGeneration,
			"capability":         senderCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if wrongProfileNudge.OK || wrongProfileNudge.Error == nil || wrongProfileNudge.Error.Code != "NOT_FOUND" {
		t.Fatalf("wrong profile nudge response = %+v", wrongProfileNudge)
	}
	stopSender := requestDaemon(t, paths, map[string]any{
		"id": "req_sessionstopsession",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.sender",
			"session_id":         senderSessionID,
			"session_generation": senderGeneration,
			"capability":         senderCapability,
		},
		"params": map[string]any{},
	})
	if !stopSender.OK || stopSender.Result.(map[string]any)["state"] != "dead" {
		t.Fatalf("session stop response = %+v", stopSender)
	}
	senderStatusAfterStop := requestDaemon(t, paths, map[string]any{
		"id": "req_senderstatusafterstop",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.sender",
			"session_id":         senderSessionID,
			"session_generation": senderGeneration,
			"capability":         senderCapability,
		},
		"params": map[string]any{},
	})
	if senderStatusAfterStop.OK || senderStatusAfterStop.Error == nil || senderStatusAfterStop.Error.Code != "FORBIDDEN" {
		t.Fatalf("stopped sender session auth response = %+v", senderStatusAfterStop)
	}
	senderReceiveAfterStop := requestDaemon(t, paths, map[string]any{
		"id": "req_senderreceiveafterstop",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.sender",
			"session_id":         senderSessionID,
			"session_generation": senderGeneration,
			"capability":         senderCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if senderReceiveAfterStop.OK || senderReceiveAfterStop.Error == nil || senderReceiveAfterStop.Error.Code != "FORBIDDEN" {
		t.Fatalf("stopped sender receive response = %+v", senderReceiveAfterStop)
	}
}

func TestDaemonBmuxManagedSessionUsesBmuxControllerAndSessionFile(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	runtimeHome := privateTestDir(t, "comment-bus-bmux-runtime-home-")
	t.Setenv("HOME", runtimeHome)
	binDir := filepath.Join(runtimeHome, ".local", "bin")
	if err := os.MkdirAll(binDir, 0o755); err != nil {
		t.Fatal(err)
	}
	claudePath := filepath.Join(binDir, "claude")
	if err := os.WriteFile(claudePath, []byte("#!/bin/sh\nexit 0\n"), 0o700); err != nil {
		t.Fatal(err)
	}
	t.Setenv("PATH", binDir+string(os.PathListSeparator)+os.Getenv("PATH"))

	bmux := newTestBmuxController(paths)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
		Now: func() time.Time {
			return time.Date(2026, 5, 7, 0, 0, 0, 0, time.UTC)
		},
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()

	appendTranscript := func(record SessionRecord, text string) {
		t.Helper()
		path, err := ClaudeSessionFilePath(runtimeHome, record.WorkingDir, record.RuntimeSessionRef)
		if err != nil {
			t.Fatal(err)
		}
		if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
			t.Fatal(err)
		}
		file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o600)
		if err != nil {
			t.Fatal(err)
		}
		if _, err := file.WriteString(text + "\n"); err != nil {
			_ = file.Close()
			t.Fatal(err)
		}
		if err := file.Close(); err != nil {
			t.Fatal(err)
		}
	}
	touchTranscriptOld := func(record SessionRecord) {
		t.Helper()
		path, err := ClaudeSessionFilePath(runtimeHome, record.WorkingDir, record.RuntimeSessionRef)
		if err != nil {
			t.Fatal(err)
		}
		old := time.Now().Add(-2 * transientRuntimeStartupInputQuietDelay)
		if err := os.Chtimes(path, old, old); err != nil {
			t.Fatal(err)
		}
	}
	bmux.afterSendEnter = func(sessionName string, _ string) {
		records, err := ListSessionRecords(paths)
		if err != nil {
			t.Errorf("ListSessionRecords: %v", err)
			return
		}
		for _, record := range records {
			if record.SessionName == sessionName && record.Host == SessionHostBmux {
				appendTranscript(record, `{"type":"user_message"}`)
				return
			}
		}
	}

	reviewerPath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_reviewer_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled": true,
			"runtime": "claude",
			"host":    "bmux",
		},
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxreload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	sent, err := daemon.store.InsertLocalMessages(ctx, LocalMessageSend{
		SenderProfile: "max.sender",
		SenderBotName: "sender",
		Recipients: []LocalMessageRecipient{{
			Profile: "max.reviewer",
			BotName: "reviewer",
		}},
		Body: MessageBody{Format: "markdown", Content: "Please inspect the bmux path."},
		Now:  time.Now().UTC(),
	})
	if err != nil {
		t.Fatal(err)
	}
	messageID := sent.Messages[0].ID

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("bmux sessions.start failed: %+v", start.Error)
	}
	tmux := daemon.tmux.(*testTmuxController)
	tmux.mu.Lock()
	tmuxStarts := len(tmux.starts)
	tmux.mu.Unlock()
	if tmuxStarts != 0 {
		t.Fatalf("tmux starts = %d, want 0 for bmux-managed bot", tmuxStarts)
	}
	bmux.mu.Lock()
	if len(bmux.starts) != 1 || bmux.waitForOutputCalls != 1 || bmux.enterCount < 4 {
		t.Fatalf("bmux start/wait/enter state = starts=%d waits=%d enters=%d", len(bmux.starts), bmux.waitForOutputCalls, bmux.enterCount)
	}
	if !strings.Contains(bmux.starts[0].OutputPipeCommand, "__runtime-tail") {
		t.Fatalf("bmux managed start missing output pipe: %+v", bmux.starts[0])
	}
	bmux.mu.Unlock()

	record := requireOnlyAliveSessionForBot(t, paths, "reviewer")
	if record.Host != SessionHostBmux || !UUIDRE.MatchString(record.RuntimeSessionRef) || record.OutputLogPath == "" || record.WorkingDir != botletsHome {
		t.Fatalf("bmux session record = %+v", record)
	}
	record.BotletsHome = filepath.Join(paths.Home, "botlets-moved-after-launch")
	if err := WriteSessionRecord(paths, record); err != nil {
		t.Fatal(err)
	}
	touchTranscriptOld(record)
	daemon.sessionMu.Lock()
	nudged, nudgeErr := daemon.nudgeReadyQueueHeadIfIdleLockedWithContext(ctx, record, false)
	daemon.sessionMu.Unlock()
	if nudgeErr != nil || !nudged {
		t.Fatalf("bmux nudge = %v err=%+v", nudged, nudgeErr)
	}
	bmux.mu.Lock()
	if !testBmuxSendsContainLocked(bmux, messageID) {
		t.Fatalf("bmux sends after nudge = %+v, want message id %s", bmux.sends, messageID)
	}
	bmux.mu.Unlock()

	record, err = ReadSessionRecord(paths, record.SessionID)
	if err != nil {
		t.Fatal(err)
	}
	touchTranscriptOld(record)
	daemon.profileMu.RLock()
	bot := daemon.profileState.BotRegistry["reviewer"]
	daemon.profileMu.RUnlock()
	bmux.mu.Lock()
	// Shell-mode sessions treat a non-shell foreground as "the runtime is
	// running" (coarse liveness, §4.4.2 of the plan), so a bare login shell is
	// the meaningful "runtime not ready / busy" signal here. (Path mode could
	// distinguish an arbitrary non-runtime command like "sleep"; shell mode
	// deliberately cannot.)
	bmux.paneCommands[record.PaneTarget] = "zsh"
	bmux.mu.Unlock()
	daemon.sessionMu.Lock()
	busyResetErr := daemon.requestDailyResetLocked(ctx, managedSessionResetTarget{
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		Bot:         bot,
		BotletsHome: botletsHome,
	}, record, "2026-05-07", "UTC", time.Now().UTC())
	daemon.sessionMu.Unlock()
	if busyResetErr == nil || busyResetErr.Code != "CONFLICT" {
		t.Fatalf("busy bmux daily reset err = %+v, want CONFLICT", busyResetErr)
	}
	bmux.mu.Lock()
	if testBmuxSendsContainLocked(bmux, "Daily reset handoff") {
		t.Fatalf("bmux sends included daily reset while foreground busy: %+v", bmux.sends)
	}
	bmux.paneCommands[record.PaneTarget] = "claude"
	bmux.mu.Unlock()

	daemon.sessionMu.Lock()
	resetErr := daemon.requestDailyResetLocked(ctx, managedSessionResetTarget{
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		Bot:         bot,
		BotletsHome: botletsHome,
	}, record, "2026-05-07", "UTC", time.Now().UTC())
	daemon.sessionMu.Unlock()
	if resetErr != nil {
		t.Fatalf("bmux daily reset failed: %+v", resetErr)
	}
	bmux.mu.Lock()
	if !testBmuxSendsContainLocked(bmux, "Daily reset handoff") {
		t.Fatalf("bmux sends after daily reset = %+v", bmux.sends)
	}
	bmux.mu.Unlock()

	stop := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxstop",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": record.SessionID},
	})
	if !stop.OK {
		t.Fatalf("bmux sessions.stop failed: %+v", stop.Error)
	}
	bmux.mu.Lock()
	if len(bmux.kills) != 1 || bmux.kills[0] != record.SessionName {
		t.Fatalf("bmux kills = %+v, want %s", bmux.kills, record.SessionName)
	}
	bmux.mu.Unlock()
}

type bmuxClaudeDaemonFixture struct {
	paths       Paths
	daemon      *Daemon
	bmux        *testBmuxController
	runtimeHome string
	capability  string
}

func startBmuxClaudeDaemonFixture(t *testing.T, ctx context.Context) bmuxClaudeDaemonFixture {
	t.Helper()
	paths := testDaemonPaths(t)
	runtimeHome := privateTestDir(t, "comment-bus-bmux-recovery-runtime-home-")
	t.Setenv("HOME", runtimeHome)
	binDir := filepath.Join(runtimeHome, ".local", "bin")
	if err := os.MkdirAll(binDir, 0o755); err != nil {
		t.Fatal(err)
	}
	claudePath := filepath.Join(binDir, "claude")
	if err := os.WriteFile(claudePath, []byte("#!/bin/sh\nexit 0\n"), 0o700); err != nil {
		t.Fatal(err)
	}
	t.Setenv("PATH", binDir+string(os.PathListSeparator)+os.Getenv("PATH"))

	bmux := newTestBmuxController(paths)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
	})
	if err != nil {
		t.Fatal(err)
	}
	t.Cleanup(func() {
		daemon.Close()
	})
	appendTranscript := func(record SessionRecord, text string) {
		t.Helper()
		path, err := ClaudeSessionFilePath(runtimeHome, record.WorkingDir, record.RuntimeSessionRef)
		if err != nil {
			t.Fatal(err)
		}
		if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
			t.Fatal(err)
		}
		file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o600)
		if err != nil {
			t.Fatal(err)
		}
		if _, err := file.WriteString(text + "\n"); err != nil {
			_ = file.Close()
			t.Fatal(err)
		}
		if err := file.Close(); err != nil {
			t.Fatal(err)
		}
	}
	bmux.afterSendEnter = func(sessionName string, _ string) {
		records, err := ListSessionRecords(paths)
		if err != nil {
			t.Errorf("ListSessionRecords: %v", err)
			return
		}
		for _, record := range records {
			if record.SessionName == sessionName && record.Host == SessionHostBmux && record.Runtime == "claude" {
				appendTranscript(record, `{"type":"user_message"}`)
				return
			}
		}
	}

	reviewerPath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_reviewer_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled": true,
			"runtime": "claude",
			"host":    "bmux",
		},
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxrecoveryreload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	return bmuxClaudeDaemonFixture{paths: paths, daemon: daemon, bmux: bmux, runtimeHome: runtimeHome, capability: capability}
}

