func TestDaemonRepairBmuxRecoverPreservesClaimedMessage(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	fixture := startBmuxClaudeDaemonFixture(t, ctx)
	record := fixture.startManagedSession(t)
	sent, err := fixture.daemon.store.InsertLocalMessages(ctx, LocalMessageSend{
		SenderProfile: "max.sender",
		SenderBotName: "sender",
		Recipients: []LocalMessageRecipient{{
			Profile: "max.reviewer",
			BotName: "reviewer",
		}},
		Body: MessageBody{Format: "markdown", Content: "Keep this claim while recovering."},
		Now:  time.Now().UTC(),
	})
	if err != nil {
		t.Fatal(err)
	}
	messageID := sent.Messages[0].ID
	holder := "session:" + record.SessionID + ":" + record.Generation
	sessionID := record.SessionID
	scopeType := record.ScopeType
	scopeID := record.ScopeID
	generation := record.Generation
	if _, err := fixture.daemon.store.ClaimMessage(ctx, MessageClaimOptions{
		Profile:           "max.reviewer",
		MessageID:         messageID,
		ClaimHolder:       holder,
		SessionID:         &sessionID,
		SessionScopeType:  &scopeType,
		SessionScopeID:    &scopeID,
		SessionGeneration: &generation,
		LeaseTTL:          defaultLocalLeaseTTL,
		Now:               time.Now().UTC(),
	}); err != nil {
		t.Fatal(err)
	}

	fixture.bmux.mu.Lock()
	fixture.bmux.deadChildren[record.SessionName] = true
	fixture.bmux.mu.Unlock()
	fixture.daemon.sessionMu.Lock()
	actions, repairErr := fixture.daemon.reconcileClaimedMessagesLocked(ctx, time.Now().UTC(), RepairFilter{}, map[string]struct{}{}, true)
	fixture.daemon.sessionMu.Unlock()
	if repairErr != nil {
		t.Fatalf("reconcileClaimedMessagesLocked err = %v", repairErr)
	}
	if len(actions) != 0 {
		t.Fatalf("repair actions = %+v, want none for recovered bmux session", actions)
	}
	after, err := fixture.daemon.store.GetInboxMessage(ctx, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if after.Delivery.State != "claimed" || stringValue(after.Delivery.ClaimHolder) != holder {
		t.Fatalf("message after repair = state:%q holder:%q, want claimed by %q", after.Delivery.State, stringValue(after.Delivery.ClaimHolder), holder)
	}
	recovered := requireOnlyAliveSessionForBot(t, fixture.paths, "reviewer")
	if recovered.RuntimeCommand[1] != "--resume" || recovered.RuntimeSessionRef != record.RuntimeSessionRef {
		t.Fatalf("recovered record = %+v, want resumed runtime ref %q", recovered, record.RuntimeSessionRef)
	}
}

