func TestDaemonRepairNonExpiredStaleBmuxCleanupFailureKeepsCloudClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	bmux := newTestBmuxController(paths)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	sessionName := "comment-reviewer-abc123"
	paneTarget, err := BmuxSocketPathForSession(paths, sessionName)
	if err != nil {
		t.Fatal(err)
	}
	record, err := RegisterSession(RegisterSessionOptions{
		Paths:       paths,
		Host:        SessionHostBmux,
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		ScopeType:   "profile",
		ScopeID:     "max.reviewer",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		SessionName: sessionName,
		PaneTarget:  paneTarget,
		Runtime:     "claude",
		State:       "stale",
		Now:         time.Now().UTC(),
	})
	if err != nil {
		t.Fatal(err)
	}
	bmux.mu.Lock()
	bmux.sessions[record.SessionName] = record.PaneTarget
	bmux.paneCommands[record.PaneTarget] = "claude"
	bmux.killErr = errors.New("kill denied")
	bmux.mu.Unlock()

	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	messageID := seedCloudMessageForBot(t, paths, daemon.store, CloudNotificationLease{
		ClaimID:        "clm_bmuxnonexpiredrepair123",
		NotificationID: "ntf_bmuxnonexpiredrepair123",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_bmuxnonexpiredrepair123",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Repair must not requeue a non-expired stale bmux claim if cleanup fails.",
			CreatedAt:  claimedAt,
		},
	}, "reviewer")
	claimHolder := "session:" + record.SessionID + ":" + record.Generation
	if _, err := daemon.store.ClaimMessage(ctx, MessageClaimOptions{
		Profile:           record.Profile,
		MessageID:         messageID,
		ClaimHolder:       claimHolder,
		SessionID:         &record.SessionID,
		SessionScopeType:  &record.ScopeType,
		SessionScopeID:    &record.ScopeID,
		SessionGeneration: &record.Generation,
		Now:               time.Now().UTC(),
	}); err != nil {
		t.Fatal(err)
	}

	daemon.sessionMu.Lock()
	daemon.busMu.Lock()
	actions, repairErr := daemon.reconcileLocked(ctx, time.Now().UTC(), RepairFilter{MessageID: messageID}, true)
	daemon.busMu.Unlock()
	daemon.sessionMu.Unlock()
	if repairErr == nil || !strings.Contains(repairErr.Error(), "could not stop stale bmux session") {
		t.Fatalf("non-expired stale bmux repair err = %v, want cleanup failure", repairErr)
	}
	if len(actions) != 0 {
		t.Fatalf("non-expired stale bmux cleanup failure actions = %#v, want none", actions)
	}
	after, err := daemon.store.GetInboxMessage(ctx, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if after.Delivery.State != "claimed" || stringValue(after.Delivery.ClaimHolder) != claimHolder {
		t.Fatalf("non-expired stale bmux cleanup failure changed delivery = %+v, want claimed by %s", after.Delivery, claimHolder)
	}
	bmux.mu.Lock()
	defer bmux.mu.Unlock()
	if len(bmux.killAttempts) != 1 || bmux.killAttempts[0] != record.SessionName {
		t.Fatalf("non-expired stale bmux cleanup attempts = %+v, want %s", bmux.killAttempts, record.SessionName)
	}
}

