func TestDaemonBmuxStartupReadyMarkerFailureFallsBackToOrientation(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	bmux := newTestBmuxController(paths)
	bmux.waitForOutputReady = false
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()

	sessionName := "comment-reviewer-abc123"
	paneTarget, err := BmuxSocketPathForSession(paths, sessionName)
	if err != nil {
		t.Fatal(err)
	}
	bmux.mu.Lock()
	bmux.sessions[sessionName] = paneTarget
	bmux.paneCommands[paneTarget] = "agent"
	bmux.mu.Unlock()

	record := SessionRecord{
		Host:              SessionHostBmux,
		Profile:           "max.reviewer",
		BotName:           "reviewer",
		SessionName:       sessionName,
		PaneTarget:        paneTarget,
		Runtime:           "agent",
		RuntimeSessionRef: "123e4567-e89b-42d3-a456-426614174000",
	}
	_, errOut := daemon.sendSessionStartupInstruction(ctx, record, "https://comment.example", "max.reviewer", BotRegistryEntry{Name: "reviewer", Handle: "max.reviewer"})
	if errOut != nil {
		t.Fatalf("startup marker failure should fall back to sending orientation, got %+v", errOut)
	}
	bmux.mu.Lock()
	defer bmux.mu.Unlock()
	if bmux.waitForOutputCalls != 1 {
		t.Fatalf("waitForOutputCalls = %d, want 1", bmux.waitForOutputCalls)
	}
	if !testSendsContainPrefixAndNeedle(bmux.sends, "literal "+paneTarget+" ", "https://comment.example/llms.txt") {
		t.Fatalf("startup orientation was not sent after missing ready marker: sends=%+v", bmux.sends)
	}
	if bmux.sends[len(bmux.sends)-1] != "enter "+paneTarget {
		t.Fatalf("startup orientation should be submitted after missing ready marker: sends=%+v", bmux.sends)
	}
}

