func TestDaemonBmuxLaunchErrorIncludesBmuxBinaryHint(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	runtimeHome := privateTestDir(t, "comment-bus-bmux-launch-error-home-")
	t.Setenv("HOME", runtimeHome)
	binDir := filepath.Join(runtimeHome, ".local", "bin")
	if err := os.MkdirAll(binDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(binDir, "claude"), []byte("#!/bin/sh\nexit 0\n"), 0o700); err != nil {
		t.Fatal(err)
	}
	t.Setenv("PATH", binDir+string(os.PathListSeparator)+os.Getenv("PATH"))
	bmux := newTestBmuxController(paths)
	bmux.newSessionErr = errors.New("bmux binary not found in trusted directories; install it on a standard path or set " + BmuxBinaryEnv + " to an absolute path")
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()

	reviewerPath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_reviewer_profile_secret",
	})
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled": true,
			"runtime": "claude",
			"host":    "bmux",
		},
	}})
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxlaunchhintreload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxlaunchhintstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if start.OK || start.Error == nil || start.Error.Code != "UPSTREAM_ERROR" || !strings.Contains(start.Error.Message, BmuxBinaryEnv) {
		t.Fatalf("bmux launch error = %+v", start.Error)
	}
	if strings.Contains(start.Error.Message, TmuxBinaryEnv) {
		t.Fatalf("bmux launch error mentioned tmux env: %q", start.Error.Message)
	}
}

func TestDaemonManagedSessionFencesDuplicateLiveSessions(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	originalID := session["session_id"].(string)
	original, err := ReadSessionRecord(paths, originalID)
	if err != nil {
		t.Fatal(err)
	}
	duplicateID, err := GenerateLocalID("sess", 0)
	if err != nil {
		t.Fatal(err)
	}
	duplicateGeneration, err := GenerateLocalID("gen", 0)
	if err != nil {
		t.Fatal(err)
	}
	duplicateName, err := tmuxSessionName("reviewer", duplicateID)
	if err != nil {
		t.Fatal(err)
	}
	duplicate, err := RegisterSession(RegisterSessionOptions{
		Paths:       paths,
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		ScopeType:   "profile",
		ScopeID:     "max.reviewer",
		SessionID:   duplicateID,
		Generation:  duplicateGeneration,
		BotletsHome: original.BotletsHome,
		SessionName: duplicateName,
		PaneTarget:  "%777",
		Runtime:     original.Runtime,
		State:       "alive",
		Now:         time.Now().UTC().Add(time.Hour),
	})
	if err != nil {
		t.Fatal(err)
	}
	duplicate.RuntimePath = original.RuntimePath
	duplicate.RuntimeCommandPath = original.RuntimeCommandPath
	duplicate.RuntimeCommand = append([]string(nil), original.RuntimeCommand...)
	if err := WriteSessionRecord(paths, duplicate); err != nil {
		t.Fatal(err)
	}
	tmux.mu.Lock()
	tmux.setActivePaneLocked(duplicate.SessionName, duplicate.PaneTarget)
	tmux.paneCommands[duplicate.PaneTarget] = "claude"
	tmux.mu.Unlock()

	reconciled := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !reconciled.OK {
		t.Fatalf("duplicate reconciliation failed: %+v", reconciled.Error)
	}
	reconciledSession := reconciled.Result.(map[string]any)["session"].(map[string]any)
	if reconciledSession["session_id"] != duplicateID {
		t.Fatalf("expected newest duplicate to be kept: %#v", reconciledSession)
	}
	originalAfter, err := ReadSessionRecord(paths, originalID)
	if err != nil {
		t.Fatal(err)
	}
	duplicateAfter, err := ReadSessionRecord(paths, duplicateID)
	if err != nil {
		t.Fatal(err)
	}
	if originalAfter.State != "stale" || duplicateAfter.State != "alive" {
		t.Fatalf("duplicate fencing states: original=%s duplicate=%s", originalAfter.State, duplicateAfter.State)
	}
	tmux.mu.Lock()
	_, originalLive := tmux.sessions[original.SessionName]
	_, duplicateLive := tmux.sessions[duplicate.SessionName]
	kills := append([]string(nil), tmux.kills...)
	tmux.mu.Unlock()
	if originalLive || !duplicateLive {
		t.Fatalf("tmux live state after duplicate fencing: original=%v duplicate=%v", originalLive, duplicateLive)
	}
	if len(kills) != 1 || kills[0] != original.SessionName {
		t.Fatalf("duplicate fencing kills = %+v, want [%s]", kills, original.SessionName)
	}
}

func TestDaemonManagedSessionDuplicateFenceKillFailureKeepsSessionAlive(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	record := requireOnlyAliveSessionForBot(t, paths, "reviewer")
	tmux.mu.Lock()
	tmux.failKill[record.SessionName] = true
	tmux.mu.Unlock()

	daemon.sessionMu.Lock()
	_, fenceErr := daemon.fenceDuplicateLiveSessionLocked(record)
	daemon.sessionMu.Unlock()
	if fenceErr == nil || fenceErr.Code != "UPSTREAM_ERROR" {
		t.Fatalf("duplicate fence kill failure = %+v", fenceErr)
	}
	after, err := ReadSessionRecord(paths, record.SessionID)
	if err != nil {
		t.Fatal(err)
	}
	if after.State != "alive" {
		t.Fatalf("failed duplicate fence should restore session alive: %+v", after)
	}
	tmux.mu.Lock()
	_, live := tmux.sessions[record.SessionName]
	tmux.mu.Unlock()
	if !live {
		t.Fatal("failed duplicate fence killed tmux session")
	}
}

