func TestDaemonManagedSessionDailyResetFallbackRequeuesClaimedBotletsTask(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	oldGrace := managedSessionDailyResetGracePeriod
	managedSessionDailyResetGracePeriod = time.Millisecond
	t.Cleanup(func() { managedSessionDailyResetGracePeriod = oldGrace })

	resetNow := testDailyResetNow()
	paths, daemon, _, _, messageID, brainRoot := startBotletsTaskDaemonWithLeaseAt(t, ctx, "clm_dailyfallback1234567890", "ntf_dailyfallback1234567890", testDailyResetSessionStartNow())
	defer daemon.Close()
	record := requireOnlyAliveSessionForBot(t, paths, "reviewer")
	sessionCapability, err := ReadCapability(record.CapabilityFile)
	if err != nil {
		t.Fatal(err)
	}
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         record.SessionID,
			"session_generation": record.Generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("session receive before reset failed: %+v", receive.Error)
	}
	daemon.now = func() time.Time { return resetNow }
	if errs := daemon.runManagedSessionDailyResetOnce(ctx); len(errs) != 0 {
		t.Fatalf("daily reset request errors = %+v", errs)
	}
	daemon.now = func() time.Time { return resetNow.Add(2 * time.Millisecond) }
	if errs := daemon.runManagedSessionDailyResetOnce(ctx); len(errs) != 0 {
		t.Fatalf("daily reset fallback errors = %+v", errs)
	}
	oldAfter, err := ReadSessionRecord(paths, record.SessionID)
	if err != nil {
		t.Fatal(err)
	}
	wantLogPath := filepath.Join(brainRoot, "logs", "2026-05-27.md")
	if oldAfter.State != "dead" || oldAfter.DailyReset == nil || oldAfter.DailyReset.State != "completed" || oldAfter.DailyReset.LogPath != wantLogPath {
		t.Fatalf("fallback old reset record = %+v", oldAfter)
	}
	logData, err := os.ReadFile(wantLogPath)
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(string(logData), "Daily Reset Fallback") || !strings.Contains(string(logData), record.SessionID) {
		t.Fatalf("fallback log content = %s", string(logData))
	}
	replacementID := oldAfter.DailyReset.ReplacementSessionID
	replacement, err := ReadSessionRecord(paths, replacementID)
	if err != nil {
		t.Fatal(err)
	}
	if replacement.State != "alive" {
		t.Fatalf("replacement after fallback = %+v", replacement)
	}
	daemon.busMu.Lock()
	messageAfterFallback, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if messageAfterFallback.Delivery.State != "unclaimed" {
		t.Fatalf("claimed task was not requeued: %+v", messageAfterFallback.Delivery)
	}
	replacementCapability, err := ReadCapability(replacement.CapabilityFile)
	if err != nil {
		t.Fatal(err)
	}
	receiveAfterFallback := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         replacement.SessionID,
			"session_generation": replacement.Generation,
			"capability":         replacementCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receiveAfterFallback.OK {
		t.Fatalf("replacement receive after fallback failed: %+v", receiveAfterFallback.Error)
	}
	if got := countMessagesBySource(t, daemon, "max.reviewer", "comment.io"); got != 1 {
		t.Fatalf("cloud task count after fallback = %d, want 1", got)
	}
}

func TestDaemonManagedSessionLazyStartsAndNudgesOnLocalWrite(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_lazywritenudge",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "body with $(shell) and ; metacharacters"},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)

	tmux.mu.Lock()
	starts := append([]TmuxNewSessionOptions{}, tmux.starts...)
	sends := append([]string{}, tmux.sends...)
	tmux.mu.Unlock()
	if len(starts) != 1 {
		t.Fatalf("tmux starts = %#v", starts)
	}
	if !strings.Contains(starts[0].Command, " session-exec sess_") || strings.Contains(starts[0].Command, "body with") {
		t.Fatalf("tmux launch command = %q", starts[0].Command)
	}
	if len(sends) != 4 || !strings.HasPrefix(sends[0], "literal ") || !strings.HasPrefix(sends[1], "enter ") || !strings.HasPrefix(sends[2], "literal ") || !strings.HasPrefix(sends[3], "enter ") {
		t.Fatalf("tmux sends = %#v", sends)
	}
	if !strings.Contains(sends[0], "handle max.reviewer") || !strings.Contains(sends[0], "https://comment.io/llms.txt") || strings.Contains(sends[0], "body with") {
		t.Fatalf("startup instruction should point at llms.txt without message content: %#v", sends)
	}
	if !strings.Contains(sends[2], "comment messages receive "+messageID) {
		t.Fatalf("nudge did not include local message id: %#v", sends)
	}
	if strings.Contains(sends[2], "body with") || strings.ContainsAny(sends[2], "`\"'$;&|<>\n\r") {
		t.Fatalf("nudge exposed unsafe content: %#v", sends)
	}
	spooled, ok, err := ReadMessageSpool(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if !ok || spooled.MessageID != messageID || spooled.LastNudge.SucceededAt == nil {
		t.Fatalf("spool after nudge = %+v ok=%v", spooled, ok)
	}
	records, err := ListSessionRecords(paths)
	if err != nil {
		t.Fatal(err)
	}
	var reviewer SessionRecord
	for _, record := range records {
		if record.BotName == "reviewer" {
			reviewer = record
			break
		}
	}
	if reviewer.SessionID == "" {
		t.Fatal("reviewer session record not found")
	}
	sessionCapability, err := ReadCapability(reviewer.CapabilityFile)
	if err != nil {
		t.Fatal(err)
	}
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_lazyspoolreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         reviewer.SessionID,
			"session_generation": reviewer.Generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("receive failed: %+v", receive.Error)
	}
	if _, ok, err := ReadMessageSpool(paths, "max.reviewer", messageID); err != nil || ok {
		t.Fatalf("spool after receive ok=%v err=%v", ok, err)
	}
}

