func TestDaemonRuntimeNudgesUseShortReceiveCommand(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_llmsfirststart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("sessions start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	generation := session["generation"].(string)
	sessionCapability, err := ReadCapability(session["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}
	sendMessage := func(id string, body string) string {
		t.Helper()
		response := requestDaemon(t, paths, map[string]any{
			"id": id,
			"op": "messages.send",
			"auth": map[string]any{
				"mode":       "owner",
				"capability": capability,
			},
			"params": map[string]any{
				"from_bot": "sender",
				"to":       []any{"reviewer"},
				"body":     map[string]any{"format": "markdown", "content": body},
			},
		})
		if !response.OK {
			t.Fatalf("%s send failed: %+v", id, response.Error)
		}
		return response.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	}

	firstID := sendMessage("req_shortfirstmessage", "first body should not appear in the tmux nudge")
	tmux.mu.Lock()
	firstSends := append([]string(nil), tmux.sends...)
	tmux.mu.Unlock()
	if len(firstSends) != 4 || !strings.HasPrefix(firstSends[0], "literal ") || !strings.HasPrefix(firstSends[1], "enter ") || !strings.HasPrefix(firstSends[2], "literal ") || !strings.HasPrefix(firstSends[3], "enter ") {
		t.Fatalf("first tmux sends = %#v", firstSends)
	}
	if !strings.Contains(firstSends[0], "https://comment.io/llms.txt") {
		t.Fatalf("first tmux send did not include startup llms.txt instruction: %#v", firstSends)
	}
	firstNudgeText := testPromptPayload(firstSends[2])
	if !strings.Contains(firstNudgeText, "comment messages receive "+firstID) {
		t.Fatalf("first nudge did not include message id %s: %#v", firstID, firstSends)
	}
	if strings.Contains(firstNudgeText, "llms.txt") || strings.Contains(firstNudgeText, "first body") || len(firstNudgeText) > 256 {
		t.Fatalf("first nudge should stay short and local: %#v", firstSends)
	}

	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_shortfirstreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": firstID},
	})
	if !receive.OK {
		t.Fatalf("receive failed: %+v", receive.Error)
	}
	tmux.mu.Lock()
	sendsBeforeSecond := len(tmux.sends)
	tmux.mu.Unlock()
	secondID := sendMessage("req_shortsecondmessage", "second")
	tmux.mu.Lock()
	sendsWhileActive := append([]string(nil), tmux.sends[sendsBeforeSecond:]...)
	tmux.mu.Unlock()
	if len(sendsWhileActive) != 0 {
		t.Fatalf("send while active should not nudge: %#v", sendsWhileActive)
	}
	ack := requestDaemon(t, paths, map[string]any{
		"id": "req_shortfirstack",
		"op": "messages.ack",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": firstID},
	})
	if !ack.OK {
		t.Fatalf("ack failed: %+v", ack.Error)
	}
	tmux.mu.Lock()
	secondSends := append([]string(nil), tmux.sends[sendsBeforeSecond:]...)
	tmux.mu.Unlock()
	if len(secondSends) != 2 || !strings.HasPrefix(secondSends[0], "literal ") || !strings.HasPrefix(secondSends[1], "enter ") {
		t.Fatalf("second tmux sends = %#v", secondSends)
	}
	secondNudgeText := testPromptPayload(secondSends[0])
	if strings.Contains(secondNudgeText, "llms.txt") || !strings.Contains(secondNudgeText, "comment messages receive "+secondID) || len(secondNudgeText) > 256 {
		t.Fatalf("second nudge should be plain message nudge: %#v", secondSends)
	}
}

func TestDaemonStructuredLogsForManagedSessionFlow(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	var logs bytes.Buffer
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		Tmux:        newTestTmuxController(),
		LogWriter:   &logs,
		Now: func() time.Time {
			return time.Date(2026, 5, 7, 0, 0, 0, 0, time.UTC)
		},
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_logmanagedsend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "local log body should stay private"},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	records, err := ListSessionRecords(paths)
	if err != nil {
		t.Fatal(err)
	}
	var reviewer SessionRecord
	for _, record := range records {
		if record.BotName == "reviewer" && record.State == "alive" {
			reviewer = record
			break
		}
	}
	if reviewer.SessionID == "" {
		t.Fatalf("reviewer session not found: %+v", records)
	}
	sessionCapability, err := ReadCapability(reviewer.CapabilityFile)
	if err != nil {
		t.Fatal(err)
	}
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_logmanagedreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            reviewer.Profile,
			"session_id":         reviewer.SessionID,
			"session_generation": reviewer.Generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("receive failed: %+v", receive.Error)
	}
	stop := requestDaemon(t, paths, map[string]any{
		"id": "req_logmanagedstop",
		"op": "sessions.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": reviewer.SessionID, "reason": "test complete"},
	})
	if !stop.OK {
		t.Fatalf("stop failed: %+v", stop.Error)
	}

	text := logs.String()
	if strings.Contains(text, "local log body") || containsSecretValue(text) {
		t.Fatalf("structured logs leaked sensitive content: %s", text)
	}
	entries := structuredLogEntries(t, &logs)
	for _, msg := range []string{
		"bus.startup_repair",
		"bus.local_write",
		"session.started",
		"tmux.nudge_attempted",
		"tmux.nudge_succeeded",
		"message.received",
		"session.dead",
	} {
		requireStructuredLog(t, entries, msg)
	}
	localWrite := requireStructuredLog(t, entries, "bus.local_write")
	if localWrite.Data["message_id"] != messageID || localWrite.Data["profile"] != "max.reviewer" || localWrite.Data["bot_name"] != "reviewer" {
		t.Fatalf("local write log data = %#v", localWrite.Data)
	}
	received := requireStructuredLog(t, entries, "message.received")
	if received.Data["claim_holder_type"] != "session" || received.Data["session_id"] != reviewer.SessionID {
		t.Fatalf("received log data = %#v", received.Data)
	}
}

func TestDaemonStructuredLogsForCloudLeaseFlow(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimID := "clm_logcloudclaim1234567890"
	notificationID := "ntf_logcloudnotification1234"
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         notificationID,
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "cloud log body should stay private",
			CreatedAt:  claimedAt,
		},
	}
	paths := testDaemonPaths(t)
	var logs bytes.Buffer
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
		LogWriter:          &logs,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_logcloudwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("cloud wait failed: %+v", wait.Error)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_logcloudreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("cloud receive failed: %+v", receive.Error)
	}
	renew := requestDaemon(t, paths, map[string]any{
		"id": "req_logcloudrenew",
		"op": "messages.renew",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "lease_ttl_ms": 60_000},
	})
	if !renew.OK {
		t.Fatalf("cloud renew failed: %+v", renew.Error)
	}
	ack := requestDaemon(t, paths, map[string]any{
		"id": "req_logcloudack",
		"op": "messages.ack",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !ack.OK {
		t.Fatalf("cloud ack failed: %+v", ack.Error)
	}

	text := logs.String()
	if strings.Contains(text, claimID) || strings.Contains(text, notificationID) || strings.Contains(text, "cloud log body") || containsSecretValue(text) {
		t.Fatalf("structured logs leaked cloud-private content: %s", text)
	}
	entries := structuredLogEntries(t, &logs)
	for _, msg := range []string{
		"socket.request.start",
		"socket.request.end",
		"lease.acquired",
		"message.received",
		"notification.cloud_mutation.start",
		"notification.cloud_mutation.remote_end",
		"notification.cloud_mutation.local_complete",
		"lease.renewed",
		"message.ack_proxied",
	} {
		requireStructuredLog(t, entries, msg)
	}
	acquired := requireStructuredLog(t, entries, "lease.acquired")
	if acquired.Data["message_id"] != messageID || acquired.Data["source"] != "comment.io" || acquired.Data["mode"] != "new" {
		t.Fatalf("lease acquired log data = %#v", acquired.Data)
	}
	cloudMutation := requireStructuredLog(t, entries, "notification.cloud_mutation.start")
	if cloudMutation.Data["message_id"] != messageID || cloudMutation.Data["profile"] != "max.reviewer" || cloudMutation.Data["op_id"] == "" {
		t.Fatalf("cloud mutation log data = %#v", cloudMutation.Data)
	}
}

