func TestEnvCommandNameSplitsQuotedSplitStringOperand(t *testing.T) {
	for _, tokens := range [][]string{
		{"-S", "-u NODE_OPTIONS node"},
		{"--split-string", "-u NODE_OPTIONS node"},
		{"-S-u", "NODE_OPTIONS", "node"},
		{"-Snode"},
	} {
		if got := envCommandName(tokens); got != "node" {
			t.Fatalf("envCommandName(%#v) = %q, want node", tokens, got)
		}
	}
}

