func TestDaemonStartingSessionRecoveryRequiresRuntimeCommand(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)
	sessionID, err := GenerateLocalID("sess", 0)
	if err != nil {
		t.Fatal(err)
	}
	generation, err := GenerateLocalID("gen", 0)
	if err != nil {
		t.Fatal(err)
	}
	sessionName, err := tmuxSessionName("reviewer", sessionID)
	if err != nil {
		t.Fatal(err)
	}
	paneTarget := sessionName + ":0.0"
	claudePath := prependFakeRuntime(t, "claude")
	record, err := RegisterSession(RegisterSessionOptions{
		Paths:       paths,
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		ScopeType:   "profile",
		ScopeID:     "max.reviewer",
		SessionID:   sessionID,
		Generation:  generation,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
		SessionName: sessionName,
		PaneTarget:  paneTarget,
		Runtime:     "claude",
		State:       "starting",
		Now:         time.Now().Add(-managedSessionRuntimeStartupTimeout - time.Second).UTC(),
	})
	if err != nil {
		t.Fatal(err)
	}
	runtimeResolution, err := resolveRuntimeCommandPath(claudePath)
	if err != nil {
		t.Fatal(err)
	}
	record.RuntimePath = runtimeResolution.RuntimePath
	record.RuntimeCommandPath = runtimeResolution.CommandPath
	record.RuntimeLaunchMode = RuntimeLaunchModePath
	if err := WriteSessionRecord(paths, record); err != nil {
		t.Fatal(err)
	}
	tmux.mu.Lock()
	tmux.sessions[sessionName] = paneTarget
	tmux.paneCommands[paneTarget] = "zsh"
	tmux.mu.Unlock()

	startedAt := time.Now()
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_startingrecoverruntime",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("replacement start after stuck starting session failed: %+v", start.Error)
	}
	if elapsed := time.Since(startedAt); elapsed > 2*time.Second {
		t.Fatalf("replacement start after expired starting session took %s, want no fresh startup wait", elapsed)
	}
	replacementID := start.Result.(map[string]any)["session"].(map[string]any)["session_id"].(string)
	if replacementID == record.SessionID {
		t.Fatalf("stuck starting session was promoted to alive: %s", replacementID)
	}
	recordAfter, err := ReadSessionRecord(paths, record.SessionID)
	if err != nil {
		t.Fatal(err)
	}
	if recordAfter.State != "stale" {
		t.Fatalf("stuck starting session state = %+v", recordAfter)
	}
}

func TestDaemonKeepsStoredPaneTargetWhenActivePaneChangesBeforeNudge(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_reresolvepanestart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	sessionName := session["session_name"].(string)
	oldPaneTarget := session["pane_target"].(string)
	newPaneTarget := "%999"
	tmux.mu.Lock()
	tmux.setActivePaneLocked(sessionName, newPaneTarget)
	tmux.paneCommands[oldPaneTarget] = "claude"
	tmux.paneCommands[newPaneTarget] = "claude"
	tmux.sends = nil
	tmux.mu.Unlock()

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_stablepanesend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "use the stored pane target"},
		},
	})
	if !send.OK {
		t.Fatalf("send after active pane change failed: %+v", send.Error)
	}
	if dispatchErrors, ok := send.Result.(map[string]any)["dispatch_errors"]; ok && len(dispatchErrors.([]any)) != 0 {
		t.Fatalf("stable pane dispatch errors = %#v", dispatchErrors)
	}
	tmux.mu.Lock()
	sends := append([]string{}, tmux.sends...)
	tmux.mu.Unlock()
	if len(sends) != 2 || !strings.Contains(sends[0], "literal "+oldPaneTarget+" ") || !strings.Contains(sends[1], "enter "+oldPaneTarget) {
		t.Fatalf("stable pane sends = %#v", sends)
	}
	record, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	if record.PaneTarget != oldPaneTarget || record.State != "alive" {
		t.Fatalf("stable pane record = %+v", record)
	}
}

func TestDaemonSessionStartPersistsPaneTargetBeforeRuntimeWait(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)
	_ = prependFakeRuntime(t, "claude")
	var checked atomic.Bool
	tmux.mu.Lock()
	tmux.defaultPaneCommandSequence = []string{"zsh", "claude"}
	tmux.beforePaneCurrentCommand = func(paneTarget string) {
		if checked.Swap(true) {
			return
		}
		records, err := ListSessionRecords(paths)
		if err != nil {
			t.Errorf("list session records during runtime wait: %v", err)
			return
		}
		if len(records) != 1 {
			t.Errorf("session records during runtime wait = %+v", records)
			return
		}
		record := records[0]
		if record.State != "starting" || record.PaneTarget != paneTarget {
			t.Errorf("session record before runtime wait = %+v, pane=%s", record, paneTarget)
		}
	}
	tmux.mu.Unlock()

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_startpersistspane",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start failed: %+v", start.Error)
	}
	if !checked.Load() {
		t.Fatal("runtime wait hook was not reached")
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	if session["pane_target"] == "" {
		t.Fatalf("started session missing pane target: %#v", session)
	}
	record, err := ReadSessionRecord(paths, session["session_id"].(string))
	if err != nil {
		t.Fatal(err)
	}
	// Shell-mode managed sessions pin no runtime path.
	if record.RuntimeLaunchMode != RuntimeLaunchModeShell || record.RuntimePath != "" || record.State != "alive" {
		t.Fatalf("started session record = %+v", record)
	}
}

func TestDaemonSessionStartRetriesTransientForegroundInspectFailures(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)
	_ = prependFakeRuntime(t, "claude")

	var attempts atomic.Int32
	tmux.beforePaneCurrentCommand = func(paneTarget string) {
		attempt := attempts.Add(1)
		tmux.mu.Lock()
		defer tmux.mu.Unlock()
		if attempt <= 3 {
			tmux.failPaneCommand[paneTarget] = true
			return
		}
		tmux.failPaneCommand[paneTarget] = false
		tmux.paneCommands[paneTarget] = "claude"
	}

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_startretryinspect",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start failed after transient foreground inspect failures: %+v", start.Error)
	}
	if got := attempts.Load(); got < 4 {
		t.Fatalf("foreground inspect attempts = %d, want retries before success", got)
	}
	if len(tmux.kills) != 0 {
		t.Fatalf("transient foreground inspect failures killed session(s): %#v", tmux.kills)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	if session["state"] != "alive" {
		t.Fatalf("session state = %#v, want alive", session)
	}
}

