func TestDaemonLocalWriteRenudgesExistingReadyQueueHead(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	sendMessage := func(id string, body string) string {
		t.Helper()
		response := requestDaemon(t, paths, map[string]any{
			"id": id,
			"op": "messages.send",
			"auth": map[string]any{
				"mode":       "owner",
				"capability": capability,
			},
			"params": map[string]any{
				"from_bot": "sender",
				"to":       []any{"reviewer"},
				"body":     map[string]any{"format": "markdown", "content": body},
			},
		})
		if !response.OK {
			t.Fatalf("%s send failed: %+v", id, response.Error)
		}
		return response.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	}

	firstID := sendMessage("req_renudgefirst", "first ready message")
	tmux.mu.Lock()
	sendsBeforeSecond := len(tmux.sends)
	tmux.mu.Unlock()
	secondID := sendMessage("req_renudgesecond", "second queued message")

	tmux.mu.Lock()
	secondSends := append([]string(nil), tmux.sends[sendsBeforeSecond:]...)
	tmux.mu.Unlock()
	foundFirst := false
	foundSecond := false
	for _, send := range secondSends {
		if strings.Contains(send, "comment messages receive "+firstID) {
			foundFirst = true
		}
		if strings.Contains(send, "comment messages receive "+secondID) {
			foundSecond = true
		}
	}
	if !foundFirst || foundSecond {
		t.Fatalf("second write should re-nudge existing queue head only; first=%s second=%s sends=%#v", firstID, secondID, secondSends)
	}
}

