func TestDaemonSessionStartStalesMultipleLegacyAliveStateOnlyRecords(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	var legacyIDs []string
	for i := 0; i < 2; i++ {
		record, err := RegisterSession(RegisterSessionOptions{
			Paths:       paths,
			Profile:     "max.reviewer",
			BotName:     "reviewer",
			ScopeType:   "profile",
			ScopeID:     "max.reviewer",
			BotletsHome: filepath.Join(paths.Home, "botlets"),
			Runtime:     "claude",
			State:       "alive",
			Now:         time.Now().UTC(),
		})
		if err != nil {
			t.Fatal(err)
		}
		legacyIDs = append(legacyIDs, record.SessionID)
	}

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_startstaleslegacyalive",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start should stale legacy records and launch a managed session: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	if session["state"] != "alive" || session["session_name"] == "" || session["pane_target"] == "" {
		t.Fatalf("started session = %#v", session)
	}
	for _, legacyID := range legacyIDs {
		if session["session_id"] == legacyID {
			t.Fatalf("start reused legacy state-only session: %#v", session)
		}
		legacy, err := ReadSessionRecord(paths, legacyID)
		if err != nil {
			t.Fatal(err)
		}
		if legacy.State != "stale" {
			t.Fatalf("legacy session %s state = %s, want stale", legacyID, legacy.State)
		}
	}
}

func TestDaemonSessionStatusMarksMissingTmuxStaleAndRequeuesClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_stalestart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	generation := session["generation"].(string)
	sessionName := session["session_name"].(string)
	sessionCapability, err := ReadCapability(session["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_stalesend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "claim then stale"},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_stalereceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("session receive failed: %+v", receive.Error)
	}

	tmux.mu.Lock()
	delete(tmux.sessions, sessionName)
	tmux.mu.Unlock()

	status := requestDaemon(t, paths, map[string]any{
		"id": "req_stalestatus",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID},
	})
	if !status.OK {
		t.Fatalf("status failed: %+v", status.Error)
	}
	statusSession := status.Result.(map[string]any)["sessions"].([]any)[0].(map[string]any)
	if statusSession["state"] != "stale" {
		t.Fatalf("status session = %#v", statusSession)
	}
	sessionStatus := requestDaemon(t, paths, map[string]any{
		"id": "req_stalesessionauth",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{},
	})
	if sessionStatus.OK || sessionStatus.Error == nil || sessionStatus.Error.Code != "FORBIDDEN" {
		t.Fatalf("stale session auth response = %+v", sessionStatus)
	}
	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_stalewait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK || wait.Result.(map[string]any)["message_id"] != messageID {
		t.Fatalf("requeued message wait response = %+v", wait)
	}
	tmux.mu.Lock()
	sendsBeforeRestart := len(tmux.sends)
	tmux.mu.Unlock()
	sendAfterStale := requestDaemon(t, paths, map[string]any{
		"id": "req_stalesendafterstatus",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "newer work should not overtake stale work"},
		},
	})
	if !sendAfterStale.OK {
		t.Fatalf("send after stale failed: %+v", sendAfterStale.Error)
	}
	newMessageID := sendAfterStale.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	tmux.mu.Lock()
	restartSends := append([]string(nil), tmux.sends[sendsBeforeRestart:]...)
	tmux.mu.Unlock()
	foundRequeueNudge := false
	foundNewNudge := false
	for _, send := range restartSends {
		if strings.Contains(send, "comment messages receive "+messageID) {
			foundRequeueNudge = true
		}
		if strings.Contains(send, "comment messages receive "+newMessageID) {
			foundNewNudge = true
		}
	}
	if !foundRequeueNudge {
		t.Fatalf("restart did not nudge requeued message %s: %#v", messageID, restartSends)
	}
	if foundNewNudge {
		t.Fatalf("restart nudged newer message %s before requeued message was claimed: %#v", newMessageID, restartSends)
	}
	records, err := ListSessionRecords(paths)
	if err != nil {
		t.Fatal(err)
	}
	var replacement SessionRecord
	for _, record := range records {
		if record.Profile == "max.reviewer" && record.BotName == "reviewer" && record.State == "alive" && record.SessionID != sessionID {
			replacement = record
			break
		}
	}
	if replacement.SessionID == "" {
		t.Fatalf("replacement session not found: %#v", records)
	}
	replacementCapability, err := ReadCapability(replacement.CapabilityFile)
	if err != nil {
		t.Fatal(err)
	}
	receiveRequeued := requestDaemon(t, paths, map[string]any{
		"id": "req_stalereplacementreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            replacement.Profile,
			"session_id":         replacement.SessionID,
			"session_generation": replacement.Generation,
			"capability":         replacementCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receiveRequeued.OK {
		t.Fatalf("replacement receive failed: %+v", receiveRequeued.Error)
	}
	tmux.mu.Lock()
	sendsBeforeActiveClaim := len(tmux.sends)
	tmux.mu.Unlock()
	sendWhileActive := requestDaemon(t, paths, map[string]any{
		"id": "req_stalesendwhileactive",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "do not nudge while active"},
		},
	})
	if !sendWhileActive.OK {
		t.Fatalf("send while active failed: %+v", sendWhileActive.Error)
	}
	tmux.mu.Lock()
	activeClaimSends := append([]string(nil), tmux.sends[sendsBeforeActiveClaim:]...)
	tmux.mu.Unlock()
	if len(activeClaimSends) != 0 {
		t.Fatalf("send while replacement session had active claim should not nudge: %#v", activeClaimSends)
	}
}

func TestDaemonSessionStatusRemoteReleasesExpiredCloudClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := CloudNotificationLease{
		ClaimID:        "clm_statusexpiredcloud1234567890",
		NotificationID: "ntf_statusexpiredcloud1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_statusexpiredcloud1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Expired cloud claim should remote release on liveness repair.",
			CreatedAt:  claimedAt,
		},
	}
	paths := testDaemonPaths(t)
	client := &fakeNotificationClient{claimNotifications: map[string]string{lease.ClaimID: lease.NotificationID}}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_statusexpiredstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	generation := session["generation"].(string)
	sessionName := session["session_name"].(string)

	daemon.busMu.Lock()
	messageID := seedClaimedCloudMessage(t, paths, daemon.store, lease)
	expiredAt := busTime(time.Now().Add(-time.Minute))
	if _, err := daemon.store.db.Exec(`UPDATE message_recipients
		SET claim_holder = ?, session_id = ?, session_scope_type = 'profile', session_scope_id = 'max.reviewer', session_generation = ?, lease_expires_at = ?
		WHERE message_id = ? AND profile = ?`,
		"session:"+sessionID+":"+generation,
		sessionID,
		generation,
		expiredAt,
		messageID,
		"max.reviewer",
	); err != nil {
		daemon.busMu.Unlock()
		t.Fatal(err)
	}
	daemon.busMu.Unlock()

	tmux := daemon.tmux.(*testTmuxController)
	tmux.mu.Lock()
	delete(tmux.sessions, sessionName)
	tmux.mu.Unlock()

	status := requestDaemon(t, paths, map[string]any{
		"id": "req_statusexpiredstatus",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID},
	})
	if !status.OK {
		t.Fatalf("status failed: %+v", status.Error)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if message.Delivery.State != "released" || message.Delivery.LeaseExpiresAt != nil || message.Delivery.ClaimHolder != nil {
		t.Fatalf("expired cloud status release delivery = %+v", message.Delivery)
	}
	if redactedJSON := latestMessageEventJSON(t, daemon, messageID, "message.released"); !strings.Contains(redactedJSON, `"reason":"lease_expired"`) {
		t.Fatalf("expired cloud status release event reason = %s", redactedJSON)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall(nil), client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 1 || mutations[0].Operation != "release" || mutations[0].ClaimID != lease.ClaimID {
		t.Fatalf("expired cloud status mutations = %+v", mutations)
	}
}

func TestDaemonMissingTmuxDoesNotReleaseClaimWhenStaleWriteFails(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	tmux := daemon.tmux.(*testTmuxController)

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_stalewritefailstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	generation := session["generation"].(string)
	sessionName := session["session_name"].(string)
	sessionCapability, err := ReadCapability(session["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_stalewritefailsend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "claim should stay claimed"},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_stalewritefailreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":               "session",
			"profile":            "max.reviewer",
			"session_id":         sessionID,
			"session_generation": generation,
			"capability":         sessionCapability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("session receive failed: %+v", receive.Error)
	}

	tmux.mu.Lock()
	delete(tmux.sessions, sessionName)
	tmux.mu.Unlock()
	daemon.writeSessionRecord = func(paths Paths, record SessionRecord) error {
		if record.SessionID == sessionID && record.State == "stale" {
			return errors.New("injected stale write failure")
		}
		return WriteSessionRecord(paths, record)
	}
	status := requestDaemon(t, paths, map[string]any{
		"id": "req_stalewritefailstatus",
		"op": "sessions.status",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"session_id": sessionID},
	})
	if status.OK || status.Error == nil || status.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("expected stale write failure, got %+v", status)
	}
	record, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	if record.State != "alive" {
		t.Fatalf("failed stale write changed record state = %s", record.State)
	}
	daemon.busMu.Lock()
	message, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if message.Delivery.State != "claimed" {
		t.Fatalf("claim was released despite failed stale write: %+v", message.Delivery)
	}
}

