func TestDaemonLocalMessageLifecycle(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_msgsend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "Please review this local-only message."},
			"refs":     map[string]any{"doc_slug": "abc123"},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	if encoded := mustJSON(t, send); containsSecretValue(encoded) {
		t.Fatalf("send response leaked secret-shaped value: %s", encoded)
	}
	messages := send.Result.(map[string]any)["messages"].([]any)
	if len(messages) != 1 {
		t.Fatalf("send messages = %#v", messages)
	}
	if outboxID := send.Result.(map[string]any)["outbox_id"].(string); !LocalOperationIDRE.MatchString(outboxID) {
		t.Fatalf("outbox_id = %q", outboxID)
	}
	message := messages[0].(map[string]any)
	messageID := message["id"].(string)
	if !LocalMessageIDRE.MatchString(messageID) || message["source"] != "local" || message["kind"] != "message" || message["profile"] != "max.reviewer" {
		t.Fatalf("unexpected sent message = %#v", message)
	}
	delivery := message["delivery"].(map[string]any)
	if delivery["state"] != "sent" || delivery["claim_holder"] != nil || delivery["session_id"] != nil || delivery["read_at"] != nil || delivery["lease_expires_at"] != nil {
		t.Fatalf("initial delivery = %#v", delivery)
	}

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_msgwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("wait failed: %+v", wait.Error)
	}
	waitResult := wait.Result.(map[string]any)
	if waitResult["message_id"] != messageID || waitResult["profile"] != "max.reviewer" {
		t.Fatalf("wait result = %#v", waitResult)
	}
	if _, ok := waitResult["body"]; ok {
		t.Fatalf("wait result exposed body: %#v", waitResult)
	}

	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_msgreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("receive failed: %+v", receive.Error)
	}
	received := receive.Result.(map[string]any)["message"].(map[string]any)
	receivedDelivery := received["delivery"].(map[string]any)
	if receivedDelivery["state"] != "claimed" || receivedDelivery["claim_holder"] != "owner:max.reviewer" || receivedDelivery["read_at"] == nil || receivedDelivery["lease_expires_at"] == nil {
		t.Fatalf("received delivery = %#v", receivedDelivery)
	}

	renewWithOpID := requestDaemon(t, paths, map[string]any{
		"id": "req_msgrenewop",
		"op": "messages.renew",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "lease_ttl_ms": 60_000, "op_id": "op_abcdefghijklmnopqrst"},
	})
	if renewWithOpID.OK || renewWithOpID.Error == nil || renewWithOpID.Error.Code != "VALIDATION_ERROR" {
		t.Fatalf("renew op_id response = %+v", renewWithOpID)
	}

	renew := requestDaemon(t, paths, map[string]any{
		"id": "req_msgrenew",
		"op": "messages.renew",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "lease_ttl_ms": 60_000},
	})
	if !renew.OK {
		t.Fatalf("renew failed: %+v", renew.Error)
	}
	if renew.Result.(map[string]any)["lease_expires_at"] == nil {
		t.Fatalf("renew result = %#v", renew.Result)
	}

	release := requestDaemon(t, paths, map[string]any{
		"id": "req_msgownerrelease",
		"op": "messages.release",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "reason": "owner retry"},
	})
	if !release.OK || release.Result.(map[string]any)["state"] != "unclaimed" {
		t.Fatalf("owner release response = %+v", release)
	}
	if redactedJSON := latestMessageEventJSON(t, daemon, messageID, "message.released"); !strings.Contains(redactedJSON, `"reason":"owner retry"`) {
		t.Fatalf("message release event reason = %s", redactedJSON)
	}
	receiveAfterRelease := requestDaemon(t, paths, map[string]any{
		"id": "req_msgownerreceiveafterrelease",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receiveAfterRelease.OK {
		t.Fatalf("receive after owner release failed: %+v", receiveAfterRelease.Error)
	}

	ackWithOpID := requestDaemon(t, paths, map[string]any{
		"id": "req_msgackop",
		"op": "messages.ack",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "op_id": "op_bcdefghijklmnopqrstu"},
	})
	if ackWithOpID.OK || ackWithOpID.Error == nil || ackWithOpID.Error.Code != "VALIDATION_ERROR" {
		t.Fatalf("ack op_id response = %+v", ackWithOpID)
	}

	ack := requestDaemon(t, paths, map[string]any{
		"id": "req_msgack",
		"op": "messages.ack",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !ack.OK {
		t.Fatalf("ack failed: %+v", ack.Error)
	}
	if state := ack.Result.(map[string]any)["state"]; state != "acked" {
		t.Fatalf("ack state = %v", state)
	}

	listAcked := requestDaemon(t, paths, map[string]any{
		"id": "req_msglistacked",
		"op": "messages.list",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "state": "acked"},
	})
	if !listAcked.OK {
		t.Fatalf("list acked failed: %+v", listAcked.Error)
	}
	if listed := listAcked.Result.(map[string]any)["messages"].([]any); len(listed) != 1 {
		t.Fatalf("listed acked messages = %#v", listed)
	}
	if next := listAcked.Result.(map[string]any)["next_cursor"]; next != nil {
		t.Fatalf("unexpected next cursor = %#v", next)
	}

	sent := requestDaemon(t, paths, map[string]any{
		"id": "req_msgsent",
		"op": "messages.sent",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "sender"},
	})
	if !sent.OK {
		t.Fatalf("sent failed: %+v", sent.Error)
	}
	if sentMessages := sent.Result.(map[string]any)["messages"].([]any); len(sentMessages) != 1 {
		t.Fatalf("sent messages = %#v", sentMessages)
	} else {
		sentDelivery := sentMessages[0].(map[string]any)["delivery"].(map[string]any)
		if sentDelivery["state"] != "sent" || sentDelivery["claim_holder"] != nil || sentDelivery["session_id"] != nil || sentDelivery["session_generation"] != nil || sentDelivery["read_at"] != nil || sentDelivery["lease_expires_at"] != nil {
			t.Fatalf("sent delivery leaked recipient state = %#v", sentDelivery)
		}
	}
}

func TestDaemonActivityCompleteAcksLocalMessage(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	send := requestDaemon(t, paths, map[string]any{
		"id": "req_activitylocalsend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "Local work can be completed without a visible reply."},
		},
	})
	if !send.OK {
		t.Fatalf("send failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)

	ownerAuth := map[string]any{
		"mode":       "owner",
		"profile":    "max.reviewer",
		"capability": capability,
	}
	receive := requestDaemon(t, paths, map[string]any{
		"id":     "req_activitylocalreceive",
		"op":     "messages.receive",
		"auth":   ownerAuth,
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("receive failed: %+v", receive.Error)
	}
	received := receive.Result.(map[string]any)["message"].(map[string]any)
	if received["source"] != "local" {
		t.Fatalf("received source = %v, want local", received["source"])
	}

	completeWithOpID := requestDaemon(t, paths, map[string]any{
		"id":   "req_activitylocalcompleteop",
		"op":   "activity.complete",
		"auth": ownerAuth,
		"params": map[string]any{
			"message_id": messageID,
			"profile":    "max.reviewer",
			"op_id":      "op_activitylocalabcdef",
		},
	})
	if completeWithOpID.OK || completeWithOpID.Error == nil || completeWithOpID.Error.Code != "VALIDATION_ERROR" {
		t.Fatalf("local activity complete op_id response = %+v", completeWithOpID)
	}

	complete := requestDaemon(t, paths, map[string]any{
		"id":     "req_activitylocalcomplete",
		"op":     "activity.complete",
		"auth":   ownerAuth,
		"params": map[string]any{"message_id": messageID, "profile": "max.reviewer"},
	})
	if !complete.OK {
		t.Fatalf("activity complete failed: %+v", complete.Error)
	}
	if result := complete.Result.(map[string]any); result["message_id"] != messageID || result["state"] != "acked" {
		t.Fatalf("activity complete result = %#v", result)
	}
	replay := requestDaemon(t, paths, map[string]any{
		"id":     "req_activitylocalreplay",
		"op":     "activity.complete",
		"auth":   ownerAuth,
		"params": map[string]any{"message_id": messageID, "profile": "max.reviewer"},
	})
	if !replay.OK || replay.Result.(map[string]any)["state"] != "acked" {
		t.Fatalf("activity complete replay = %+v", replay)
	}
	if redactedJSON := latestMessageEventJSON(t, daemon, messageID, "message.acked"); strings.Contains(redactedJSON, `"source":"comment.io"`) {
		t.Fatalf("local activity complete wrote cloud event source: %s", redactedJSON)
	}
}

func TestDaemonIngestsCloudNotificationOnWait(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimID := "clm_cloudclaim1234567890"
	notificationID := "ntf_cloudnotification1234567890"
	accessToken := "doc_private_access_token"
	commentID := "cmt_cloudcomment"
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:          notificationID,
			Type:        "mention",
			DocSlug:     "abc123",
			DocTitle:    "Design Review",
			CommentID:   &commentID,
			FromHandle:  "max.sender",
			FromName:    "Max",
			Context:     "Please review the latest section.",
			CreatedAt:   claimedAt,
			AccessToken: accessToken,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               tmux,
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("cloud wait failed: %+v", wait.Error)
	}
	if client.calls != 1 {
		t.Fatalf("notification wait calls = %d", client.calls)
	}
	if len(client.contextDeadlines) != 1 || !client.contextDeadlines[0] {
		t.Fatalf("zero-timeout cloud lease deadline = %#v", client.contextDeadlines)
	}
	waitResult := wait.Result.(map[string]any)
	messageID := waitResult["message_id"].(string)
	if !LocalMessageIDRE.MatchString(messageID) || waitResult["kind"] != "doc.mention" || waitResult["source"] != "comment.io" {
		t.Fatalf("cloud wait result = %#v", waitResult)
	}
	if _, ok := waitResult["lease_expires_at"]; ok {
		t.Fatalf("cloud wait exposed private lease expiry: %#v", waitResult)
	}
	if encoded := mustJSON(t, wait); strings.Contains(encoded, claimID) || strings.Contains(encoded, notificationID) || strings.Contains(encoded, accessToken) || containsSecretValue(encoded) {
		t.Fatalf("cloud wait leaked private metadata: %s", encoded)
	}

	secondWait := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudwait2",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !secondWait.OK {
		t.Fatalf("second cloud wait failed: %+v", secondWait.Error)
	}
	secondWaitResult := secondWait.Result.(map[string]any)
	if secondWaitResult["message_id"] != messageID {
		t.Fatalf("deduped cloud wait message id = %v, want %s", secondWaitResult["message_id"], messageID)
	}
	if client.calls != 1 {
		t.Fatalf("notification wait calls after queued duplicate = %d", client.calls)
	}

	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudreceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("cloud receive failed: %+v", receive.Error)
	}
	received := receive.Result.(map[string]any)["message"].(map[string]any)
	if received["source"] != "comment.io" || received["kind"] != "doc.mention" || received["from"] != "@max.sender" {
		t.Fatalf("received cloud message = %#v", received)
	}
	body := received["body"].(map[string]any)
	if body["content"] != "Please review the latest section." {
		t.Fatalf("cloud body = %#v", body)
	}
	refs := received["refs"].(map[string]any)
	if refs["doc_slug"] != "abc123" || refs["comment_id"] != commentID || refs["notification_type"] != "mention" {
		t.Fatalf("cloud refs = %#v", refs)
	}
	if encoded := mustJSON(t, receive); strings.Contains(encoded, claimID) || strings.Contains(encoded, notificationID) || strings.Contains(encoded, accessToken) {
		t.Fatalf("cloud receive leaked private metadata: %s", encoded)
	}
	senderSent := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudsent",
		"op": "messages.sent",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "sender"},
	})
	if !senderSent.OK {
		t.Fatalf("cloud sender sent failed: %+v", senderSent.Error)
	}
	if sent := senderSent.Result.(map[string]any)["messages"].([]any); len(sent) != 0 {
		t.Fatalf("cloud notification appeared in local sent history: %#v", sent)
	}
	renewOpID := "op_cloudrenewabcdefghijkl"
	renewedExpiry := testCloudLeaseExpiresIn(20 * time.Minute)
	client.renewLeases = append(client.renewLeases, &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: renewedExpiry,
		Notification:   lease.Notification,
	})
	renew := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudrenew",
		"op": "messages.renew",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "lease_ttl_ms": 60_000, "op_id": renewOpID},
	})
	if !renew.OK {
		t.Fatalf("cloud renew failed: %+v", renew.Error)
	}
	renewedDelivery := renew.Result.(map[string]any)["delivery"].(map[string]any)
	if renewedDelivery["lease_expires_at"] != renewedExpiry {
		t.Fatalf("cloud renewed delivery = %#v, want expiry %s", renewedDelivery, renewedExpiry)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, renewOpID); err != nil || ok {
		t.Fatalf("pending renew op after success = %+v %v %v", pending, ok, err)
	}
	if done, ok, err := ReadDoneCloudNotificationClaimOperation(paths, renewOpID); err != nil || !ok || done.Operation != "renew" || done.LocalMessageID != messageID {
		t.Fatalf("done renew op = %+v %v %v", done, ok, err)
	}
	metadataAfterRenew, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if metadataAfterRenew.LeaseExpiresAt != renewedExpiry {
		t.Fatalf("renewed private metadata = %+v, want expiry %s", metadataAfterRenew, renewedExpiry)
	}
	renewReplay := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudrenewreplay",
		"op": "messages.renew",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "lease_ttl_ms": 60_000, "op_id": renewOpID},
	})
	if !renewReplay.OK || renewReplay.Result.(map[string]any)["lease_expires_at"] != renewedExpiry {
		t.Fatalf("cloud renew replay response = %+v", renewReplay)
	}

	client.mu.Lock()
	mutations := append([]notificationMutationCall{}, client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 1 || mutations[0].Operation != "renew" || mutations[0].ClaimID != claimID || mutations[0].OpID != renewOpID {
		t.Fatalf("cloud mutations = %+v", mutations)
	}
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if metadata.ClaimID != claimID || metadata.NotificationID != notificationID || metadata.AccessToken != accessToken || metadata.LocalMessageID != messageID || metadata.LeaseExpiresAt != renewedExpiry {
		t.Fatalf("private cloud metadata = %+v", metadata)
	}
	indexedID, ok, err := FindPrivateCloudMessageByNotificationID(paths, "max.reviewer", notificationID)
	if err != nil {
		t.Fatal(err)
	}
	if !ok || indexedID != messageID {
		t.Fatalf("notification index = %q %v", indexedID, ok)
	}

	freshClaimID := "clm_cloudclaimfresh1234567890"
	freshLease := *lease
	freshLease.ClaimID = freshClaimID
	freshLease.LeaseExpiresAt = testCloudLeaseExpiresIn(15 * time.Minute)
	client.enqueue(&freshLease)
	claimedDuplicateWait := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudwait3",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !claimedDuplicateWait.OK || claimedDuplicateWait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("claimed duplicate cloud wait response = %+v", claimedDuplicateWait)
	}
	if client.calls != 2 {
		t.Fatalf("notification wait calls after claimed duplicate = %d", client.calls)
	}
	metadata, err = ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if metadata.ClaimID != claimID || metadata.LeaseExpiresAt != renewedExpiry || metadata.LocalMessageID != messageID {
		t.Fatalf("refreshed private cloud metadata = %+v", metadata)
	}
	daemon.busMu.Lock()
	refreshedMessage, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if refreshedMessage.Delivery.State != "claimed" || stringValue(refreshedMessage.Delivery.LeaseExpiresAt) != renewedExpiry {
		t.Fatalf("active duplicate local delivery = %+v, want claimed with original lease %s", refreshedMessage.Delivery, renewedExpiry)
	}
	if count := countMessagesBySource(t, daemon, "max.reviewer", "comment.io"); count != 1 {
		t.Fatalf("cloud message count after duplicate = %d, want 1", count)
	}
}

func TestDaemonCloudReceiveSkipsTerminalReplay(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_replayskipclaim1234567890",
		NotificationID: "ntf_replayskipnotification123",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_replayskipnotification123",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "This replay was already answered.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{
		leases: []*CloudNotificationLease{lease},
		handlingResults: []CloudNotificationHandlingResult{{
			OK:       true,
			Activity: map[string]any{"status": "start"},
		}, {
			OK:              true,
			Ignored:         true,
			TerminalOutcome: "responded",
		}},
	}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	wait := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayskipwait",
		"op":     "messages.wait",
		"auth":   map[string]any{"mode": "owner", "capability": capability},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("cloud wait failed: %+v", wait.Error)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayskipreceive",
		"op":     "messages.receive",
		"auth":   map[string]any{"mode": "owner", "profile": "max.reviewer", "capability": capability},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("terminal replay receive failed: %+v", receive.Error)
	}
	result := receive.Result.(map[string]any)
	if result["replay_skipped"] != true || result["skip_outcome"] != "responded" {
		t.Fatalf("terminal replay result = %#v", result)
	}
	if result["message"] != nil || result["replay_protection"] != nil {
		t.Fatalf("terminal replay exposed work payload: %#v", result)
	}
	if result["message_id"] != messageID {
		t.Fatalf("terminal replay message_id = %#v, want %s", result["message_id"], messageID)
	}
	daemon.busMu.Lock()
	stored, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if stored.Delivery.State != "acked" {
		t.Fatalf("terminal replay delivery = %+v, want acked", stored.Delivery)
	}
	client.mu.Lock()
	handling := append([]notificationHandlingCall(nil), client.handlingActivities...)
	mutations := append([]notificationMutationCall(nil), client.mutations...)
	client.mu.Unlock()
	if len(handling) != 2 ||
		handling[0].Action != "start" || handling[0].ClaimID != lease.ClaimID ||
		handling[1].Action != "start" || handling[1].ClaimID != lease.ClaimID {
		t.Fatalf("handling calls = %+v", handling)
	}
	if len(mutations) != 1 || mutations[0].Operation != "ack" || mutations[0].ClaimID != lease.ClaimID {
		t.Fatalf("terminal replay mutations = %+v", mutations)
	}
}

func TestDaemonCloudReceiveSettlesAlreadyAckedTerminalReplay(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_replayackedclaim123456",
		NotificationID: "ntf_replayackednotification12",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_replayackednotification12",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "This replay was remotely acked before local settlement.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{
		leases: []*CloudNotificationLease{lease},
		handlingErrs: []error{
			nil,
			&NotificationHTTPError{Status: http.StatusConflict, Code: "LEASE_ALREADY_ACKED"},
		},
	}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	wait := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayackedwait",
		"op":     "messages.wait",
		"auth":   map[string]any{"mode": "owner", "capability": capability},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("cloud wait failed: %+v", wait.Error)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayackedreceive",
		"op":     "messages.receive",
		"auth":   map[string]any{"mode": "owner", "profile": "max.reviewer", "capability": capability},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("already-acked replay receive failed: %+v", receive.Error)
	}
	result := receive.Result.(map[string]any)
	if result["replay_skipped"] != true || result["skip_outcome"] != "already_acked" {
		t.Fatalf("already-acked replay result = %#v", result)
	}
	if result["message"] != nil || result["replay_protection"] != nil {
		t.Fatalf("already-acked replay exposed work payload: %#v", result)
	}
	daemon.busMu.Lock()
	stored, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if stored.Delivery.State != "acked" {
		t.Fatalf("already-acked replay delivery = %+v, want acked", stored.Delivery)
	}
	client.mu.Lock()
	handling := append([]notificationHandlingCall(nil), client.handlingActivities...)
	mutations := append([]notificationMutationCall(nil), client.mutations...)
	client.mu.Unlock()
	if len(handling) != 2 ||
		handling[0].Action != "start" || handling[0].ClaimID != lease.ClaimID ||
		handling[1].Action != "start" || handling[1].ClaimID != lease.ClaimID {
		t.Fatalf("handling calls = %+v", handling)
	}
	if len(mutations) != 1 || mutations[0].Operation != "ack" || mutations[0].ClaimID != lease.ClaimID {
		t.Fatalf("already-acked replay mutations = %+v", mutations)
	}
}

func TestDaemonCloudReceiveDoesNotSkipFailedTerminalReplay(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_replayfailedclaim123456",
		NotificationID: "ntf_replayfailednotification12",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_replayfailednotification12",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "This replay should retry after a failure.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{
		leases: []*CloudNotificationLease{lease},
		handlingResults: []CloudNotificationHandlingResult{{
			OK:       true,
			Activity: map[string]any{"status": "start"},
		}, {
			OK:              true,
			Ignored:         true,
			TerminalOutcome: "failed",
		}},
	}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	wait := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayfailedwait",
		"op":     "messages.wait",
		"auth":   map[string]any{"mode": "owner", "capability": capability},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("cloud wait failed: %+v", wait.Error)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id":     "req_replayfailedreceive",
		"op":     "messages.receive",
		"auth":   map[string]any{"mode": "owner", "profile": "max.reviewer", "capability": capability},
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("failed replay receive failed: %+v", receive.Error)
	}
	result := receive.Result.(map[string]any)
	if _, skipped := result["replay_skipped"]; skipped {
		t.Fatalf("failed terminal replay was skipped: %#v", result)
	}
	daemon.busMu.Lock()
	stored, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if stored.Delivery.State != "claimed" {
		t.Fatalf("failed terminal replay delivery = %+v, want claimed", stored.Delivery)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall(nil), client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 0 {
		t.Fatalf("failed terminal replay mutations = %+v", mutations)
	}
}

func TestDaemonBotScopedCloudWaitUsesSelectedBot(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimID := "clm_cloudbotclaim1234567890"
	notificationID := "ntf_cloudbotnotification1234567890"
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:          notificationID,
			Type:        "mention",
			DocSlug:     "abc123",
			DocTitle:    "Design Review",
			FromHandle:  "max.sender",
			FromName:    "Max",
			Context:     "Bot-scoped cloud wait.",
			CreatedAt:   claimedAt,
			AccessToken: "doc_private_access_token",
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               tmux,
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	addSameProfileAnalystBot(t, daemon)
	if _, err := daemon.store.InsertLocalMessages(context.Background(), LocalMessageSend{
		SenderProfile: "max.sender",
		SenderBotName: "sender",
		Recipients: []LocalMessageRecipient{
			{Profile: "max.reviewer", BotName: "analyst"},
		},
		Body: MessageBody{Format: "markdown", Content: "analyst work should not block reviewer cloud wait"},
		Now:  time.Now().UTC(),
	}); err != nil {
		t.Fatal(err)
	}

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudbotwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK {
		t.Fatalf("bot-scoped cloud wait failed: %+v", wait.Error)
	}
	if client.calls != 1 {
		t.Fatalf("notification wait calls = %d, want 1", client.calls)
	}
	result := wait.Result.(map[string]any)
	messageID := result["message_id"].(string)
	if result["bot_name"] != "reviewer" || result["source"] != "comment.io" {
		t.Fatalf("bot-scoped cloud wait result = %#v", result)
	}
	daemon.busMu.Lock()
	message, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if message.BotName != "reviewer" {
		t.Fatalf("cloud message bot = %s, want reviewer", message.BotName)
	}
	tmux.mu.Lock()
	starts := append([]TmuxNewSessionOptions(nil), tmux.starts...)
	sends := append([]string(nil), tmux.sends...)
	tmux.mu.Unlock()
	if len(starts) != 1 || !strings.Contains(starts[0].SessionName, "comment-reviewer-") {
		t.Fatalf("bot-scoped cloud wait starts = %+v", starts)
	}
	if len(sends) != 4 || !strings.Contains(sends[0], "handle max.reviewer") || !strings.Contains(sends[0], "https://comment.io/llms.txt") {
		t.Fatalf("bot-scoped cloud wait sends = %+v, want startup instruction plus one literal nudge", sends)
	}
}

func TestDaemonBotScopedCloudWaitRejectsWrongBotDuplicate(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimID := "clm_clouddupbotclaim1234567890"
	notificationID := "ntf_clouddupbotnotification1234567890"
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:          notificationID,
			Type:        "mention",
			DocSlug:     "abc123",
			DocTitle:    "Design Review",
			FromHandle:  "max.sender",
			FromName:    "Max",
			Context:     "Duplicate wrong-bot cloud wait.",
			CreatedAt:   claimedAt,
			AccessToken: "doc_private_access_token",
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               tmux,
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	addSameProfileAnalystBot(t, daemon)
	existingID := seedCloudMessageForBot(t, paths, daemon.store, *lease, "analyst")

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_clouddupbotwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK || wait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("wrong-bot duplicate wait response = %+v", wait)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall(nil), client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 1 || mutations[0].Operation != "release" || mutations[0].ClaimID != claimID {
		t.Fatalf("wrong-bot duplicate mutations = %+v", mutations)
	}
	daemon.busMu.Lock()
	existing, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", existingID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if existing.BotName != "analyst" {
		t.Fatalf("wrong-bot duplicate message bot = %s", existing.BotName)
	}
	if count := countMessagesBySource(t, daemon, "max.reviewer", "comment.io"); count != 1 {
		t.Fatalf("cloud message count after wrong-bot duplicate = %d, want 1", count)
	}
	tmux.mu.Lock()
	starts := append([]TmuxNewSessionOptions(nil), tmux.starts...)
	sends := append([]string(nil), tmux.sends...)
	tmux.mu.Unlock()
	if len(starts) != 0 || len(sends) != 0 {
		t.Fatalf("wrong-bot duplicate dispatched tmux: starts=%+v sends=%+v", starts, sends)
	}
}

