func TestDaemonDuplicateCloudNotificationAbandonsPendingRenewBeforeAckReplay(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_dupackrenewold12345",
		NotificationID: "ntf_dupackrenewold12345",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_dupackrenewold12345",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Pending renew should be cleared before duplicate ack replay returns.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	claimHolder := stringValue(message.Delivery.ClaimHolder)
	renewOpID, err := GenerateLocalID("op", 0)
	if err != nil {
		t.Fatal(err)
	}
	renewOp, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "renew", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, claimHolder, renewOpID, time.Minute, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin pending renew op = %+v done=%v err=%v", renewOp, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, renewOp, time.Now().UTC()); err != nil {
		t.Fatal(err)
	}

	ackOpID, err := GenerateLocalID("op", 0)
	if err != nil {
		t.Fatal(err)
	}
	client.mu.Lock()
	client.mutationErrs = append(client.mutationErrs, errNotificationMutationAmbiguous)
	client.mu.Unlock()
	ack := requestDaemon(t, paths, map[string]any{
		"id": "req_dupackrenewack",
		"op": "messages.ack",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID, "op_id": ackOpID},
	})
	if ack.OK || ack.Error == nil || ack.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("ambiguous ack with pending renew = %+v", ack)
	}

	freshLease := *lease
	freshLease.ClaimID = "clm_dupackrenewfresh123"
	freshLease.LeaseExpiresAt = testCloudLeaseExpiresIn(15 * time.Minute)
	client.enqueue(&freshLease)
	duplicateWait := requestDaemon(t, paths, map[string]any{
		"id": "req_dupackrenewwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !duplicateWait.OK || duplicateWait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("duplicate wait after pending renew and ack = %+v", duplicateWait)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "acked")
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", freshLease.ClaimID, 1)
	assertNotificationMutationCount(t, client, "renew", lease.ClaimID, 0)
	if pendingRenew, ok, err := ReadPendingCloudNotificationClaimOperation(paths, renewOpID); err != nil || ok {
		t.Fatalf("pending renew after duplicate ack replay = %+v ok=%v err=%v", pendingRenew, ok, err)
	}
	if pendingAck, ok, err := ReadPendingCloudNotificationClaimOperation(paths, ackOpID); err != nil || ok {
		t.Fatalf("pending ack after duplicate ack replay = %+v ok=%v err=%v", pendingAck, ok, err)
	}
}

func TestDaemonDuplicateCloudNotificationRetriesSessionPendingAckInline(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_sessiondupackold123",
		NotificationID: "ntf_sessiondupackold123",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_sessiondupackold123",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Session pending ack should close before duplicate release.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_sessiondupackstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionCapability, err := ReadCapability(session["capability_file"].(string))
	if err != nil {
		t.Fatal(err)
	}
	sessionAuth := map[string]any{
		"mode":               "session",
		"profile":            "max.reviewer",
		"session_id":         session["session_id"],
		"session_generation": session["generation"],
		"capability":         sessionCapability,
	}
	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_sessiondupackwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK || wait.Result.(map[string]any)["timeout"] == true {
		t.Fatalf("cloud wait failed: %+v", wait)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	receive := requestDaemon(t, paths, map[string]any{
		"id":     "req_sessiondupackreceive",
		"op":     "messages.receive",
		"auth":   sessionAuth,
		"params": map[string]any{"message_id": messageID},
	})
	if !receive.OK {
		t.Fatalf("session receive failed: %+v", receive.Error)
	}

	opID, err := GenerateLocalID("op", 0)
	if err != nil {
		t.Fatal(err)
	}
	client.mu.Lock()
	client.mutationErrs = append(client.mutationErrs, errNotificationMutationAmbiguous)
	client.mu.Unlock()
	ack := requestDaemon(t, paths, map[string]any{
		"id":     "req_sessiondupackack",
		"op":     "messages.ack",
		"auth":   sessionAuth,
		"params": map[string]any{"message_id": messageID, "op_id": opID},
	})
	if ack.OK || ack.Error == nil || ack.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("ambiguous session ack = %+v error=%+v", ack, ack.Error)
	}
	pending, ok, err := findPendingCloudNotificationClaimOperation(paths, "ack", "max.reviewer", messageID, lease.ClaimID, lease.NotificationID, 0, "")
	if err != nil || !ok || pending.OpID != opID || pending.Attempts != 1 {
		t.Fatalf("pending session ack = %+v ok=%v err=%v", pending, ok, err)
	}
	if pending.ClaimHolder != "session:"+session["session_id"].(string)+":"+session["generation"].(string) {
		t.Fatalf("pending session ack holder = %q", pending.ClaimHolder)
	}
	daemon.busMu.Lock()
	claimedMessage, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if claimedMessage.Delivery.SessionID == nil {
		t.Fatalf("session pending ack lost session delivery ref: %+v", claimedMessage.Delivery)
	}

	freshLease := *lease
	freshLease.ClaimID = "clm_sessiondupfresh123"
	freshLease.LeaseExpiresAt = testCloudLeaseExpiresIn(15 * time.Minute)
	client.enqueue(&freshLease)
	duplicateWait := requestDaemon(t, paths, map[string]any{
		"id": "req_sessiondupackdupwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !duplicateWait.OK || duplicateWait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("duplicate wait after session pending ack = %+v", duplicateWait)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "acked")
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", freshLease.ClaimID, 1)
	assertNotificationMutationCount(t, client, "release", freshLease.ClaimID, 0)
	if pendingAfter, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID); err != nil || ok {
		t.Fatalf("pending session ack after duplicate replay = %+v ok=%v err=%v", pendingAfter, ok, err)
	}
	done, ok, err := ReadDoneCloudNotificationClaimOperation(paths, opID)
	if err != nil || !ok || done.Attempts != 2 {
		t.Fatalf("done session ack after duplicate replay = %+v ok=%v err=%v", done, ok, err)
	}
}

func TestDaemonDuplicateCloudNotificationClosesFreshLeaseWhenPendingAckAlreadyLocal(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_pendingdupacklocalold",
		NotificationID: "ntf_pendingdupacklocalold",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_pendingdupacklocalold",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Pending ack already landed locally before duplicate lease.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	claimHolder := stringValue(message.Delivery.ClaimHolder)
	opID := "op_pendingdupacklocal12"
	op, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, claimHolder, opID, 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin pending local ack op = %+v done=%v err=%v", op, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, op, time.Now().UTC()); err != nil {
		t.Fatal(err)
	}
	daemon.busMu.Lock()
	_, err = daemon.store.AckCloudMessage(context.Background(), "max.reviewer", messageID, claimHolder, time.Now().UTC())
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}

	freshLease := *lease
	freshLease.ClaimID = "clm_pendingdupacklocalnew"
	freshLease.LeaseExpiresAt = testCloudLeaseExpiresIn(15 * time.Minute)
	client.enqueue(&freshLease)
	duplicateWait := requestDaemon(t, paths, map[string]any{
		"id": "req_pendingdupacklocalwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !duplicateWait.OK || duplicateWait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("duplicate wait after locally completed pending ack = %+v", duplicateWait)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "acked")
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 0)
	assertNotificationMutationCount(t, client, "ack", freshLease.ClaimID, 1)
	assertNotificationMutationCount(t, client, "release", freshLease.ClaimID, 0)
	if pendingAfter, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID); err != nil || ok {
		t.Fatalf("pending local ack after duplicate replay = %+v ok=%v err=%v", pendingAfter, ok, err)
	}
	doneOp, ok, err := ReadDoneCloudNotificationClaimOperation(paths, opID)
	if err != nil || !ok || doneOp.Attempts != 2 {
		t.Fatalf("done local ack after duplicate replay = %+v ok=%v err=%v", doneOp, ok, err)
	}
}

func TestDaemonRepairPendingDuplicateAckWithRetargetedClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_repairdupackold12345",
		NotificationID: "ntf_repairdupackold12345",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_repairdupackold12345",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Repair should recover duplicate ack journal.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	claimHolder := stringValue(message.Delivery.ClaimHolder)
	oldOpID, err := GenerateLocalID("op", 0)
	if err != nil {
		t.Fatal(err)
	}
	oldOp, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, claimHolder, oldOpID, 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin old pending ack op = %+v done=%v err=%v", oldOp, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, oldOp, time.Now().UTC()); err != nil {
		t.Fatal(err)
	}
	freshClaimID := "clm_repairdupackfresh123"
	duplicateOp, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, freshClaimID, metadata.NotificationID, claimHolder, "", 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin duplicate pending ack op = %+v done=%v err=%v", duplicateOp, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, duplicateOp, time.Now().UTC()); err != nil {
		t.Fatal(err)
	}
	client.mu.Lock()
	client.recordClaimNotificationLocked(freshClaimID, metadata.NotificationID)
	client.mu.Unlock()

	repairDuplicate := requestDaemon(t, paths, map[string]any{
		"id": "req_repairdupackfresh",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false, "op_id": duplicateOp.OpID},
	})
	if !repairDuplicate.OK {
		t.Fatalf("duplicate ack repair failed: %+v", repairDuplicate.Error)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "acked")
	assertNotificationMutationCount(t, client, "ack", freshClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 0)
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, duplicateOp.OpID); err != nil || ok {
		t.Fatalf("duplicate pending ack after repair = %+v ok=%v err=%v", pending, ok, err)
	}
	if doneOp, ok, err := ReadDoneCloudNotificationClaimOperation(paths, duplicateOp.OpID); err != nil || !ok || doneOp.ClaimID != freshClaimID {
		t.Fatalf("duplicate done ack after repair = %+v ok=%v err=%v", doneOp, ok, err)
	}

	repairOld := requestDaemon(t, paths, map[string]any{
		"id": "req_repairdupackold",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false, "op_id": oldOpID},
	})
	if !repairOld.OK {
		t.Fatalf("old ack repair failed: %+v", repairOld.Error)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, oldOpID); err != nil || ok {
		t.Fatalf("old pending ack after repair = %+v ok=%v err=%v", pending, ok, err)
	}
	if doneOp, ok, err := ReadDoneCloudNotificationClaimOperation(paths, oldOpID); err != nil || !ok || doneOp.ClaimID != lease.ClaimID {
		t.Fatalf("old done ack after repair = %+v ok=%v err=%v", doneOp, ok, err)
	}
	assertNotificationMutationCount(t, client, "ack", freshClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 0)
}

func TestDaemonRepairPendingDuplicateAckPrioritizesFreshClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_repairduporderold123",
		NotificationID: "ntf_repairduporder12345",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_repairduporder12345",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Fresh duplicate ack should replay before the stale ack.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	claimHolder := stringValue(message.Delivery.ClaimHolder)
	now := time.Now().UTC()
	oldOpID := "op_aaaaaaaaaaaaaaaaaaaa"
	oldOp, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, claimHolder, oldOpID, 0, now.Add(-2*time.Minute))
	if err != nil || done {
		t.Fatalf("begin old pending ack op = %+v done=%v err=%v", oldOp, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, oldOp, now.Add(-2*time.Minute)); err != nil {
		t.Fatal(err)
	}
	freshClaimID := "clm_repairduporderfresh"
	metadata.ClaimID = freshClaimID
	metadata.LeaseExpiresAt = testCloudLeaseExpiresIn(15 * time.Minute)
	if err := WritePrivateCloudMessageMetadata(paths, metadata); err != nil {
		t.Fatal(err)
	}
	freshOpID := "op_zzzzzzzzzzzzzzzzzzzz"
	freshOp, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, freshClaimID, metadata.NotificationID, claimHolder, freshOpID, 0, now.Add(-time.Minute))
	if err != nil || done {
		t.Fatalf("begin fresh pending ack op = %+v done=%v err=%v", freshOp, done, err)
	}
	if _, err := RecordCloudNotificationClaimOperationAttempt(paths, freshOp, now.Add(-time.Minute)); err != nil {
		t.Fatal(err)
	}
	client.mu.Lock()
	client.recordClaimNotificationLocked(freshClaimID, metadata.NotificationID)
	client.mu.Unlock()

	repair := requestDaemon(t, paths, map[string]any{
		"id": "req_repairduporder",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false},
	})
	if !repair.OK {
		t.Fatalf("duplicate ack repair failed: %+v", repair.Error)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "acked")
	assertNotificationMutationCount(t, client, "ack", freshClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 0)
	if pendingOld, ok, err := ReadPendingCloudNotificationClaimOperation(paths, oldOpID); err != nil || !ok {
		t.Fatalf("old pending ack should wait for second repair pass = %+v ok=%v err=%v", pendingOld, ok, err)
	}
	if pendingFresh, ok, err := ReadPendingCloudNotificationClaimOperation(paths, freshOpID); err != nil || ok {
		t.Fatalf("fresh pending ack after repair = %+v ok=%v err=%v", pendingFresh, ok, err)
	}

	repairOld := requestDaemon(t, paths, map[string]any{
		"id": "req_repairduporderold",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false, "op_id": oldOpID},
	})
	if !repairOld.OK {
		t.Fatalf("old duplicate ack repair failed: %+v", repairOld.Error)
	}
	if pendingOld, ok, err := ReadPendingCloudNotificationClaimOperation(paths, oldOpID); err != nil || ok {
		t.Fatalf("old pending ack after local completion repair = %+v ok=%v err=%v", pendingOld, ok, err)
	}
	assertNotificationMutationCount(t, client, "ack", freshClaimID, 1)
	assertNotificationMutationCount(t, client, "ack", lease.ClaimID, 0)
}

