func TestDaemonRepairRejectsHolderMismatchedPendingCloudMutation(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_holdermismatch1234567890",
		NotificationID: "ntf_holdermismatch1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_holdermismatch1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Holder mismatch repair should not replay.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	opID := "op_holdermismatchabcdef"
	wrongHolder := "session:sess_holdermismatch1234567890:gen_holdermismatch1234"
	op, done, err := BeginCloudNotificationClaimOperationForHolder(paths, "ack", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, wrongHolder, opID, 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin holder-mismatched terminal op = %+v done=%v err=%v", op, done, err)
	}
	dryRun := requestDaemon(t, paths, map[string]any{
		"id": "req_holdermismatchdryrun",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": true, "op_id": opID},
	})
	if !dryRun.OK {
		t.Fatalf("holder-mismatched dry-run failed: %+v", dryRun.Error)
	}
	dryRunActions := dryRun.Result.(map[string]any)["actions"].([]any)
	if len(dryRunActions) != 1 || dryRunActions[0].(map[string]any)["action"] != "replay_op" || dryRunActions[0].(map[string]any)["reason"] != "local delivery claim holder does not match pending operation" {
		t.Fatalf("holder-mismatched dry-run actions = %#v", dryRunActions)
	}
	repair := requestDaemon(t, paths, map[string]any{
		"id": "req_holdermismatchrepair",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false, "op_id": opID},
	})
	if !repair.OK {
		t.Fatalf("holder-mismatched repair failed: %+v", repair.Error)
	}
	actions := repair.Result.(map[string]any)["actions"].([]any)
	if len(actions) != 1 || actions[0].(map[string]any)["action"] != "replay_op" || actions[0].(map[string]any)["reason"] != "local delivery claim holder does not match pending operation" {
		t.Fatalf("holder-mismatched repair actions = %#v", actions)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID); err != nil || !ok || pending.ClaimHolder != wrongHolder {
		t.Fatalf("holder-mismatched pending op = %+v ok=%v err=%v", pending, ok, err)
	}
	daemon.busMu.Lock()
	message, storeErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if storeErr != nil {
		t.Fatal(storeErr)
	}
	if message.Delivery.State != "claimed" || stringValue(message.Delivery.ClaimHolder) != "owner:max.reviewer" {
		t.Fatalf("holder-mismatched repair delivery = %+v", message.Delivery)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall{}, client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 0 {
		t.Fatalf("holder-mismatched repair called cloud mutations: %+v", mutations)
	}
}

func TestDaemonRepairCreatesHolderBoundCloudReleaseOperation(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := CloudNotificationLease{
		ClaimID:        "clm_repairholderrelease12345",
		NotificationID: "ntf_repairholderrelease12345",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_repairholderrelease12345",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Repair-created release ops should keep the current holder.",
			CreatedAt:  claimedAt,
		},
	}
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	messageID := seedClaimedCloudMessage(t, paths, daemon.store, lease)

	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(ctx, "max.reviewer", messageID)
	if err != nil {
		daemon.busMu.Unlock()
		t.Fatal(err)
	}
	claimHolder := stringValue(message.Delivery.ClaimHolder)
	action, err := daemon.releaseAbandonedCloudClaimLocked(ctx, message, "lease_expired", time.Now().UTC())
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if action.Action != "replay_op" || action.MessageID != messageID || action.Reason != "notification client is not configured" {
		t.Fatalf("release action = %+v", action)
	}
	ops, err := ListPendingCloudNotificationClaimOperations(paths)
	if err != nil {
		t.Fatal(err)
	}
	if len(ops) != 1 {
		t.Fatalf("pending ops = %+v", ops)
	}
	op := ops[0]
	if op.Operation != "release" || op.LocalMessageID != messageID || op.ReleaseReason != "lease_expired" {
		t.Fatalf("pending release op = %+v", op)
	}
	if op.ClaimHolder != claimHolder || op.ClaimHolder == "" {
		t.Fatalf("pending release holder = %q, want %q", op.ClaimHolder, claimHolder)
	}
}

