func TestDaemonSocketResponseWriteSanitizesInvalidRawRequest(t *testing.T) {
	var logs bytes.Buffer
	daemon := &Daemon{
		logger: &structuredLogger{writer: &logs, now: time.Now},
	}
	raw := []byte(`{"id":"req_invalidwriteraw","op":"cloud.clm_writerawsecret123456","auth":{"mode":"owner","capability":"cap_writerawsecret123456"},"params":{"op_id":"clm_writerawsecret123456","message_id":"msg_writerawsecret123456"}}`)
	daemon.logSocketResponseWrite(
		raw,
		SocketResponse{ID: "req_invalidwriteraw", OK: false, Error: socketError("VALIDATION_ERROR", "invalid operation", false)},
		slowSocketRequestDuration+time.Millisecond,
		errors.New("i/o timeout"),
	)

	text := logs.String()
	if strings.Contains(text, "cloud.clm_writerawsecret123456") ||
		strings.Contains(text, "cap_writerawsecret123456") ||
		strings.Contains(text, "clm_writerawsecret123456") ||
		strings.Contains(text, "msg_writerawsecret123456") {
		t.Fatalf("invalid raw write log leaked request content: %s", text)
	}
	entries := structuredLogEntries(t, &logs)
	entry := requireStructuredLog(t, entries, "socket.response.write")
	if entry.Data["request_id"] != "req_invalidwriteraw" ||
		entry.Data["op"] != "invalid" ||
		entry.Data["error_kind"] != "write_failed" {
		t.Fatalf("invalid raw write log data = %#v", entry.Data)
	}
}

