func TestDaemonStartupRemoteReleasesDeadSessionCloudClaim(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := CloudNotificationLease{
		ClaimID:        "clm_deadsessionrelease1234567890",
		NotificationID: "ntf_deadsessionrelease1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_deadsessionrelease1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Dead session cloud claim should not be locally requeued.",
			CreatedAt:  claimedAt,
		},
	}
	paths := testDaemonPaths(t)
	botletsHome := writeMessageTestBotFiles(t, paths)
	store, err := OpenStore(ctx, paths)
	if err != nil {
		t.Fatal(err)
	}
	messageID := seedClaimedCloudMessage(t, paths, store, lease)
	sessionID, err := GenerateLocalID("sess", 0)
	if err != nil {
		t.Fatal(err)
	}
	generation, err := GenerateLocalID("gen", 0)
	if err != nil {
		t.Fatal(err)
	}
	sessionName, err := tmuxSessionName("reviewer", sessionID)
	if err != nil {
		t.Fatal(err)
	}
	record, err := RegisterSession(RegisterSessionOptions{
		Paths:       paths,
		Profile:     "max.reviewer",
		BotName:     "reviewer",
		ScopeType:   "profile",
		ScopeID:     "max.reviewer",
		SessionID:   sessionID,
		Generation:  generation,
		BotletsHome: botletsHome,
		SessionName: sessionName,
		PaneTarget:  sessionName + ":0.0",
		Runtime:     "claude",
		State:       "dead",
		Now:         time.Now().UTC(),
	})
	if err != nil {
		t.Fatal(err)
	}
	if _, err := store.db.Exec(`UPDATE message_recipients
		SET claim_holder = ?, session_id = ?, session_scope_type = ?, session_scope_id = ?, session_generation = ?
		WHERE message_id = ? AND profile = ?`,
		"session:"+record.SessionID+":"+record.Generation,
		record.SessionID,
		record.ScopeType,
		record.ScopeID,
		record.Generation,
		messageID,
		"max.reviewer",
	); err != nil {
		t.Fatal(err)
	}
	if err := store.Close(); err != nil {
		t.Fatal(err)
	}
	client := &fakeNotificationClient{claimNotifications: map[string]string{lease.ClaimID: lease.NotificationID}}
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               tmux,
		BotletsHome:        botletsHome,
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	deadRecord, err := ReadSessionRecord(paths, record.SessionID)
	if err != nil {
		t.Fatal(err)
	}
	if deadRecord.State != "dead" {
		t.Fatalf("dead session was rewritten by repair: %+v", deadRecord)
	}
	daemon.busMu.Lock()
	message, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if message.Delivery.State != "released" || message.Delivery.LeaseExpiresAt != nil || message.Delivery.SessionID != nil {
		t.Fatalf("dead-session cloud release delivery = %+v", message.Delivery)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall{}, client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 1 || mutations[0].Operation != "release" || mutations[0].ClaimID != lease.ClaimID {
		t.Fatalf("dead-session cloud release mutations = %+v", mutations)
	}
	tmux.mu.Lock()
	starts := append([]TmuxNewSessionOptions(nil), tmux.starts...)
	tmux.mu.Unlock()
	if len(starts) != 0 {
		t.Fatalf("dead-session cloud release should not start tmux: %#v", starts)
	}
}

