func TestDaemonRepairRespectsOperationSelector(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	firstLease := &CloudNotificationLease{
		ClaimID:        "clm_repairselectone1234567890",
		NotificationID: "ntf_repairselectone1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_repairselectone1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Repair only this op.",
			CreatedAt:  claimedAt,
		},
	}
	secondLease := &CloudNotificationLease{
		ClaimID:        "clm_repairselecttwo1234567890",
		NotificationID: "ntf_repairselecttwo1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_repairselecttwo1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Do not repair this op.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{firstLease, secondLease}}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	firstMessageID := waitAndReceiveCloudMessage(t, paths, capability)
	secondMessageID := waitAndReceiveCloudMessage(t, paths, capability)
	firstMetadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", firstMessageID)
	if err != nil {
		t.Fatal(err)
	}
	secondMetadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", secondMessageID)
	if err != nil {
		t.Fatal(err)
	}
	firstOpID := "op_repairselectoneabcdef"
	firstOp, done, err := BeginCloudNotificationClaimOperation(paths, "ack", "max.reviewer", firstMessageID, firstMetadata.ClaimID, firstMetadata.NotificationID, firstOpID, 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin selected repair op = %+v done=%v err=%v", firstOp, done, err)
	}
	secondOpID := "op_repairselecttwoabcdef"
	secondOp, done, err := BeginCloudNotificationClaimOperation(paths, "ack", "max.reviewer", secondMessageID, secondMetadata.ClaimID, secondMetadata.NotificationID, secondOpID, 0, time.Now().UTC())
	if err != nil || done {
		t.Fatalf("begin unselected repair op = %+v done=%v err=%v", secondOp, done, err)
	}

	repair := requestDaemon(t, paths, map[string]any{
		"id": "req_repairselector",
		"op": "messages.repair",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"dry_run": false, "op_id": firstOpID},
	})
	if !repair.OK {
		t.Fatalf("targeted repair failed: %+v", repair.Error)
	}
	actions := repair.Result.(map[string]any)["actions"].([]any)
	if len(actions) != 1 || actions[0].(map[string]any)["op_id"] != firstOpID {
		t.Fatalf("targeted repair actions = %#v", actions)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, firstOpID); err != nil || ok {
		t.Fatalf("selected pending op after repair = %+v %v %v", pending, ok, err)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, secondOpID); err != nil || !ok || pending.LocalMessageID != secondMessageID {
		t.Fatalf("unselected pending op after repair = %+v %v %v", pending, ok, err)
	}
	daemon.busMu.Lock()
	firstMessage, firstErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", firstMessageID)
	secondMessage, secondErr := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", secondMessageID)
	daemon.busMu.Unlock()
	if firstErr != nil || secondErr != nil {
		t.Fatalf("messages after targeted repair err = %v %v", firstErr, secondErr)
	}
	if firstMessage.Delivery.State != "acked" || secondMessage.Delivery.State != "claimed" {
		t.Fatalf("targeted repair deliveries = %+v %+v", firstMessage.Delivery, secondMessage.Delivery)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall{}, client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 1 || mutations[0].OpID != firstOpID || mutations[0].ClaimID != firstLease.ClaimID {
		t.Fatalf("targeted repair mutations = %+v", mutations)
	}
}

func TestDaemonDoesNotReplayDefinitiveCloudMutationFailureAsSuccess(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_cloudnotfound1234567890",
		NotificationID: "ntf_cloudnotfound1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_cloudnotfound1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Ack will fail definitively.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{
		leases: []*CloudNotificationLease{lease},
		mutationErrs: []error{
			&NotificationHTTPError{Status: http.StatusNotFound},
			&NotificationHTTPError{Status: http.StatusNotFound},
		},
	}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	messageID := waitAndReceiveCloudMessage(t, paths, capability)
	opID := "op_cloudnotfoundabcdefghi"

	for i, requestID := range []string{"req_cloudnotfound1", "req_cloudnotfound2"} {
		response := requestDaemon(t, paths, map[string]any{
			"id": requestID,
			"op": "messages.ack",
			"auth": map[string]any{
				"mode":       "owner",
				"profile":    "max.reviewer",
				"capability": capability,
			},
			"params": map[string]any{"message_id": messageID, "op_id": opID},
		})
		if response.OK || response.Error == nil || response.Error.Code != "NOT_FOUND" || response.Error.Retryable {
			t.Fatalf("definitive cloud ack attempt %d response = %+v", i+1, response)
		}
		pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID)
		if err != nil || ok {
			t.Fatalf("pending definitive op after attempt %d = %+v %v %v", i+1, pending, ok, err)
		}
		if done, ok, err := ReadDoneCloudNotificationClaimOperation(paths, opID); err != nil || ok {
			t.Fatalf("done definitive op after attempt %d = %+v %v %v", i+1, done, ok, err)
		}
	}
	daemon.busMu.Lock()
	stillClaimed, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if stillClaimed.Delivery.State != "claimed" {
		t.Fatalf("definitive failure local delivery = %+v", stillClaimed.Delivery)
	}
	client.mu.Lock()
	mutations := append([]notificationMutationCall{}, client.mutations...)
	client.mu.Unlock()
	if len(mutations) != 2 || mutations[0].OpID != opID || mutations[1].OpID != opID {
		t.Fatalf("definitive mutation calls = %+v", mutations)
	}
}

func TestCompleteCloudNotificationClaimOperationKeepsPendingWhenDoneWriteFails(t *testing.T) {
	paths := testDaemonPaths(t)
	if err := EnsureBaseDirs(paths); err != nil {
		t.Fatal(err)
	}
	opID := "op_donewritefailureabcdef"
	messageID := "msg_donewritefailureabcdef"
	op, done, err := BeginCloudNotificationClaimOperation(paths, "ack", "max.reviewer", messageID, "clm_donewritefailureabcdef", "ntf_donewritefailureabcdef", opID, 0, time.Now().UTC())
	if err != nil {
		t.Fatal(err)
	}
	if done {
		t.Fatal("new operation unexpectedly replayed done")
	}
	op, err = RecordCloudNotificationClaimOperationAttempt(paths, op, time.Now().UTC())
	if err != nil {
		t.Fatal(err)
	}
	if err := os.RemoveAll(paths.OpsDone); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(paths.OpsDone, []byte("not a directory"), 0o600); err != nil {
		t.Fatal(err)
	}
	if err := CompleteCloudNotificationClaimOperation(paths, op, time.Now().UTC()); err == nil {
		t.Fatal("complete succeeded with invalid done path")
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID); err != nil || !ok || pending.Attempts != 1 {
		t.Fatalf("pending op after failed done write = %+v %v %v", pending, ok, err)
	}

	if err := os.Remove(paths.OpsDone); err != nil {
		t.Fatal(err)
	}
	if err := os.MkdirAll(paths.OpsDone, 0o700); err != nil {
		t.Fatal(err)
	}
	if err := CompleteCloudNotificationClaimOperation(paths, op, time.Now().UTC()); err != nil {
		t.Fatalf("complete retry failed: %v", err)
	}
	if pending, ok, err := ReadPendingCloudNotificationClaimOperation(paths, opID); err != nil || ok {
		t.Fatalf("pending op after successful complete = %+v %v %v", pending, ok, err)
	}
	if doneOp, ok, err := ReadDoneCloudNotificationClaimOperation(paths, opID); err != nil || !ok || doneOp.Attempts != 1 {
		t.Fatalf("done op after successful complete = %+v %v %v", doneOp, ok, err)
	}
}

