func TestDaemonReusesPendingCloudNotificationWaitOperationAfterAmbiguousFailure(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	client := &fakeNotificationClient{
		errs: []error{errNotificationLeaseAmbiguous},
		leases: []*CloudNotificationLease{{
			ClaimID:        "clm_pendingwait1234567890",
			NotificationID: "ntf_pendingwait1234567890",
			ClaimedAt:      claimedAt,
			LeaseExpiresAt: leaseExpiresAt,
			Notification: CloudNotification{
				ID:         "ntf_pendingwait1234567890",
				Type:       "mention",
				DocSlug:    "abc123",
				DocTitle:   "Design Review",
				FromHandle: "max.sender",
				Context:    "Replay the pending wait.",
				CreatedAt:  claimedAt,
			},
		}},
	}
	paths := testDaemonPaths(t)
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	first := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudpendingwait1",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 1000},
	})
	if first.OK || first.Error == nil || first.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("first pending wait response = %+v", first)
	}
	pending, ok, err := ReadPendingCloudNotificationWaitOperationForBot(paths, "max.reviewer", "reviewer")
	if err != nil {
		t.Fatal(err)
	}
	if !ok || !LocalOperationIDRE.MatchString(pending.OpID) {
		t.Fatalf("pending op = %+v ok=%v", pending, ok)
	}
	if len(client.idempotencyKeys) != 1 || client.idempotencyKeys[0] != pending.OpID {
		t.Fatalf("first idempotency keys = %#v pending=%s", client.idempotencyKeys, pending.OpID)
	}

	second := requestDaemon(t, paths, map[string]any{
		"id": "req_cloudpendingwait2",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 1000},
	})
	if !second.OK || second.Result.(map[string]any)["source"] != "comment.io" {
		t.Fatalf("second pending wait response = %+v", second)
	}
	if len(client.idempotencyKeys) != 2 || client.idempotencyKeys[1] != pending.OpID {
		t.Fatalf("second idempotency keys = %#v pending=%s", client.idempotencyKeys, pending.OpID)
	}
	if _, ok, err := ReadPendingCloudNotificationWaitOperationForBot(paths, "max.reviewer", "reviewer"); err != nil || ok {
		t.Fatalf("pending op after success ok=%v err=%v", ok, err)
	}
	if _, err := os.Stat(doneCloudNotificationWaitOperationPath(paths, pending.OpID)); err != nil {
		t.Fatalf("done op missing: %v", err)
	}
}

