func TestDaemonNotificationPollerIngestsAndNudgesManagedBot(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_pollerclaim1234567890",
		NotificationID: "ntf_pollercloud1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_pollercloud1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Background poller should wake the managed reviewer bot.",
			CreatedAt:  claimedAt,
		},
	}
	paths := testDaemonPaths(t)
	botletsHome := writeMessageTestBotFiles(t, paths)
	client := &fakeNotificationClient{leasesByProfile: map[string][]*CloudNotificationLease{
		"max.reviewer": {lease},
	}}
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:                     paths,
		Version:                   "test",
		Tmux:                      tmux,
		BotletsHome:               botletsHome,
		NotificationClient:        client,
		EnableNotificationPollers: true,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()

	var messageID string
	waitForCondition(t, "background cloud notification nudge", func() bool {
		daemon.busMu.Lock()
		summary, storeErr := daemon.store.WaitMessageSummary(context.Background(), MessageListFilter{Profile: "max.reviewer", BotName: "reviewer"})
		daemon.busMu.Unlock()
		if storeErr != nil || summary == nil || summary.Source != "comment.io" {
			return false
		}
		messageID = summary.MessageID
		tmux.mu.Lock()
		defer tmux.mu.Unlock()
		for _, send := range tmux.sends {
			if strings.Contains(send, "comment messages receive "+messageID) {
				return true
			}
		}
		return false
	})

	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	if metadata.ClaimID != lease.ClaimID || metadata.NotificationID != lease.NotificationID {
		t.Fatalf("poller metadata = %+v", metadata)
	}
	records, err := ListSessionRecords(paths)
	if err != nil {
		t.Fatal(err)
	}
	foundAlive := false
	for _, record := range records {
		if record.Profile == "max.reviewer" && record.BotName == "reviewer" && record.State == "alive" {
			foundAlive = true
			break
		}
	}
	if !foundAlive {
		t.Fatalf("poller did not start reviewer session: %#v", records)
	}
	health := requestDaemon(t, paths, map[string]any{"id": "req_pollerhealth", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health failed: %+v", health.Error)
	}
	result := health.Result.(map[string]any)
	if result["notification_pollers_enabled"] != true {
		t.Fatalf("pollers not enabled in health: %#v", result)
	}
	pollers := result["notification_pollers"].([]any)
	foundReviewer := false
	for _, raw := range pollers {
		status := raw.(map[string]any)
		if status["profile"] == "max.reviewer" {
			foundReviewer = true
			if _, ok := status["last_lease_at"].(string); !ok {
				t.Fatalf("reviewer poller missing last_lease_at: %#v", status)
			}
		}
	}
	if !foundReviewer {
		t.Fatalf("reviewer poller missing from health: %#v", pollers)
	}
}

func TestDaemonNotificationPollerWithoutWakeUsesIdleCadence(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_nowakepollerclaim123",
		NotificationID: "ntf_nowakepollercloud123",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_nowakepollercloud123",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "No Wake Poller",
			FromHandle: "max.sender",
			Context:    "No-wake clients should keep the fast lease cadence.",
			CreatedAt:  claimedAt,
		},
	}
	paths := testDaemonPaths(t)
	botletsHome := writeMessageTestBotFiles(t, paths)
	client := &fakeNotificationClient{leasesByProfile: map[string][]*CloudNotificationLease{
		"max.reviewer": {},
	}}
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:                     paths,
		Version:                   "test",
		Tmux:                      tmux,
		BotletsHome:               botletsHome,
		NotificationClient:        client,
		EnableNotificationPollers: true,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()

	waitForCondition(t, "initial no-wake lease probe", func() bool {
		return client.profileWaitCalls("max.reviewer") >= 1
	})
	client.enqueueForProfile("max.reviewer", lease)

	var messageID string
	foundNudge := false
	deadline := time.Now().Add(time.Second)
	for time.Now().Before(deadline) {
		daemon.busMu.Lock()
		summary, storeErr := daemon.store.WaitMessageSummary(context.Background(), MessageListFilter{Profile: "max.reviewer", BotName: "reviewer"})
		daemon.busMu.Unlock()
		if storeErr == nil && summary != nil && summary.Source == "comment.io" {
			messageID = summary.MessageID
			tmux.mu.Lock()
			for _, send := range tmux.sends {
				if strings.Contains(send, "comment messages receive "+messageID) {
					foundNudge = true
					break
				}
			}
			tmux.mu.Unlock()
			if foundNudge {
				break
			}
		}
		time.Sleep(20 * time.Millisecond)
	}
	if !foundNudge {
		client.mu.Lock()
		timeouts := append([]time.Duration(nil), client.timeouts...)
		client.mu.Unlock()
		t.Fatalf("timed out waiting for no-wake cloud notification nudge; waits=%#v", timeouts)
	}
	health := requestDaemon(t, paths, map[string]any{"id": "req_nowakepollerhealth", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health failed: %+v", health.Error)
	}
	for _, raw := range health.Result.(map[string]any)["notification_pollers"].([]any) {
		status := raw.(map[string]any)
		if status["profile"] == "max.reviewer" {
			if _, ok := status["last_error_code"]; ok {
				t.Fatalf("no-wake poller marked unhealthy: %#v", status)
			}
			return
		}
	}
	t.Fatalf("reviewer poller missing from health: %#v", health.Result)
}

