func TestDaemonTransientRuntimeReportsMissingBmux(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	bmux := newTestBmuxController(paths)
	bmux.defaultPaneCommand = "codex"
	bmux.newSessionErr = ErrBmuxNotInstalled
	// Pin an absolute bmux binary so this transient runtime opts into the bmux
	// host (tmux is the default); the pinned-but-missing bmux then surfaces the
	// dedicated BMUX_NOT_INSTALLED error.
	bmuxBinary := writeTrustedTestExecutable(t, "comment-bus-bmux-bin-", "bmux")
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        newTestTmuxController(),
		Bmux:        bmux,
		BmuxBinary:  bmuxBinary,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_missingtmuxruntime",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if start.OK || start.Error == nil {
		t.Fatalf("expected runtime.start to fail when bmux is missing: %+v", start)
	}
	if start.Error.Code != SocketErrorCodeBmuxNotInstalled {
		t.Fatalf("runtime.start error code = %q; want %q", start.Error.Code, SocketErrorCodeBmuxNotInstalled)
	}
	if !strings.Contains(start.Error.Message, "bmux is required") {
		t.Fatalf("error message should explain bmux is required + how to install: %q", start.Error.Message)
	}
}

func TestDaemonTransientRuntimeUsesTmuxByDefault(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.runner", map[string]any{
		"agent_secret": "as_runner_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "agent")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"agent"}
	tmux.defaultPaneCaptureSequence = []string{"runtime ready", "runtime ready", "runtime ready"}
	// No bmux binary pin: the transient runtime must default to the tmux host.
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_tmuxdefaultruntime",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.runner",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.runner",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !start.OK {
		t.Fatalf("runtime.start failed: %+v", start.Error)
	}
	runtimeResult := start.Result.(map[string]any)["runtime"].(map[string]any)
	if runtimeResult["host"] != SessionHostTmux {
		t.Fatalf("runtime host = %#v, want %q (tmux is the default)", runtimeResult["host"], SessionHostTmux)
	}
	if bin, ok := runtimeResult["bmux_binary"]; ok && bin != "" {
		t.Fatalf("tmux-default runtime should not carry a bmux_binary, got %#v", bin)
	}
	paneTarget := runtimeResult["pane_target"].(string)
	tmux.mu.Lock()
	starts := len(tmux.starts)
	sends := append([]string(nil), tmux.sends...)
	tmux.mu.Unlock()
	if starts != 1 {
		t.Fatalf("tmux NewSession calls = %d, want 1 (default host must launch through tmux)", starts)
	}
	// The default tmux path must still deliver the startup instruction through
	// the tmux controller (a regression that silently skipped it would otherwise
	// leave this test green).
	if !testSendsContainPrefixAndNeedle(sends, "literal "+paneTarget+" ", "https://comment.example/llms.txt") {
		t.Fatalf("tmux-default startup instruction should be sent through tmux, got %#v", sends)
	}
}

