func TestDaemonTransientRuntimeUsesBmuxWhenBinaryPinned(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	runtimeHome := filepath.Dir(filepath.Dir(filepath.Dir(runtimePath)))
	bmuxBinary := writeTrustedTestExecutable(t, "comment-bus-bmux-bin-", "bmux")
	tmux := newTestTmuxController()
	tmux.failStartErrAll = errors.New("tmux should not be used for transient runtimes")
	bmux := newTestBmuxController(paths)
	bmux.defaultPaneCommand = "codex"
	codexSessionID := "019d0c01-3dbe-7512-a10b-28593b915bbc"
	bmux.afterSendEnter = func(_ string, _ string) {
		bmux.mu.Lock()
		nonce := codexNonceFromSendsLocked(bmux.sends)
		bmux.mu.Unlock()
		if nonce == "" {
			return
		}
		if err := writeCodexRolloutForDaemonTest(runtimeHome, time.Now(), codexSessionID, paths.Home, nonce); err != nil {
			t.Errorf("write Codex rollout: %v", err)
		}
	}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		Bmux:        bmux,
		BmuxBinary:  bmuxBinary,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_bmuxruntime",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !start.OK {
		t.Fatalf("runtime.start failed: %+v", start.Error)
	}
	runtimeResult := start.Result.(map[string]any)["runtime"].(map[string]any)
	if runtimeResult["host"] != SessionHostBmux {
		t.Fatalf("runtime host = %#v, want %q", runtimeResult["host"], SessionHostBmux)
	}
	if runtimeResult["bmux_binary"] != bmuxBinary {
		t.Fatalf("runtime bmux_binary = %#v, want %q", runtimeResult["bmux_binary"], bmuxBinary)
	}
	bmux.mu.Lock()
	starts := len(bmux.starts)
	paneTarget := runtimeResult["pane_target"].(string)
	sends := append([]string(nil), bmux.sends...)
	bmux.mu.Unlock()
	if starts != 1 {
		t.Fatalf("bmux starts = %d, want 1", starts)
	}
	if want, err := BmuxSocketPathForSession(paths, runtimeResult["session_name"].(string)); err != nil || paneTarget != want {
		t.Fatalf("runtime pane target = %q, want bmux socket %q (err=%v)", paneTarget, want, err)
	}
	if len(sends) == 0 {
		t.Fatalf("bmux startup sends = %#v, want startup instruction", sends)
	}
	sessionRecords, err := ListSessionRecords(paths)
	if err != nil {
		t.Fatalf("ListSessionRecords after transient runtime startup = %v", err)
	}
	if len(sessionRecords) != 0 {
		t.Fatalf("transient runtime wrote managed session records: %+v", sessionRecords)
	}
}

