func TestDaemonTransientRuntimeReconcileTracksRetryableInspectFailure(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"codex"}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_retryrehydratestart",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !start.OK {
		t.Fatalf("runtime.start failed: %+v", start.Error)
	}
	runtimeResult := start.Result.(map[string]any)["runtime"].(map[string]any)
	runID := runtimeResult["run_id"].(string)
	sessionName := runtimeResult["session_name"].(string)
	if err := daemon.Close(); err != nil {
		t.Fatal(err)
	}

	tmux.mu.Lock()
	tmux.failHas[sessionName] = true
	tmux.mu.Unlock()
	restarted, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer restarted.Close()
	restarted.transientRuntimeMu.Lock()
	active := restarted.transientRuntimes[runID]
	mainRunID := restarted.transientRuntimeMainProfiles["max.codex"]
	restarted.transientRuntimeMu.Unlock()
	if active == nil || mainRunID != runID {
		t.Fatalf("retryable runtime active=%v mainRunID=%q want %q", active != nil, mainRunID, runID)
	}
	second := requestDaemon(t, paths, map[string]any{
		"id": "req_retryrehydratesecond",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !second.OK {
		t.Fatalf("second main during retryable inspect failure = %+v", second)
	}
	secondResult := second.Result.(map[string]any)
	secondRuntime := secondResult["runtime"].(map[string]any)
	if secondResult["existing"] != true || secondRuntime["run_id"] != runID {
		t.Fatalf("second main during retryable inspect failure result = %#v", secondResult)
	}
	tmux.mu.Lock()
	starts := len(tmux.starts)
	tmux.mu.Unlock()
	if starts != 1 {
		t.Fatalf("retryable inspect failure starts = %d, want 1", starts)
	}
}

func TestDaemonTransientRuntimeAllowsExplicitTaskRoleBesideMain(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"codex"}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	startRuntime := func(id string, role string) string {
		t.Helper()
		params := map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		}
		if role != "" {
			params["role"] = role
		}
		response := requestDaemon(t, paths, map[string]any{
			"id": id,
			"op": "runtime.start",
			"auth": map[string]any{
				"mode":       "owner",
				"profile":    "max.codex",
				"capability": capability,
			},
			"params": params,
		})
		if !response.OK {
			t.Fatalf("%s failed: %+v", id, response.Error)
		}
		runtimeResult := response.Result.(map[string]any)["runtime"].(map[string]any)
		if runtimeResult["role"] != normalizeTransientRuntimeRole(role) {
			t.Fatalf("%s role = %#v", id, runtimeResult)
		}
		return runtimeResult["run_id"].(string)
	}
	mainRunID := startRuntime("req_taskmainstart", "")
	taskRunID := startRuntime("req_taskrolestart", RuntimeRoleTask)
	if mainRunID == taskRunID {
		t.Fatal("main and task runtimes used same run id")
	}
	records, err := daemon.store.ListTransientRuntimes(context.Background())
	if err != nil {
		t.Fatal(err)
	}
	if len(records) != 2 {
		t.Fatalf("stored runtimes = %+v", records)
	}
	for i, runID := range []string{taskRunID, mainRunID} {
		stop := requestDaemon(t, paths, map[string]any{
			"id": "req_taskstop" + strconv.Itoa(i),
			"op": "runtime.stop",
			"auth": map[string]any{
				"mode":       "owner",
				"profile":    "max.codex",
				"capability": capability,
			},
			"params": map[string]any{"run_id": runID},
		})
		if !stop.OK {
			t.Fatalf("runtime.stop %s failed: %+v", runID, stop.Error)
		}
	}
}

func TestDaemonTransientRuntimeStartReturnsExistingMainRuntime(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"codex"}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:       paths,
		Version:     "test",
		Tmux:        tmux,
		BotletsHome: filepath.Join(paths.Home, "botlets"),
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}
	startRuntime := func(id string) SocketResponse {
		t.Helper()
		return requestDaemon(t, paths, map[string]any{
			"id": id,
			"op": "runtime.start",
			"auth": map[string]any{
				"mode":       "owner",
				"profile":    "max.codex",
				"capability": capability,
			},
			"params": map[string]any{
				"profile":         "max.codex",
				"cwd":             paths.Home,
				"runtime_command": []any{runtimePath},
			},
		})
	}
	first := startRuntime("req_secondmainfirst")
	if !first.OK {
		t.Fatalf("first runtime.start failed: %+v", first.Error)
	}
	second := startRuntime("req_secondmainsecond")
	if !second.OK {
		t.Fatalf("second runtime.start = %+v", second)
	}
	firstRuntime := first.Result.(map[string]any)["runtime"].(map[string]any)
	secondResult := second.Result.(map[string]any)
	secondRuntime := secondResult["runtime"].(map[string]any)
	if secondResult["existing"] != true {
		t.Fatalf("second runtime.start existing = %#v", secondResult)
	}
	if secondRuntime["run_id"] != firstRuntime["run_id"] {
		t.Fatalf("second runtime = %#v, want run_id %s", secondRuntime, firstRuntime["run_id"])
	}
	tmux.mu.Lock()
	starts := len(tmux.starts)
	tmux.mu.Unlock()
	if starts != 1 {
		t.Fatalf("runtime starts = %d, want 1", starts)
	}
	records, err := daemon.store.ListTransientRuntimes(context.Background())
	if err != nil {
		t.Fatal(err)
	}
	if len(records) != 1 {
		t.Fatalf("stored runtimes = %+v", records)
	}
}

