func TestDaemonTransientRuntimeWatcherAvoidsPerTickSessionPolls(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"codex"}
	// Pin a bmux binary so this transient runtime opts into the bmux host (its
	// pane target is the bmux socket path this watcher test asserts on).
	bmuxBinary := writeTrustedTestExecutable(t, "comment-bus-bmux-bin-", "bmux")
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:            paths,
		Version:          "test",
		Tmux:             tmux,
		BmuxBinary:       bmuxBinary,
		BotletsHome:      filepath.Join(paths.Home, "botlets"),
		TmuxPollInterval: 250 * time.Millisecond,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_runtimewatchpolls",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !start.OK {
		t.Fatalf("runtime.start failed: %+v", start.Error)
	}
	runtimeResult := start.Result.(map[string]any)["runtime"].(map[string]any)
	sessionName := runtimeResult["session_name"].(string)
	paneTarget := runtimeResult["pane_target"].(string)
	expectedPaneTarget, err := BmuxSocketPathForSession(paths, sessionName)
	if err != nil {
		t.Fatal(err)
	}
	if paneTarget != expectedPaneTarget {
		t.Fatalf("runtime pane target = %q, want bmux socket %q", paneTarget, expectedPaneTarget)
	}

	waitForConditionWithin(t, "runtime watcher pane command checks", 2*time.Second, func() bool {
		tmux.mu.Lock()
		defer tmux.mu.Unlock()
		return tmux.paneCommandReads[paneTarget] >= 2
	})
	tmux.mu.Lock()
	hasReads := tmux.hasSessionReads[sessionName]
	belongsReads := tmux.paneBelongsReads[paneTarget]
	tmux.mu.Unlock()
	if hasReads != 0 || belongsReads != 0 {
		t.Fatalf("runtime watcher used per-tick session polls: session=%q pane=%q has=%d belongs=%d", sessionName, paneTarget, hasReads, belongsReads)
	}
}

func TestDaemonTransientRuntimeWatcherRetriesOnTransientTmuxError(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	writeAgentProfile(t, paths, "max.codex", map[string]any{
		"agent_secret": "as_codex_profile_secret",
		"base_url":     "https://comment.example",
	})
	runtimePath := prependFakeRuntime(t, "codex")
	tmux := newTestTmuxController()
	tmux.defaultPaneCommandSequence = []string{"codex"}
	var logs bytes.Buffer
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:            paths,
		Version:          "test",
		Tmux:             tmux,
		BotletsHome:      filepath.Join(paths.Home, "botlets"),
		LogWriter:        &logs,
		TmuxPollInterval: 250 * time.Millisecond,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	start := requestDaemon(t, paths, map[string]any{
		"id": "req_watcherretrystart",
		"op": "runtime.start",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{
			"profile":         "max.codex",
			"cwd":             paths.Home,
			"runtime_command": []any{runtimePath},
		},
	})
	if !start.OK {
		t.Fatalf("runtime.start failed: %+v", start.Error)
	}
	runtimeResult := start.Result.(map[string]any)["runtime"].(map[string]any)
	runID := runtimeResult["run_id"].(string)
	paneTarget := runtimeResult["pane_target"].(string)

	tmux.mu.Lock()
	tmux.failPaneCommand[paneTarget] = true
	tmux.mu.Unlock()
	waitForCondition(t, "watcher logs poller_error during pane inspect blip", func() bool {
		for _, entry := range structuredLogEntries(t, &logs) {
			if entry.Msg == "runtime.poller_error" && entry.Data["run_id"] == runID {
				return true
			}
			if entry.Msg == "runtime.poller_stopped" && entry.Data["run_id"] == runID {
				t.Fatalf("watcher terminated poller on transient tmux error: %+v", entry)
			}
		}
		return false
	})
	daemon.transientRuntimeMu.Lock()
	_, stillActive := daemon.transientRuntimes[runID]
	daemon.transientRuntimeMu.Unlock()
	if !stillActive {
		t.Fatalf("transient runtime was removed during transient tmux error")
	}

	tmux.mu.Lock()
	tmux.failPaneCommand[paneTarget] = false
	tmux.mu.Unlock()
	waitForConditionWithin(t, "watcher logs poller_resumed after tmux recovery", 10*time.Second, func() bool {
		for _, entry := range structuredLogEntries(t, &logs) {
			if entry.Msg == "runtime.poller_resumed" && entry.Data["run_id"] == runID {
				return true
			}
		}
		return false
	})

	stop := requestDaemon(t, paths, map[string]any{
		"id": "req_watcherretrystop",
		"op": "runtime.stop",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.codex",
			"capability": capability,
		},
		"params": map[string]any{"run_id": runID},
	})
	if !stop.OK {
		t.Fatalf("runtime.stop failed: %+v", stop.Error)
	}
}

