func TestDaemonAutomaticCloudNudgeBackoffScansPastBlockedWindow(t *testing.T) {
	ctx := context.Background()
	paths := testDaemonPaths(t)
	store, err := OpenStore(ctx, paths)
	if err != nil {
		t.Fatal(err)
	}
	defer store.Close()
	now := time.Now().UTC()
	attemptedAt := busTime(now.Add(-2 * time.Minute))
	succeededAt := busTime(now.Add(-time.Minute))
	nextEligibleAt := busTime(now.Add(time.Hour))
	record := registerAutomaticNudgeTestSession(t, paths)
	record.AutomaticNudges = map[string]LastNudgeRecord{}
	wantMessageID := ""
	for i := 0; i < dispatchReadySummaryLimit+1; i++ {
		messageID, err := GenerateLocalID("msg", 0)
		if err != nil {
			t.Fatal(err)
		}
		claimID := fmt.Sprintf("clm_dispatchscan%02d1234567890", i)
		notificationID := fmt.Sprintf("ntf_dispatchscan%02d1234567890", i)
		createdAt := now.Add(time.Duration(i) * time.Millisecond)
		claimGeneration := busTime(createdAt)
		if _, err := store.InsertCloudNotificationMessage(ctx, CloudNotificationMessage{
			ID:             messageID,
			Profile:        "max.reviewer",
			BotName:        "reviewer",
			Kind:           "doc.mention",
			From:           "@max.sender",
			Body:           MessageBody{Format: "markdown", Content: fmt.Sprintf("cloud %d", i)},
			Refs:           map[string]any{"doc_slug": fmt.Sprintf("doc-%d", i)},
			NotificationID: notificationID,
			CreatedAt:      busTime(createdAt),
			LeaseExpiresAt: busTime(now.Add(time.Hour)),
			Now:            now,
		}); err != nil {
			t.Fatal(err)
		}
		if err := WritePrivateCloudMessageMetadata(paths, PrivateCloudMessageMetadata{
			LocalMessageID: messageID,
			Source:         "comment.io",
			Profile:        "max.reviewer",
			BaseURL:        "https://comment.example",
			NotificationID: notificationID,
			ClaimID:        claimID,
			ClaimedAt:      claimGeneration,
			LeaseExpiresAt: busTime(now.Add(time.Hour)),
		}); err != nil {
			t.Fatal(err)
		}
		if i < dispatchReadySummaryLimit {
			setAutomaticNudgeState(&record, LastNudgeRecord{
				MessageID:       &messageID,
				AttemptedAt:     &attemptedAt,
				SucceededAt:     &succeededAt,
				ClaimGeneration: &claimGeneration,
				AttemptCount:    1,
				NextEligibleAt:  &nextEligibleAt,
			})
		} else {
			wantMessageID = messageID
		}
	}
	if err := WriteSessionRecord(paths, record); err != nil {
		t.Fatal(err)
	}
	daemon := &Daemon{paths: paths, store: store}
	summary, err := daemon.waitReadyMessageSummaryForDispatchLocked(ctx, MessageListFilter{Profile: "max.reviewer", BotName: "reviewer"}, now, []SessionRecord{record})
	if err != nil {
		t.Fatal(err)
	}
	if summary == nil || summary.MessageID != wantMessageID {
		t.Fatalf("dispatch summary = %+v, want message %s after blocked window", summary, wantMessageID)
	}
	ready, readyErr := daemon.hasReadyCloudNotificationMessage("max.reviewer", "reviewer")
	if readyErr != nil {
		t.Fatal(readyErr)
	}
	if !ready {
		t.Fatal("cloud pre-lease readiness scan should find eligible message after blocked window")
	}
}

func TestDaemonCloudNudgeReadinessDoesNotWaitBehindBusLock(t *testing.T) {
	ctx := context.Background()
	paths := testDaemonPaths(t)
	store, err := OpenStore(ctx, paths)
	if err != nil {
		t.Fatal(err)
	}
	defer store.Close()
	daemon := &Daemon{paths: paths, store: store}
	daemon.busMu.Lock()
	busLocked := true
	unlockBus := func() {
		if busLocked {
			daemon.busMu.Unlock()
			busLocked = false
		}
	}
	defer unlockBus()
	done := make(chan *SocketError, 1)
	go func() {
		_, readyErr := daemon.hasReadyCloudNotificationMessage("max.reviewer", "reviewer")
		done <- readyErr
	}()
	select {
	case readyErr := <-done:
		unlockBus()
		if readyErr != nil {
			t.Fatal(readyErr)
		}
	case <-time.After(2 * time.Second):
		unlockBus()
		select {
		case readyErr := <-done:
			if readyErr != nil {
				t.Fatal(readyErr)
			}
			t.Fatal("cloud pre-lease readiness scan waited behind busMu")
		case <-time.After(2 * time.Second):
			t.Fatal("cloud pre-lease readiness scan did not finish after releasing busMu")
		}
	}
}

func TestDaemonAutomaticCloudNudgeDeadlineUsesEarliestBlockedMessage(t *testing.T) {
	ctx := context.Background()
	paths := testDaemonPaths(t)
	store, err := OpenStore(ctx, paths)
	if err != nil {
		t.Fatal(err)
	}
	defer store.Close()
	now := time.Now().UTC()
	record := registerAutomaticNudgeTestSession(t, paths)
	record.AutomaticNudges = map[string]LastNudgeRecord{}
	attemptedAt := busTime(now.Add(-2 * time.Minute))
	succeededAt := busTime(now.Add(-time.Minute))
	firstDeadline := now.Add(30 * time.Second).UTC()
	secondDeadline := now.Add(time.Minute).UTC()
	for i, deadline := range []time.Time{secondDeadline, firstDeadline} {
		messageID, err := GenerateLocalID("msg", 0)
		if err != nil {
			t.Fatal(err)
		}
		claimID := fmt.Sprintf("clm_deadlinescan%02d1234567890", i)
		notificationID := fmt.Sprintf("ntf_deadlinescan%02d1234567890", i)
		createdAt := now.Add(time.Duration(i) * time.Millisecond)
		claimGeneration := busTime(createdAt)
		if _, err := store.InsertCloudNotificationMessage(ctx, CloudNotificationMessage{
			ID:             messageID,
			Profile:        "max.reviewer",
			BotName:        "reviewer",
			Kind:           "doc.mention",
			From:           "@max.sender",
			Body:           MessageBody{Format: "markdown", Content: fmt.Sprintf("deadline %d", i)},
			Refs:           map[string]any{"doc_slug": fmt.Sprintf("doc-deadline-%d", i)},
			NotificationID: notificationID,
			CreatedAt:      busTime(createdAt),
			LeaseExpiresAt: busTime(now.Add(time.Hour)),
			Now:            now,
		}); err != nil {
			t.Fatal(err)
		}
		if err := WritePrivateCloudMessageMetadata(paths, PrivateCloudMessageMetadata{
			LocalMessageID: messageID,
			Source:         "comment.io",
			Profile:        "max.reviewer",
			BaseURL:        "https://comment.example",
			NotificationID: notificationID,
			ClaimID:        claimID,
			ClaimedAt:      claimGeneration,
			LeaseExpiresAt: busTime(now.Add(time.Hour)),
		}); err != nil {
			t.Fatal(err)
		}
		nextEligibleAt := busTime(deadline)
		setAutomaticNudgeState(&record, LastNudgeRecord{
			MessageID:       &messageID,
			AttemptedAt:     &attemptedAt,
			SucceededAt:     &succeededAt,
			ClaimGeneration: &claimGeneration,
			AttemptCount:    1,
			NextEligibleAt:  &nextEligibleAt,
		})
	}
	if err := WriteSessionRecord(paths, record); err != nil {
		t.Fatal(err)
	}
	daemon := &Daemon{paths: paths, store: store}
	ready, readyErr := daemon.hasReadyCloudNotificationMessage("max.reviewer", "reviewer")
	if readyErr != nil {
		t.Fatal(readyErr)
	}
	if ready {
		t.Fatal("cloud pre-lease readiness should be false while all messages are backed off")
	}
	next, deadlineErr := daemon.nextReadyCloudAutomaticNudgeDeadline("max.reviewer", "reviewer", now)
	if deadlineErr != nil {
		t.Fatal(deadlineErr)
	}
	if next == nil || !next.Equal(firstDeadline) {
		t.Fatalf("next automatic nudge deadline = %v, want %v", next, firstDeadline)
	}
}

func TestDaemonAutomaticCloudNudgeAttemptCountWaitsForSubmittedPrompt(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_attemptsubmitted1234567890",
		NotificationID: "ntf_attemptsubmitted1234567890",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:         "ntf_attemptsubmitted1234567890",
			Type:       "mention",
			DocSlug:    "abc123",
			DocTitle:   "Design Review",
			FromHandle: "max.sender",
			Context:    "Transient send failure should not consume automatic attempts.",
			CreatedAt:  claimedAt,
		},
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	paths := testDaemonPaths(t)
	tmux := newTestTmuxController()
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               tmux,
		BotletsHome:        filepath.Join(paths.Home, "botlets"),
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)
	start := requestDaemon(t, paths, map[string]any{
		"id": "req_attemptsubmittedstart",
		"op": "sessions.start",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer"},
	})
	if !start.OK {
		t.Fatalf("session start failed: %+v", start.Error)
	}
	session := start.Result.(map[string]any)["session"].(map[string]any)
	sessionID := session["session_id"].(string)
	record, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	tmux.mu.Lock()
	tmux.failSend[record.PaneTarget] = true
	tmux.mu.Unlock()
	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_attemptsubmittedwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0},
	})
	if !wait.OK || wait.Result.(map[string]any)["source"] != "comment.io" {
		t.Fatalf("cloud wait after failed send = %+v", wait)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)
	failedRecord, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	if failedRecord.LastNudge.MessageID == nil || *failedRecord.LastNudge.MessageID != messageID {
		t.Fatalf("failed nudge should record latest attempt, last nudge = %+v", failedRecord.LastNudge)
	}
	if failedRecord.LastNudge.AttemptCount != 0 || failedRecord.LastNudge.NextEligibleAt != nil || len(failedRecord.AutomaticNudges) != 0 {
		t.Fatalf("failed send consumed automatic nudge state: last=%+v automatic=%+v", failedRecord.LastNudge, failedRecord.AutomaticNudges)
	}
	tmux.mu.Lock()
	tmux.failSend[record.PaneTarget] = false
	tmux.mu.Unlock()
	daemon.sessionMu.Lock()
	refreshed, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		daemon.sessionMu.Unlock()
		t.Fatal(err)
	}
	nudged, nudgeErr := daemon.nudgeReadyQueueHeadIfIdleLockedWithContext(context.Background(), refreshed, false)
	daemon.sessionMu.Unlock()
	if nudgeErr != nil || !nudged {
		t.Fatalf("retry nudge = %v err=%+v", nudged, nudgeErr)
	}
	retriedRecord, err := ReadSessionRecord(paths, sessionID)
	if err != nil {
		t.Fatal(err)
	}
	retryState := automaticNudgeState(retriedRecord, messageID, &claimedAt)
	if retryState.MessageID == nil || *retryState.MessageID != messageID || retryState.AttemptCount != 1 || retryState.NextEligibleAt == nil {
		t.Fatalf("retry automatic nudge state = %+v, want first submitted attempt", retryState)
	}
}

