func TestDaemonWaitQuarantinesQueuedBotletsTaskAfterRegistryGenerationChange(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	task := validBotletsTaskNotification()
	lease := &CloudNotificationLease{
		ClaimID:        "clm_stalebotletstask123",
		NotificationID: "ntf_stalebotletstask123",
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:          "ntf_stalebotletstask123",
			Type:        "botlets_task",
			FromHandle:  "botlets.ai",
			FromName:    "Botlets",
			Context:     "Run the scheduled task.",
			CreatedAt:   claimedAt,
			BotletsTask: task,
		},
	}
	paths := testDaemonPaths(t)
	prependFakeRuntime(t, "claude")
	reviewerPath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_reviewer_profile_secret",
	})
	writeLocalSyncBrainProjectionForTest(t, paths, "Botlets/max/reviewer/brain")
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled":  true,
			"runtime":  "claude",
			"timezone": "UTC",
		},
		"brain_ref": map[string]any{
			"workspace_id":     "ws_brain",
			"owner_agent_id":   "ag_owner",
			"bot_agent_id":     "ag_bot",
			"container_id":     "lc_brain",
			"root_folder_id":   "lf_brain",
			"relative_path":    "Botlets/max/reviewer/brain",
			"setup_generation": 5,
		},
	}})
	if _, err := ValidateBotletsBrainProjection(paths, BotRegistryEntry{
		Name:   "reviewer",
		Handle: "max.reviewer",
		BrainRef: &BotBrainRef{
			WorkspaceID:     "ws_brain",
			OwnerAgentID:    "ag_owner",
			BotAgentID:      "ag_bot",
			ContainerID:     "lc_brain",
			RootFolderID:    "lf_brain",
			RelativePath:    "Botlets/max/reviewer/brain",
			SetupGeneration: 5,
		},
	}); err != nil {
		t.Fatalf("direct projection validation failed: %v", err)
	}
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        botletsHome,
		NotificationClient: client,
	})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		t.Fatal(err)
	}

	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_botletstaskfirstwait",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0, "kinds": []any{"botlets.task"}},
	})
	if !wait.OK || wait.Result.(map[string]any)["source"] != "comment.io" {
		client.mu.Lock()
		mutations := append([]notificationMutationCall{}, client.mutations...)
		calls := client.calls
		client.mu.Unlock()
		t.Fatalf("initial botlets task wait = %+v calls=%d mutations=%+v", wait, calls, mutations)
	}
	messageID := wait.Result.(map[string]any)["message_id"].(string)

	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled":  true,
			"runtime":  "claude",
			"timezone": "UTC",
		},
		"brain_ref": map[string]any{
			"workspace_id":     "ws_brain",
			"owner_agent_id":   "ag_owner",
			"bot_agent_id":     "ag_bot",
			"container_id":     "lc_brain",
			"root_folder_id":   "lf_brain",
			"relative_path":    "Botlets/max/reviewer/brain",
			"setup_generation": 6,
		},
	}})
	reload := requestDaemon(t, paths, map[string]any{
		"id": "req_botletstaskreload",
		"op": "reload-profiles",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"botlets_home": botletsHome},
	})
	if !reload.OK {
		t.Fatalf("reload failed: %+v", reload.Error)
	}
	secondWait := requestDaemon(t, paths, map[string]any{
		"id": "req_botletstaskstale",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0, "kinds": []any{"botlets.task"}},
	})
	if !secondWait.OK || secondWait.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("stale botlets task wait = %+v", secondWait)
	}
	daemon.busMu.Lock()
	staleMessage, err := daemon.store.GetInboxMessage(context.Background(), "max.reviewer", messageID)
	daemon.busMu.Unlock()
	if err != nil {
		t.Fatal(err)
	}
	if staleMessage.Delivery.State != "released" {
		t.Fatalf("stale task delivery = %+v, want released", staleMessage.Delivery)
	}
	assertNotificationMutationCount(t, client, "release", "clm_stalebotletstask123", 1)
	assertNotificationMutationCount(t, client, "ack", "clm_stalebotletstask123", 0)
	assertNotificationMutationCount(t, client, "renew", "clm_stalebotletstask123", 0)
	receive := requestDaemon(t, paths, map[string]any{
		"id": "req_botletstaskstalereceive",
		"op": "messages.receive",
		"auth": map[string]any{
			"mode":       "owner",
			"profile":    "max.reviewer",
			"capability": capability,
		},
		"params": map[string]any{"message_id": messageID},
	})
	if receive.OK || receive.Error == nil || receive.Error.Code != "CONFLICT" {
		t.Fatalf("stale botlets task receive = %+v", receive)
	}
}

