func TestDaemonStaleBotletsTaskWaitKeepsLocalVisibleUntilUpstreamReleaseSettles(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon, client, capability, messageID, brainRoot := startBotletsTaskDaemonWithLease(t, ctx, "clm_pendingstalerelease123", "ntf_pendingstalerelease123")
	defer daemon.Close()

	client.mutationErrs = append(client.mutationErrs, errNotificationMutationAmbiguous)
	if err := os.RemoveAll(brainRoot); err != nil {
		t.Fatal(err)
	}
	stale := requestDaemon(t, paths, map[string]any{
		"id": "req_pendingstalerelease",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0, "kinds": []any{"botlets.task"}},
	})
	if stale.OK || stale.Error == nil || stale.Error.Code != "UPSTREAM_ERROR" {
		t.Fatalf("ambiguous stale botlets release wait = %+v", stale)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "unclaimed")
	assertNotificationMutationCount(t, client, "release", "clm_pendingstalerelease123", 1)
	metadata, err := ReadPrivateCloudMessageMetadata(paths, "max.reviewer", messageID)
	if err != nil {
		t.Fatal(err)
	}
	pending, ok, err := findPendingCloudNotificationClaimOperation(paths, "release", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, 0, staleBotletsTaskTargetReleaseReason)
	if err != nil || !ok {
		t.Fatalf("pending stale release op = %+v ok=%v err=%v", pending, ok, err)
	}
	if pending.Attempts != 1 {
		t.Fatalf("pending stale release attempts = %d, want 1", pending.Attempts)
	}

	retry := requestDaemon(t, paths, map[string]any{
		"id": "req_pendingstalereleaseretry",
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0, "kinds": []any{"botlets.task"}},
	})
	if !retry.OK || retry.Result.(map[string]any)["timeout"] != true {
		t.Fatalf("settled stale botlets release retry = %+v", retry)
	}
	assertCloudMessageDeliveryState(t, daemon, "max.reviewer", messageID, "released")
	assertNotificationMutationCount(t, client, "release", "clm_pendingstalerelease123", 2)
	_, ok, err = findPendingCloudNotificationClaimOperation(paths, "release", "max.reviewer", messageID, metadata.ClaimID, metadata.NotificationID, 0, staleBotletsTaskTargetReleaseReason)
	if err != nil {
		t.Fatal(err)
	}
	if ok {
		t.Fatal("stale release op stayed pending after upstream release settled")
	}
}

