func TestDaemonLocalMessageWaitBlocksUntilMessageArrives(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()
	capability := loadMessageTestBots(t, paths)

	waitCh := make(chan SocketResponse, 1)
	go func() {
		waitCh <- requestDaemon(t, paths, map[string]any{
			"id": "req_msgwaitblocking",
			"op": "messages.wait",
			"auth": map[string]any{
				"mode":       "owner",
				"capability": capability,
			},
			"params": map[string]any{"bot": "reviewer", "timeout_ms": 1000},
		})
	}()
	time.Sleep(150 * time.Millisecond)
	send := requestDaemon(t, paths, map[string]any{
		"id": "req_msgwaitsend",
		"op": "messages.send",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{
			"from_bot": "sender",
			"to":       []any{"reviewer"},
			"body":     map[string]any{"format": "markdown", "content": "arrives while wait is open"},
		},
	})
	if !send.OK {
		t.Fatalf("send during wait failed: %+v", send.Error)
	}
	messageID := send.Result.(map[string]any)["messages"].([]any)[0].(map[string]any)["id"].(string)

	select {
	case wait := <-waitCh:
		if !wait.OK {
			t.Fatalf("blocking wait failed: %+v", wait.Error)
		}
		result := wait.Result.(map[string]any)
		if result["message_id"] != messageID {
			t.Fatalf("blocking wait result = %#v, want message %s", result, messageID)
		}
	case <-time.After(3 * time.Second):
		t.Fatal("blocking wait did not return")
	}
}

