func TestCloudNotificationWaitOperationTimeoutNormalizesBounds(t *testing.T) {
	if got := normalizedCloudNotificationWaitOperationTimeout(-time.Millisecond); got != 0 {
		t.Fatalf("negative operation timeout = %s, want 0", got)
	}
	if got := normalizedCloudNotificationWaitOperationTimeout(30 * time.Minute); got != 65*time.Second {
		t.Fatalf("long operation timeout = %s, want 65s", got)
	}
}

