func TestDaemonRemovesStaleSocket(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths := testDaemonPaths(t)
	fd, err := unix.Socket(unix.AF_UNIX, unix.SOCK_STREAM, 0)
	if err != nil {
		t.Fatal(err)
	}
	if err := unix.Bind(fd, &unix.SockaddrUnix{Name: paths.Socket}); err != nil {
		_ = unix.Close(fd)
		t.Fatal(err)
	}
	if err := unix.Close(fd); err != nil {
		t.Fatal(err)
	}
	if _, err := os.Lstat(paths.Socket); err != nil {
		t.Fatalf("expected stale socket path: %v", err)
	}

	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{Paths: paths, Version: "test"})
	if err != nil {
		t.Fatal(err)
	}
	defer daemon.Close()
	health := requestDaemon(t, paths, map[string]any{"id": "req_healthstale", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("health after stale socket cleanup failed: %+v", health.Error)
	}
}

func TestDaemonRefusesLiveSocket(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	paths, daemon := startTestDaemon(t, ctx, nil)
	defer daemon.Close()

	_, err := startDaemonForTest(t, ctx, DaemonOptions{Paths: paths, Version: "test"})
	if err == nil {
		t.Fatal("expected live socket to be refused")
	}
	if !strings.Contains(err.Error(), "daemon socket already exists") {
		t.Fatalf("live socket error = %v", err)
	}
	health := requestDaemon(t, paths, map[string]any{"id": "req_healthlive", "op": "health", "params": map[string]any{}})
	if !health.OK {
		t.Fatalf("existing daemon health failed after refused start: %+v", health.Error)
	}
}

func TestRemoveIfSameFileDoesNotRemoveReplacement(t *testing.T) {
	path := filepath.Join(t.TempDir(), "daemon.pid")
	if err := os.WriteFile(path, []byte("first"), 0o600); err != nil {
		t.Fatal(err)
	}
	firstInfo, err := os.Lstat(path)
	if err != nil {
		t.Fatal(err)
	}
	if err := os.Remove(path); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, []byte("replacement"), 0o600); err != nil {
		t.Fatal(err)
	}

	removed, err := removeIfSameFileStatus(path, firstInfo)
	if err != nil {
		t.Fatal(err)
	}
	if removed {
		t.Fatal("replacement file was reported as removed")
	}
	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatal(err)
	}
	if string(data) != "replacement" {
		t.Fatalf("replacement file was modified: %q", data)
	}
}

func startDaemonForTest(t *testing.T, ctx context.Context, options DaemonOptions) (*Daemon, error) {
	t.Helper()
	if options.CommentExecutable == nil {
		commentPath := writeTrustedTestExecutable(t, "comment-bus-comment-", "comment")
		options.CommentExecutable = func() (string, error) {
			return commentPath, nil
		}
	}
	if options.TmuxSubmitDelay == 0 {
		options.TmuxSubmitDelay = -1
	}
	if options.Bmux == nil && options.Tmux != nil {
		if tmux, ok := options.Tmux.(*testTmuxController); ok && options.Paths.Home != "" {
			options.Bmux = newTestBmuxCompatController(options.Paths, tmux)
		} else {
			options.Bmux = options.Tmux
		}
	}
	return StartDaemon(ctx, options)
}

