func privateTestDir(t *testing.T, pattern string) string {
	t.Helper()
	base := ""
	switch runtime.GOOS {
	case "darwin":
		home, err := os.UserHomeDir()
		if err != nil {
			t.Fatal(err)
		}
		base = filepath.Join(home, ".comment-bus-test-tmp")
		if err := os.MkdirAll(base, 0o700); err != nil {
			t.Fatal(err)
		}
		if err := os.Chmod(base, 0o700); err != nil {
			t.Fatal(err)
		}
	case "linux":
		base = "/tmp"
	}
	dir, err := os.MkdirTemp(base, pattern)
	if err != nil {
		t.Fatal(err)
	}
	abs, err := filepath.Abs(dir)
	if err != nil {
		_ = os.RemoveAll(dir)
		t.Fatal(err)
	}
	if err := os.Chmod(abs, 0o700); err != nil {
		_ = os.RemoveAll(abs)
		t.Fatal(err)
	}
	t.Cleanup(func() {
		_ = os.RemoveAll(abs)
	})
	return abs
}

func requestDaemon(t *testing.T, paths Paths, request map[string]any) SocketResponse {
	t.Helper()
	payload, err := json.Marshal(request)
	if err != nil {
		t.Fatal(err)
	}
	return requestRawDaemon(t, paths, append(payload, '\n'))
}

func requestRawDaemon(t *testing.T, paths Paths, payload []byte) SocketResponse {
	t.Helper()
	conn, err := net.DialUnix("unix", nil, &net.UnixAddr{Name: paths.Socket, Net: "unix"})
	if err != nil {
		t.Fatal(err)
	}
	defer conn.Close()
	if _, err := conn.Write(payload); err != nil {
		t.Fatal(err)
	}
	line, err := bufio.NewReader(conn).ReadBytes('\n')
	if err != nil {
		t.Fatal(err)
	}
	var response SocketResponse
	if err := json.Unmarshal(line, &response); err != nil {
		t.Fatal(err)
	}
	return response
}

func latestMessageEventJSON(t *testing.T, daemon *Daemon, messageID string, eventType string) string {
	t.Helper()
	rows, err := daemon.store.db.Query(`SELECT redacted_json FROM events WHERE message_id = ? AND event_type = ? ORDER BY created_at DESC LIMIT 1`, messageID, eventType)
	if err != nil {
		t.Fatal(err)
	}
	defer rows.Close()
	if !rows.Next() {
		t.Fatalf("missing %s event for %s", eventType, messageID)
	}
	var redactedJSON string
	if err := rows.Scan(&redactedJSON); err != nil {
		t.Fatal(err)
	}
	return redactedJSON
}

type structuredLogEntry struct {
	Level     string         `json:"level"`
	Component string         `json:"component"`
	Msg       string         `json:"msg"`
	Data      map[string]any `json:"data"`
}

func structuredLogEntries(t *testing.T, logs *bytes.Buffer) []structuredLogEntry {
	t.Helper()
	text := strings.TrimSpace(logs.String())
	if text == "" {
		return nil
	}
	lines := strings.Split(text, "\n")
	entries := make([]structuredLogEntry, 0, len(lines))
	for _, line := range lines {
		var entry structuredLogEntry
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			t.Fatalf("invalid structured log %q: %v", line, err)
		}
		if entry.Component != "commentbus" {
			t.Fatalf("unexpected structured log component: %#v", entry)
		}
		entries = append(entries, entry)
	}
	return entries
}

func requireStructuredLog(t *testing.T, entries []structuredLogEntry, msg string) structuredLogEntry {
	t.Helper()
	for _, entry := range entries {
		if entry.Msg == msg {
			return entry
		}
	}
	t.Fatalf("missing structured log %q in %+v", msg, entries)
	return structuredLogEntry{}
}

