func prependFakeRuntime(t *testing.T, name string) string {
	t.Helper()
	// Place the fake under <HOME>/.local/bin so the daemon's trusted user-bin
	// lookup picks it up first. Override HOME to a fresh tempdir so any real
	// binary the test machine has at ~/.local/bin/<name> can't shadow it.
	home := privateTestDir(t, "comment-bus-runtime-home-")
	t.Setenv("HOME", home)
	binDir := filepath.Join(home, ".local", "bin")
	if err := os.MkdirAll(binDir, 0o755); err != nil {
		t.Fatal(err)
	}
	path := filepath.Join(binDir, name)
	if err := os.WriteFile(path, []byte("#!/bin/sh\nexit 0\n"), 0o700); err != nil {
		t.Fatal(err)
	}
	t.Setenv("PATH", binDir+string(os.PathListSeparator)+os.Getenv("PATH"))
	return path
}

func writeTrustedTestExecutable(t *testing.T, pattern string, name string) string {
	t.Helper()
	dir := privateTestDir(t, pattern)
	path := filepath.Join(dir, name)
	if err := os.WriteFile(path, []byte("#!/bin/sh\nexit 0\n"), 0o700); err != nil {
		t.Fatal(err)
	}
	return path
}

type testBmuxController struct {
	mu                 sync.Mutex
	paths              Paths
	sessions           map[string]string
	paneCommands       map[string]string
	paneCommandErrs    map[string]error
	deadChildren       map[string]bool
	orphanChildren     map[string]bool
	defaultPaneCommand string
	newSessionErr      error
	killErr            error
	missingKillErr     error
	starts             []TmuxNewSessionOptions
	sends              []string
	killAttempts       []string
	kills              []string
	enterCount         int
	waitForOutputCalls int
	waitForOutputReady bool
	waitForOutputErr   error
	afterSendEnter     func(sessionName string, paneTarget string)
}

func newTestBmuxController(paths Paths) *testBmuxController {
	return &testBmuxController{
		paths:              paths,
		sessions:           map[string]string{},
		paneCommands:       map[string]string{},
		paneCommandErrs:    map[string]error{},
		deadChildren:       map[string]bool{},
		orphanChildren:     map[string]bool{},
		waitForOutputReady: true,
	}
}

func (t *testBmuxController) HasSession(_ context.Context, sessionName string) (bool, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return false, err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	_, ok := t.sessions[sessionName]
	return ok, nil
}

func (t *testBmuxController) NewSession(_ context.Context, options TmuxNewSessionOptions) error {
	if err := validateTmuxSessionName(options.SessionName); err != nil {
		return err
	}
	target, err := BmuxSocketPathForSession(t.paths, options.SessionName)
	if err != nil {
		return err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	if t.newSessionErr != nil {
		return t.newSessionErr
	}
	t.sessions[options.SessionName] = target
	if t.defaultPaneCommand != "" {
		t.paneCommands[target] = t.defaultPaneCommand
	} else {
		t.paneCommands[target] = "claude"
	}
	delete(t.deadChildren, options.SessionName)
	delete(t.orphanChildren, options.SessionName)
	t.starts = append(t.starts, options)
	return nil
}

func (t *testBmuxController) PaneTarget(_ context.Context, sessionName string) (string, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return "", err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	target, ok := t.sessions[sessionName]
	if !ok {
		return "", ErrTmuxSessionMissing
	}
	return target, nil
}

func (t *testBmuxController) PaneCurrentCommand(_ context.Context, paneTarget string) (string, error) {
	if err := validatePaneTargetForHost(SessionHostBmux, paneTarget); err != nil {
		return "", err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	if !t.paneExistsLocked(paneTarget) {
		return "", ErrTmuxSessionMissing
	}
	sessionName := t.sessionNameForPaneLocked(paneTarget)
	if t.deadChildren[sessionName] {
		return "", ErrTmuxSessionMissing
	}
	if err := t.paneCommandErrs[paneTarget]; err != nil {
		return "", err
	}
	if command := t.paneCommands[paneTarget]; command != "" {
		return command, nil
	}
	return "claude", nil
}

func (t *testBmuxController) BmuxStatus(_ context.Context, sessionName string) (bmuxStatus, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return bmuxStatus{}, err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	target, ok := t.sessions[sessionName]
	if !ok {
		return bmuxStatus{}, ErrTmuxSessionMissing
	}
	return bmuxStatus{
		childAlive: !t.deadChildren[sessionName],
		childPID:   1234,
		childPGID:  1234,
		foreground: t.paneCommands[target],
	}, nil
}

func (t *testBmuxController) CapturePane(context.Context, string, int) (string, error) {
	return "", errors.New("bmux capture unsupported")
}

