func (t *testBmuxController) SendEnter(_ context.Context, paneTarget string) error {
	if err := validatePaneTargetForHost(SessionHostBmux, paneTarget); err != nil {
		return err
	}
	t.mu.Lock()
	if !t.paneExistsLocked(paneTarget) {
		t.mu.Unlock()
		return ErrTmuxSessionMissing
	}
	sessionName := t.sessionNameForPaneLocked(paneTarget)
	t.enterCount++
	t.sends = append(t.sends, "enter "+paneTarget)
	afterSendEnter := t.afterSendEnter
	t.mu.Unlock()
	if afterSendEnter != nil {
		afterSendEnter(sessionName, paneTarget)
	}
	return nil
}

func (t *testBmuxController) KillSession(_ context.Context, sessionName string) error {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	t.killAttempts = append(t.killAttempts, sessionName)
	if _, ok := t.sessions[sessionName]; !ok {
		if t.orphanChildren[sessionName] {
			delete(t.orphanChildren, sessionName)
			t.kills = append(t.kills, sessionName)
			return nil
		}
		if t.missingKillErr != nil {
			return t.missingKillErr
		}
		return ErrTmuxSessionMissing
	}
	if t.killErr != nil {
		return t.killErr
	}
	delete(t.sessions, sessionName)
	delete(t.deadChildren, sessionName)
	t.kills = append(t.kills, sessionName)
	return nil
}

func (t *testBmuxController) WaitForOutput(_ context.Context, sessionName string, needle []byte, _ time.Duration) (bool, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return false, err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	t.waitForOutputCalls++
	if t.waitForOutputErr != nil {
		return false, t.waitForOutputErr
	}
	if _, ok := t.sessions[sessionName]; !ok {
		return false, ErrTmuxSessionMissing
	}
	return t.waitForOutputReady && string(needle) == "\x1b[?2004h", nil
}

func (t *testBmuxController) paneExistsLocked(paneTarget string) bool {
	return t.sessionNameForPaneLocked(paneTarget) != ""
}

func (t *testBmuxController) sessionNameForPaneLocked(paneTarget string) string {
	for sessionName, target := range t.sessions {
		if target == paneTarget {
			return sessionName
		}
	}
	return ""
}

func testBmuxSendsContainLocked(controller *testBmuxController, needle string) bool {
	for _, send := range controller.sends {
		if strings.Contains(send, needle) {
			return true
		}
	}
	return false
}

func testSendWithPrefix(sends []string, prefix string) string {
	for _, send := range sends {
		if strings.HasPrefix(send, prefix) {
			return send
		}
	}
	return ""
}

func testSendsContainPrefixAndNeedle(sends []string, prefix string, needle string) bool {
	for _, send := range sends {
		if strings.HasPrefix(send, prefix) && strings.Contains(send, needle) {
			return true
		}
	}
	return false
}

type testBmuxCompatController struct {
	paths Paths
	tmux  *testTmuxController
}

func newTestBmuxCompatController(paths Paths, tmux *testTmuxController) *testBmuxCompatController {
	return &testBmuxCompatController{paths: paths, tmux: tmux}
}

func (c *testBmuxCompatController) HasSession(_ context.Context, sessionName string) (bool, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return false, err
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if c.tmux.failHas[sessionName] || c.tmux.failHas[botNameFromTmuxSession(sessionName)] {
		return false, errors.New("fake bmux inspect failed")
	}
	c.tmux.hasSessionReads[sessionName]++
	_, ok := c.tmux.sessions[sessionName]
	return ok, nil
}

func (c *testBmuxCompatController) NewSession(_ context.Context, options TmuxNewSessionOptions) error {
	if err := validateTmuxSessionName(options.SessionName); err != nil {
		return err
	}
	paneTarget, err := BmuxSocketPathForSession(c.paths, options.SessionName)
	if err != nil {
		return err
	}
	claudeSessionFile := ""
	if records, listErr := ListSessionRecords(c.paths); listErr == nil {
		for _, record := range records {
			if record.SessionName != options.SessionName || !isClaudeBmuxSession(record) {
				continue
			}
			userHome, homeErr := os.UserHomeDir()
			if homeErr != nil {
				break
			}
			workingDir := options.WorkingDir
			if workingDir == "" {
				workingDir = record.WorkingDir
			}
			path, pathErr := ClaudeSessionFilePath(userHome, workingDir, record.RuntimeSessionRef)
			if pathErr == nil {
				claudeSessionFile = path
			}
			break
		}
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if c.tmux.failStartErrAll != nil {
		return c.tmux.failStartErrAll
	}
	if c.tmux.failStart[options.SessionName] || c.tmux.failStart[botNameFromTmuxSession(options.SessionName)] {
		return errors.New("fake bmux start failed")
	}
	c.tmux.setActivePaneLocked(options.SessionName, paneTarget)
	if len(c.tmux.defaultPaneCommandSequence) > 0 {
		c.tmux.paneCommandSequences[paneTarget] = append([]string{}, c.tmux.defaultPaneCommandSequence...)
	} else {
		c.tmux.paneCommands[paneTarget] = "claude"
	}
	if len(c.tmux.defaultPaneCaptureSequence) > 0 {
		c.tmux.paneCaptureSequences[paneTarget] = append([]string{}, c.tmux.defaultPaneCaptureSequence...)
	}
	if claudeSessionFile != "" {
		c.tmux.claudeSessionFiles[paneTarget] = claudeSessionFile
	}
	c.tmux.starts = append(c.tmux.starts, options)
	return nil
}

func (c *testBmuxCompatController) PaneTarget(_ context.Context, sessionName string) (string, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return "", err
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	target, ok := c.tmux.sessions[sessionName]
	if !ok {
		return "", ErrTmuxSessionMissing
	}
	return target, nil
}

func (c *testBmuxCompatController) PaneCurrentCommand(_ context.Context, paneTarget string) (string, error) {
	c.tmux.mu.Lock()
	beforePaneCurrentCommand := c.tmux.beforePaneCurrentCommand
	c.tmux.mu.Unlock()
	if beforePaneCurrentCommand != nil {
		beforePaneCurrentCommand(paneTarget)
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if c.tmux.failPaneCommand[paneTarget] {
		return "", errors.New("fake bmux pane command failed")
	}
	if !c.tmux.paneExistsLocked(paneTarget) {
		return "", ErrTmuxSessionMissing
	}
	c.tmux.paneCommandReads[paneTarget]++
	if sequence, ok := c.tmux.paneCommandSequences[paneTarget]; ok && len(sequence) > 0 {
		command := sequence[0]
		if len(sequence) == 1 {
			delete(c.tmux.paneCommandSequences, paneTarget)
			c.tmux.paneCommands[paneTarget] = command
		} else {
			c.tmux.paneCommandSequences[paneTarget] = sequence[1:]
		}
		return command, nil
	}
	if command, ok := c.tmux.paneCommands[paneTarget]; ok {
		return command, nil
	}
	return "claude", nil
}

func (c *testBmuxCompatController) CapturePane(_ context.Context, paneTarget string, lines int) (string, error) {
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if !c.tmux.paneExistsLocked(paneTarget) {
		return "", ErrTmuxSessionMissing
	}
	c.tmux.paneCaptureReads[paneTarget]++
	if sequence, ok := c.tmux.paneCaptureSequences[paneTarget]; ok && len(sequence) > 0 {
		text := sequence[0]
		if len(sequence) == 1 {
			c.tmux.paneCaptureSequences[paneTarget] = sequence
		} else {
			c.tmux.paneCaptureSequences[paneTarget] = sequence[1:]
		}
		return text, nil
	}
	return "", ErrTmuxSessionMissing
}

func (c *testBmuxCompatController) PaneBelongsToSession(_ context.Context, sessionName string, paneTarget string) (bool, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return false, err
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	c.tmux.paneBelongsReads[paneTarget]++
	if !c.tmux.paneExistsLocked(paneTarget) {
		return false, ErrTmuxSessionMissing
	}
	if target := c.tmux.sessions[sessionName]; target == paneTarget {
		return true, nil
	}
	if panes := c.tmux.panes[sessionName]; panes != nil {
		_, ok := panes[paneTarget]
		return ok, nil
	}
	return false, nil
}

func (c *testBmuxCompatController) WaitForOutput(_ context.Context, sessionName string, needle []byte, _ time.Duration) (bool, error) {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return false, err
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if _, ok := c.tmux.sessions[sessionName]; !ok {
		return false, ErrTmuxSessionMissing
	}
	if string(needle) != "\x1b[?2004h" {
		return false, nil
	}
	paneTarget := c.tmux.sessions[sessionName]
	if c.tmux.ignoredEnterCounts == nil {
		c.tmux.ignoredEnterCounts = map[string]int{}
	}
	c.tmux.ignoredEnterCounts[paneTarget] += 3
	return true, nil
}

func (c *testBmuxCompatController) SendLiteral(_ context.Context, paneTarget string, text string) error {
	if text == "" || strings.ContainsAny(text, "\r\n\x00") {
		return errors.New("invalid bmux literal")
	}
	c.tmux.mu.Lock()
	if !c.tmux.paneExistsLocked(paneTarget) {
		c.tmux.mu.Unlock()
		return ErrTmuxSessionMissing
	}
	if c.tmux.failSend[paneTarget] {
		c.tmux.mu.Unlock()
		return errors.New("fake bmux send failed")
	}
	c.tmux.sends = append(c.tmux.sends, "literal "+paneTarget+" "+text)
	afterSendLiteral := c.tmux.afterSendLiteral
	c.tmux.mu.Unlock()
	if afterSendLiteral != nil {
		afterSendLiteral(paneTarget, text)
	}
	return nil
}

func (c *testBmuxCompatController) PasteText(_ context.Context, paneTarget string, text string) error {
	if text == "" || strings.ContainsRune(text, '\x00') {
		return errors.New("invalid bmux paste text")
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if !c.tmux.paneExistsLocked(paneTarget) {
		return ErrTmuxSessionMissing
	}
	if c.tmux.failSend[paneTarget] {
		return errors.New("fake bmux send failed")
	}
	c.tmux.sends = append(c.tmux.sends, "paste "+paneTarget+" "+text)
	return nil
}

func (c *testBmuxCompatController) SendEnter(_ context.Context, paneTarget string) error {
	c.tmux.mu.Lock()
	if !c.tmux.paneExistsLocked(paneTarget) {
		c.tmux.mu.Unlock()
		return ErrTmuxSessionMissing
	}
	if c.tmux.failSend[paneTarget] {
		c.tmux.mu.Unlock()
		return errors.New("fake bmux send failed")
	}
	if c.tmux.ignoredEnterCounts[paneTarget] > 0 {
		c.tmux.ignoredEnterCounts[paneTarget]--
		c.tmux.mu.Unlock()
		return nil
	}
	c.tmux.sends = append(c.tmux.sends, "enter "+paneTarget)
	claudeSessionFile := c.tmux.claudeSessionFiles[paneTarget]
	afterSendEnter := c.tmux.afterSendEnter
	c.tmux.mu.Unlock()
	if claudeSessionFile != "" {
		appendTestClaudeSessionLine(claudeSessionFile)
	}
	if afterSendEnter != nil {
		afterSendEnter(paneTarget)
	}
	return nil
}

func (c *testBmuxCompatController) KillSession(_ context.Context, sessionName string) error {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return err
	}
	c.tmux.mu.Lock()
	defer c.tmux.mu.Unlock()
	if c.tmux.failKill[sessionName] || c.tmux.failKill[botNameFromTmuxSession(sessionName)] {
		return errors.New("fake bmux kill failed")
	}
	if _, ok := c.tmux.sessions[sessionName]; !ok {
		if c.tmux.missingOnKill[sessionName] || c.tmux.missingOnKill[botNameFromTmuxSession(sessionName)] {
			return ErrTmuxSessionMissing
		}
	}
	delete(c.tmux.sessions, sessionName)
	delete(c.tmux.panes, sessionName)
	c.tmux.kills = append(c.tmux.kills, sessionName)
	return nil
}

type testTmuxController struct {
	mu                         sync.Mutex
	sessions                   map[string]string
	panes                      map[string]map[string]struct{}
	paneCounter                int
	failHas                    map[string]bool
	failStart                  map[string]bool
	failStartErrAll            error
	failKill                   map[string]bool
	failSend                   map[string]bool
	failPaneCommand            map[string]bool
	missingOnKill              map[string]bool
	paneCommands               map[string]string
	paneCommandSequences       map[string][]string
	defaultPaneCommandSequence []string
	paneCommandReads           map[string]int
	hasSessionReads            map[string]int
	paneBelongsReads           map[string]int
	paneCaptureSequences       map[string][]string
	defaultPaneCaptureSequence []string
	paneCaptureReads           map[string]int
	beforePaneCurrentCommand   func(paneTarget string)
	afterSendLiteral           func(paneTarget string, text string)
	afterSendEnter             func(paneTarget string)
	ignoredEnterCounts         map[string]int
	claudeSessionFiles         map[string]string
	starts                     []TmuxNewSessionOptions
	sends                      []string
	kills                      []string
}

func newTestTmuxController() *testTmuxController {
	return &testTmuxController{
		sessions:             map[string]string{},
		panes:                map[string]map[string]struct{}{},
		failHas:              map[string]bool{},
		failStart:            map[string]bool{},
		failKill:             map[string]bool{},
		failSend:             map[string]bool{},
		failPaneCommand:      map[string]bool{},
		missingOnKill:        map[string]bool{},
		paneCommands:         map[string]string{},
		paneCommandSequences: map[string][]string{},
		paneCommandReads:     map[string]int{},
		hasSessionReads:      map[string]int{},
		paneBelongsReads:     map[string]int{},
		paneCaptureSequences: map[string][]string{},
		paneCaptureReads:     map[string]int{},
		ignoredEnterCounts:   map[string]int{},
		claudeSessionFiles:   map[string]string{},
	}
}

func appendTestClaudeSessionLine(path string) {
	if path == "" {
		return
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return
	}
	file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o600)
	if err != nil {
		return
	}
	defer file.Close()
	_, _ = file.WriteString("{\"type\":\"test-submit\"}\n")
	old := time.Now().Add(-2 * transientRuntimeStartupInputQuietDelay)
	_ = os.Chtimes(path, old, old)
}

func testPromptPayload(send string) string {
	parts := strings.SplitN(send, " ", 3)
	if len(parts) != 3 {
		return send
	}
	return parts[2]
}

func botNameFromTmuxSession(sessionName string) string {
	if !strings.HasPrefix(sessionName, "comment-") {
		return ""
	}
	rest := strings.TrimPrefix(sessionName, "comment-")
	dash := strings.LastIndex(rest, "-")
	if dash <= 0 {
		return ""
	}
	return rest[:dash]
}

