func (t *testTmuxController) SendLiteral(_ context.Context, paneTarget string, text string) error {
	if err := validateTmuxPaneTarget(paneTarget); err != nil {
		return err
	}
	if text == "" || strings.ContainsAny(text, "\r\n\x00") {
		return errors.New("invalid tmux literal")
	}
	t.mu.Lock()
	if !t.paneExistsLocked(paneTarget) {
		t.mu.Unlock()
		return ErrTmuxSessionMissing
	}
	if t.failSend[paneTarget] {
		t.mu.Unlock()
		return errors.New("fake tmux send failed")
	}
	t.sends = append(t.sends, "literal "+paneTarget+" "+text)
	afterSendLiteral := t.afterSendLiteral
	t.mu.Unlock()
	if afterSendLiteral != nil {
		afterSendLiteral(paneTarget, text)
	}
	return nil
}

func (t *testTmuxController) PasteText(_ context.Context, paneTarget string, text string) error {
	if err := validateTmuxPaneTarget(paneTarget); err != nil {
		return err
	}
	if text == "" || strings.ContainsRune(text, '\x00') {
		return errors.New("invalid tmux paste text")
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	if !t.paneExistsLocked(paneTarget) {
		return ErrTmuxSessionMissing
	}
	if t.failSend[paneTarget] {
		return errors.New("fake tmux send failed")
	}
	t.sends = append(t.sends, "paste "+paneTarget+" "+text)
	return nil
}

func (t *testTmuxController) SendEnter(_ context.Context, paneTarget string) error {
	if err := validateTmuxPaneTarget(paneTarget); err != nil {
		return err
	}
	t.mu.Lock()
	if !t.paneExistsLocked(paneTarget) {
		t.mu.Unlock()
		return ErrTmuxSessionMissing
	}
	if t.failSend[paneTarget] {
		t.mu.Unlock()
		return errors.New("fake tmux send failed")
	}
	t.sends = append(t.sends, "enter "+paneTarget)
	afterSendEnter := t.afterSendEnter
	t.mu.Unlock()
	if afterSendEnter != nil {
		afterSendEnter(paneTarget)
	}
	return nil
}

func (t *testTmuxController) paneExistsLocked(paneTarget string) bool {
	for sessionName, target := range t.sessions {
		if target == paneTarget {
			return true
		}
		if panes := t.panes[sessionName]; panes != nil {
			if _, ok := panes[paneTarget]; ok {
				return true
			}
		}
	}
	return false
}

func (t *testTmuxController) KillSession(_ context.Context, sessionName string) error {
	if err := validateTmuxSessionName(sessionName); err != nil {
		return err
	}
	t.mu.Lock()
	defer t.mu.Unlock()
	if t.failKill[sessionName] || t.failKill[botNameFromTmuxSession(sessionName)] {
		return errors.New("fake tmux kill failed")
	}
	if t.missingOnKill[sessionName] {
		delete(t.sessions, sessionName)
		delete(t.panes, sessionName)
		return ErrTmuxSessionMissing
	}
	delete(t.sessions, sessionName)
	delete(t.panes, sessionName)
	t.kills = append(t.kills, sessionName)
	return nil
}

