func startBotletsTaskDaemonWithLeaseWithTaskClockAndLogs(t *testing.T, ctx context.Context, claimID string, notificationID string, task *CloudBotletsTaskNotification, now func() time.Time, logWriter io.Writer) (Paths, *Daemon, *fakeNotificationClient, string, string, string) {
	t.Helper()
	claimedAt, leaseExpiresAt := testCloudLeaseTimes()
	if task == nil {
		task = validBotletsTaskNotification()
	}
	lease := &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      claimedAt,
		LeaseExpiresAt: leaseExpiresAt,
		Notification: CloudNotification{
			ID:          notificationID,
			Type:        "botlets_task",
			FromHandle:  "botlets.ai",
			FromName:    "Botlets",
			Context:     "Run the scheduled task.",
			CreatedAt:   claimedAt,
			BotletsTask: task,
		},
	}
	paths := testDaemonPaths(t)
	prependFakeRuntime(t, "claude")
	reviewerPath := writeAgentProfile(t, paths, "max.reviewer", map[string]any{
		"agent_secret": "as_reviewer_profile_secret",
	})
	brainRoot := writeLocalSyncBrainProjectionForTest(t, paths, "Botlets/max/reviewer/brain")
	botletsHome := filepath.Join(paths.Home, "botlets")
	writeDaemonBotletsRegistry(t, botletsHome, []map[string]any{{
		"name":               "reviewer",
		"handle":             "max.reviewer",
		"credential_profile": reviewerPath,
		"managed_session": map[string]any{
			"enabled":  true,
			"runtime":  "claude",
			"timezone": "UTC",
		},
		"brain_ref": map[string]any{
			"workspace_id":     "ws_brain",
			"owner_agent_id":   "ag_owner",
			"bot_agent_id":     "ag_bot",
			"container_id":     "lc_brain",
			"root_folder_id":   "lf_brain",
			"relative_path":    "Botlets/max/reviewer/brain",
			"setup_generation": 5,
		},
	}})
	client := &fakeNotificationClient{leases: []*CloudNotificationLease{lease}}
	daemon, err := startDaemonForTest(t, ctx, DaemonOptions{
		Paths:              paths,
		Version:            "test",
		Tmux:               newTestTmuxController(),
		BotletsHome:        botletsHome,
		NotificationClient: client,
		Now:                now,
		LogWriter:          logWriter,
	})
	if err != nil {
		t.Fatal(err)
	}
	capability, err := ReadCapability(paths.OwnerCapability)
	if err != nil {
		daemon.Close()
		t.Fatal(err)
	}
	wait := requestDaemon(t, paths, map[string]any{
		"id": "req_" + mustRequestSuffix(t),
		"op": "messages.wait",
		"auth": map[string]any{
			"mode":       "owner",
			"capability": capability,
		},
		"params": map[string]any{"bot": "reviewer", "timeout_ms": 0, "kinds": []any{"botlets.task"}},
	})
	if !wait.OK || wait.Result.(map[string]any)["source"] != "comment.io" {
		daemon.Close()
		t.Fatalf("initial botlets task wait = %+v", wait)
	}
	return paths, daemon, client, capability, wait.Result.(map[string]any)["message_id"].(string), brainRoot
}

