func (f *contextExpiredNotificationClient) LeaseNotification(ctx context.Context, profile AgentProfile, leaseTTL time.Duration, leaseHolder string, idempotencyKey string, kinds ...string) (*CloudNotificationLease, error) {
	<-ctx.Done()
	return f.lease, nil
}

func (f *delayedLeaseNotificationClient) LeaseNotification(ctx context.Context, profile AgentProfile, leaseTTL time.Duration, leaseHolder string, idempotencyKey string, kinds ...string) (*CloudNotificationLease, error) {
	f.mu.Lock()
	f.calls++
	f.waitProfiles = append(f.waitProfiles, profile.Handle)
	f.waitKinds = append(f.waitKinds, append([]string(nil), kinds...))
	f.timeouts = append(f.timeouts, 0)
	f.idempotencyKeys = append(f.idempotencyKeys, idempotencyKey)
	_, hasDeadline := ctx.Deadline()
	f.contextDeadlines = append(f.contextDeadlines, hasDeadline)
	f.mu.Unlock()
	if f.entered != nil {
		f.once.Do(func() { close(f.entered) })
	}
	select {
	case <-time.After(f.delay):
		f.mu.Lock()
		defer f.mu.Unlock()
		if f.lease != nil {
			f.recordClaimNotificationLocked(f.lease.ClaimID, f.lease.NotificationID)
		}
		return f.lease, nil
	case <-ctx.Done():
		return nil, errNotificationLeaseDeadline
	}
}

