func (f *fakeNotificationClient) LeaseNotification(ctx context.Context, profile AgentProfile, leaseTTL time.Duration, leaseHolder string, idempotencyKey string, kinds ...string) (*CloudNotificationLease, error) {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.calls++
	f.waitProfiles = append(f.waitProfiles, profile.Handle)
	f.waitKinds = append(f.waitKinds, append([]string(nil), kinds...))
	f.timeouts = append(f.timeouts, 0)
	f.idempotencyKeys = append(f.idempotencyKeys, idempotencyKey)
	_, hasDeadline := ctx.Deadline()
	f.contextDeadlines = append(f.contextDeadlines, hasDeadline)
	if len(f.errs) > 0 {
		err := f.errs[0]
		f.errs = f.errs[1:]
		return nil, err
	}
	if len(f.leasesByProfile[profile.Handle]) > 0 {
		lease := f.leasesByProfile[profile.Handle][0]
		f.leasesByProfile[profile.Handle] = f.leasesByProfile[profile.Handle][1:]
		f.recordClaimNotificationForLeaseLocked(lease)
		return lease, nil
	}
	if len(f.leases) == 0 {
		return nil, nil
	}
	lease := f.leases[0]
	f.leases = f.leases[1:]
	f.recordClaimNotificationForLeaseLocked(lease)
	return lease, nil
}

func (f *fakeWakeNotificationClient) WaitNotificationWake(ctx context.Context, profile AgentProfile) (*CloudNotificationWake, error) {
	f.wakeMu.Lock()
	f.wakeCalls++
	f.wakeMu.Unlock()
	f.enterOnce.Do(func() {
		if f.entered != nil {
			close(f.entered)
		}
	})
	select {
	case wake := <-f.wakes:
		return wake, nil
	case err := <-f.wakeErrs:
		return nil, err
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

func (f *fakeNotificationClient) RenewNotification(ctx context.Context, profile AgentProfile, claimID string, leaseTTL time.Duration, idempotencyKey string) (*CloudNotificationLease, error) {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.mutations = append(f.mutations, notificationMutationCall{Operation: "renew", Profile: profile.Handle, ClaimID: claimID, OpID: idempotencyKey, LeaseTTL: leaseTTL})
	if err := f.nextMutationErrLocked(); err != nil {
		return nil, err
	}
	if len(f.renewLeases) > 0 {
		lease := f.renewLeases[0]
		f.renewLeases = f.renewLeases[1:]
		f.recordClaimNotificationForLeaseLocked(lease)
		return lease, nil
	}
	notificationID := f.claimNotifications[claimID]
	if notificationID == "" {
		notificationID = "ntf_fakecloudmutation1234567890"
	}
	return &CloudNotificationLease{
		ClaimID:        claimID,
		NotificationID: notificationID,
		ClaimedAt:      busTime(time.Now().UTC()),
		LeaseExpiresAt: busTime(time.Now().UTC().Add(leaseTTL)),
		Notification:   CloudNotification{ID: notificationID, Type: "mention", DocSlug: "abc123", DocTitle: "Design Review", FromHandle: "max.sender", Context: "renewed", CreatedAt: busTime(time.Now().UTC())},
	}, nil
}

