func (f *completePendingAckNotificationClient) AckNotification(ctx context.Context, profile AgentProfile, claimID string, idempotencyKey string) (*CloudNotificationClaimMutation, error) {
	mutation, err := f.fakeNotificationClient.AckNotification(ctx, profile, claimID, idempotencyKey)
	if err != nil || f.completeOpID == "" || idempotencyKey != f.completeOpID {
		return mutation, err
	}
	f.completeOnce.Do(func() {
		op, ok, readErr := ReadPendingCloudNotificationClaimOperationWithRetry(f.paths, idempotencyKey)
		if readErr != nil {
			f.completionErr = readErr
			return
		}
		if !ok {
			f.completionErr = errors.New("pending ack operation missing")
			return
		}
		now := time.Now().UTC()
		if _, storeErr := f.store.AckCloudMessage(ctx, op.Profile, op.LocalMessageID, op.ClaimHolder, now); storeErr != nil {
			f.completionErr = storeErr
			return
		}
		f.completionErr = CompleteCloudNotificationClaimOperation(f.paths, op, now)
	})
	return mutation, f.completionErr
}

func (f *fakeNotificationClient) ReleaseNotification(ctx context.Context, profile AgentProfile, claimID string, idempotencyKey string) (*CloudNotificationClaimMutation, error) {
	return f.finishNotificationClaim("release", profile, claimID, idempotencyKey)
}

func (b *blockingClaimMutationNotificationClient) AckNotification(ctx context.Context, profile AgentProfile, claimID string, idempotencyKey string) (*CloudNotificationClaimMutation, error) {
	if b.operation == "ack" {
		b.once.Do(func() { close(b.entered) })
		select {
		case <-b.release:
		case <-ctx.Done():
			return nil, ctx.Err()
		}
	}
	return b.fakeNotificationClient.AckNotification(ctx, profile, claimID, idempotencyKey)
}

