func (f *fakeNotificationClient) PublishNotificationHandlingActivity(ctx context.Context, profile AgentProfile, claimID string, request CloudNotificationHandlingRequest, idempotencyKey string) (*CloudNotificationHandlingResult, error) {
	hasDeadline := false
	if ctx != nil {
		_, hasDeadline = ctx.Deadline()
	}
	f.mu.Lock()
	f.handlingActivities = append(f.handlingActivities, notificationHandlingCall{Action: request.Action, Outcome: request.Outcome, ClaimID: claimID, OpID: idempotencyKey, ClaimGeneration: request.ClaimGeneration, ProgressAt: request.ProgressAt, HasDeadline: hasDeadline})
	err := f.nextHandlingErrLocked()
	var result *CloudNotificationHandlingResult
	if len(f.handlingResults) > 0 {
		next := f.handlingResults[0]
		f.handlingResults = f.handlingResults[1:]
		result = &next
	}
	entered := f.handlingEntered
	release := f.handlingRelease
	f.mu.Unlock()
	if entered != nil {
		f.handlingEnterOnce.Do(func() { close(entered) })
	}
	if release != nil {
		select {
		case <-release:
		case <-ctx.Done():
			return nil, ctx.Err()
		}
	}
	if err != nil {
		return nil, err
	}
	if result != nil {
		return result, nil
	}
	return &CloudNotificationHandlingResult{OK: true, Activity: map[string]any{"status": request.Action}}, nil
}

func (f *fakeNotificationClient) finishNotificationClaim(operation string, profile AgentProfile, claimID string, idempotencyKey string) (*CloudNotificationClaimMutation, error) {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.mutations = append(f.mutations, notificationMutationCall{Operation: operation, Profile: profile.Handle, ClaimID: claimID, OpID: idempotencyKey})
	if err := f.nextMutationErrLocked(); err != nil {
		return nil, err
	}
	notificationID := f.claimNotifications[claimID]
	if notificationID == "" {
		notificationID = "ntf_fakecloudmutation1234567890"
	}
	return &CloudNotificationClaimMutation{OK: true, ClaimID: claimID, NotificationID: notificationID}, nil
}

func (f *fakeNotificationClient) recordClaimNotificationLocked(claimID string, notificationID string) {
	if f.claimNotifications == nil {
		f.claimNotifications = map[string]string{}
	}
	if notificationID == "" {
		return
	}
	f.claimNotifications[claimID] = notificationID
}

func (f *fakeNotificationClient) recordClaimNotificationForLeaseLocked(lease *CloudNotificationLease) {
	if lease == nil {
		return
	}
	notificationID := lease.NotificationID
	if notificationID == "" {
		notificationID = lease.Notification.ID
	}
	f.recordClaimNotificationLocked(lease.ClaimID, notificationID)
}

func (f *fakeNotificationClient) nextMutationErrLocked() error {
	if len(f.mutationErrs) == 0 {
		return nil
	}
	err := f.mutationErrs[0]
	f.mutationErrs = f.mutationErrs[1:]
	return err
}

func (f *fakeNotificationClient) nextHandlingErrLocked() error {
	if len(f.handlingErrs) == 0 {
		return nil
	}
	err := f.handlingErrs[0]
	f.handlingErrs = f.handlingErrs[1:]
	return err
}

func (f *fakeNotificationClient) enqueue(lease *CloudNotificationLease) {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.leases = append(f.leases, lease)
}

func (f *fakeNotificationClient) enqueueForProfile(profile string, lease *CloudNotificationLease) {
	f.mu.Lock()
	defer f.mu.Unlock()
	if f.leasesByProfile == nil {
		f.leasesByProfile = map[string][]*CloudNotificationLease{}
	}
	f.leasesByProfile[profile] = append(f.leasesByProfile[profile], lease)
}

func (f *fakeNotificationClient) profileWaitCalls(profile string) int {
	f.mu.Lock()
	defer f.mu.Unlock()
	count := 0
	for _, candidate := range f.waitProfiles {
		if candidate == profile {
			count++
		}
	}
	return count
}

func (b *blockingAmbiguousNotificationClient) LeaseNotification(ctx context.Context, profile AgentProfile, leaseTTL time.Duration, leaseHolder string, idempotencyKey string, kinds ...string) (*CloudNotificationLease, error) {
	b.mu.Lock()
	b.active++
	if b.active > b.maxActive {
		b.maxActive = b.active
	}
	b.idempotencyKeys = append(b.idempotencyKeys, idempotencyKey)
	b.mu.Unlock()
	b.entered <- struct{}{}
	select {
	case <-b.release:
	case <-ctx.Done():
	}
	b.mu.Lock()
	b.active--
	b.mu.Unlock()
	return nil, errNotificationLeaseAmbiguous
}

