func waitForSignal(t *testing.T, signals <-chan struct{}, label string) {
	t.Helper()
	select {
	case <-signals:
	case <-time.After(2 * time.Second):
		t.Fatalf("timed out waiting for %s", label)
	}
}

func waitForCondition(t *testing.T, label string, check func() bool) {
	t.Helper()
	waitForConditionWithin(t, label, 2*time.Second, check)
}

func waitForConditionWithin(t *testing.T, label string, timeout time.Duration, check func() bool) {
	t.Helper()
	deadline := time.Now().Add(timeout)
	for time.Now().Before(deadline) {
		if check() {
			return
		}
		time.Sleep(20 * time.Millisecond)
	}
	t.Fatalf("timed out waiting for %s", label)
}

func testCloudLeaseTimes() (string, string) {
	now := time.Now().UTC()
	return busTime(now.Add(-time.Minute)), busTime(now.Add(10 * time.Minute))
}

func testCloudLeaseExpiresIn(duration time.Duration) string {
	return busTime(time.Now().UTC().Add(duration))
}

func mustJSON(t *testing.T, value any) string {
	t.Helper()
	encoded, err := json.Marshal(value)
	if err != nil {
		t.Fatal(err)
	}
	return string(encoded)
}
